{
  "name": "ChromaSketch AI",
  "description": "Transform any photo into a beautiful coloring page using AI. Color digitally with professional tools or print your custom line art to color by hand. Powered by Gemini 2.5 for advanced image editing and conversion.",
  "requestFramePermissions": [
    "camera"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ImageState {
  original: string | null;
  lineArt: string | null;
  history: string[];
}

export interface ColorPreset {
  name: string;
  value: string;
}

export enum ToolType {
  BRUSH = 'BRUSH',
  ERASER = 'ERASER',
  BUCKET = 'BUCKET',
}

export interface DrawingPoint {
  x: number;
  y: number;
  color: string;
  size: number;
  type: ToolType;
  isDragging: boolean;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

const getAIClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
};

export const convertToLineArt = async (base64Image: string): Promise<string> => {
  const ai = getAIClient();
  const mimeType = base64Image.split(';')[0].split(':')[1];
  const base64Data = base64Image.split(',')[1];

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType,
            data: base64Data,
          },
        },
        {
          text: "Transform this image into a clean, high-contrast black and white coloring book page. Use only solid black lines for outlines and ensure the background is pure white with no shading, gradients, or textures. The result should be perfect for a child's coloring book.",
        },
      ],
    },
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Failed to generate line art");
};

export const editWithAI = async (base64Image: string, prompt: string): Promise<string> => {
  const ai = getAIClient();
  const mimeType = base64Image.split(';')[0].split(':')[1];
  const base64Data = base64Image.split(',')[1];

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType,
            data: base64Data,
          },
        },
        {
          text: `Modify this coloring page: ${prompt}. Maintain the black and white line art style for coloring.`,
        },
      ],
    },
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Failed to edit image");
};

import React from 'react';

