import React, { useRef, useEffect, useState, useCallback } from 'react';
import { ToolType } from '../types';

interface EditorProps {
  backgroundImage: string | null;
  brushColor: string;
  brushSize: number;
  tool: ToolType;
}

export const Editor: React.FC<EditorProps> = ({ backgroundImage, brushColor, brushSize, tool }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const drawingCanvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  // Initialize Canvas
  useEffect(() => {
    const resizeHandler = () => {
      const parent = canvasRef.current?.parentElement;
      if (parent && canvasRef.current && drawingCanvasRef.current) {
        const width = parent.clientWidth;
        const height = parent.clientHeight;

        // Save current content
        const tempCanvas = document.createElement('canvas');
        tempCanvas.width = drawingCanvasRef.current.width;
        tempCanvas.height = drawingCanvasRef.current.height;
        tempCanvas.getContext('2d')?.drawImage(drawingCanvasRef.current, 0, 0);

        canvasRef.current.width = width;
        canvasRef.current.height = height;
        drawingCanvasRef.current.width = width;
        drawingCanvasRef.current.height = height;

        // Restore content
        drawingCanvasRef.current.getContext('2d')?.drawImage(tempCanvas, 0, 0, width, height);
      }
    };

    window.addEventListener('resize', resizeHandler);
    resizeHandler();
    return () => window.removeEventListener('resize', resizeHandler);
  }, []);

  // Handle Background Image
  useEffect(() => {
    if (backgroundImage && canvasRef.current) {
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;

      const img = new Image();
      img.onload = () => {
        ctx.clearRect(0, 0, canvasRef.current!.width, canvasRef.current!.height);

        // Center and scale image to contain
        const canvas = canvasRef.current!;
        const scale = Math.min(canvas.width / img.width, canvas.height / img.height);
        const x = (canvas.width / 2) - (img.width / 2) * scale;
        const y = (canvas.height / 2) - (img.height / 2) * scale;
        ctx.drawImage(img, x, y, img.width * scale, img.height * scale);
      };
      img.src = backgroundImage;
    }
  }, [backgroundImage]);

  const getCoordinates = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = drawingCanvasRef.current;
    if (!canvas) return { x: 0, y: 0 };

    const rect = canvas.getBoundingClientRect();
    let clientX, clientY;

    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }

    return {
      x: (clientX - rect.left) * (canvas.width / rect.width),
      y: (clientY - rect.top) * (canvas.height / rect.height)
    };
  };

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    setIsDrawing(true);
    const coords = getCoordinates(e);
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.beginPath();
      ctx.moveTo(coords.x, coords.y);
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.strokeStyle = tool === ToolType.ERASER ? 'rgba(255,255,255,1)' : brushColor;
      ctx.lineWidth = brushSize;

      // If eraser, we use destination-out to actually erase transparency
      if (tool === ToolType.ERASER) {
        ctx.globalCompositeOperation = 'destination-out';
      } else {
        ctx.globalCompositeOperation = 'source-over';
      }
    }
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing) return;
    const coords = getCoordinates(e);
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.lineTo(coords.x, coords.y);
      ctx.stroke();
    }
  };

  const stopDrawing = () => {
    setIsDrawing(false);
  };

  const clearDrawing = () => {
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.clearRect(0, 0, drawingCanvasRef.current!.width, drawingCanvasRef.current!.height);
    }
  };

  const exportCombined = () => {
    const finalCanvas = document.createElement('canvas');
    finalCanvas.width = canvasRef.current!.width;
    finalCanvas.height = canvasRef.current!.height;
    const ctx = finalCanvas.getContext('2d');
    if (ctx) {
      // White background for print
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, finalCanvas.width, finalCanvas.height);
      ctx.drawImage(canvasRef.current!, 0, 0);
      ctx.drawImage(drawingCanvasRef.current!, 0, 0);
      return finalCanvas.toDataURL('image/png');
    }
    return '';
  };

  // Expose methods via global or ref if needed (simplified here for demo)
  (window as any).clearCanvas = clearDrawing;
  (window as any).getCombinedImage = exportCombined;

  return (
    <div className="relative w-full h-full bg-white rounded-xl shadow-inner overflow-hidden border-2 border-slate-200">
      {/* Layer 1: The Coloring Page (Background) */}
      <canvas
        ref={canvasRef}
        className="absolute inset-0 pointer-events-none"
      />
      {/* Layer 2: The User Drawing Layer */}
      <canvas
        ref={drawingCanvasRef}
        onMouseDown={startDrawing}
        onMouseMove={draw}
        onMouseUp={stopDrawing}
        onMouseLeave={stopDrawing}
        onTouchStart={startDrawing}
        onTouchMove={draw}
        onTouchEnd={stopDrawing}
        className="absolute inset-0 cursor-crosshair touch-none"
      />
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { 
  Plus, 
  Upload, 
  Printer, 
  RotateCcw, 
  Eraser, 
  Paintbrush, 
  Sparkles, 
  Download,
  Camera,
  Loader2,
  Trash2,
  MagicWand,
  Type as TypeIcon
} from 'lucide-react';
import { ColorPicker } from './components/ColorPicker';
import { Editor } from './components/Editor';
import { convertToLineArt, editWithAI } from './services/geminiService';
import { ToolType } from './types';

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [brushColor, setBrushColor] = useState('#FF0000');
  const [brushSize, setBrushSize] = useState(10);
  const [activeTool, setActiveTool] = useState<ToolType>(ToolType.BRUSH);
  const [aiPrompt, setAiPrompt] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result as string;
      try {
        const lineArt = await convertToLineArt(base64);
        setImage(lineArt);
      } catch (error) {
        console.error("Processing failed", error);
        alert("Oops! Something went wrong while converting your image.");
      } finally {
        setIsProcessing(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const handleAIEdit = async () => {
    if (!image || !aiPrompt) return;
    setIsProcessing(true);
    try {
      const edited = await editWithAI(image, aiPrompt);
      setImage(edited);
      setAiPrompt('');
    } catch (error) {
      console.error("AI edit failed", error);
      alert("AI was unable to process that request.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handlePrint = () => {
    const combined = (window as any).getCombinedImage?.();
    if (!combined) return;
    const printWindow = window.open('', '_blank');
    if (printWindow) {
      printWindow.document.write(`
        <html>
          <head><title>Print Your Coloring Page</title></head>
          <body style="margin:0; display:flex; justify-content:center; align-items:center;">
            <img src="${combined}" style="max-width:100%; max-height:100%; object-fit:contain;" />
            <script>window.onload = () => { window.print(); window.close(); };</script>
          </body>
        </html>
      `);
      printWindow.document.close();
    }
  };

  const handleDownload = () => {
    const combined = (window as any).getCombinedImage?.();
    if (!combined) return;
    const link = document.createElement('a');
    link.href = combined;
    link.download = `chromasketch-${Date.now()}.png`;
    link.click();
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-900 overflow-hidden">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-lg">
            <Sparkles className="text-white w-6 h-6" />
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-tight">ChromaSketch AI</h1>
            <p className="text-xs text-slate-500 font-medium">Create. Color. Imagine.</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button 
            onClick={() => fileInputRef.current?.click()}
            className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700 transition-colors font-semibold shadow-sm"
          >
            <Plus className="w-4 h-4" />
            New Project
          </button>
          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            accept="image/*" 
            onChange={handleFileUpload}
          />
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        {/* Left Sidebar - Tools */}
        <aside className="w-80 bg-white border-r border-slate-200 p-6 flex flex-col gap-8 shrink-0 overflow-y-auto">
          {/* Color Section */}
          <section>
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
              <Paintbrush className="w-4 h-4" /> Colors
            </h3>
            <ColorPicker currentColor={brushColor} onChange={setBrushColor} />
          </section>

          {/* Brush Settings */}
          <section>
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4">Size</h3>
            <div className="flex items-center gap-4">
              <input 
                type="range" 
                min="1" 
                max="50" 
                value={brushSize} 
                onChange={(e) => setBrushSize(parseInt(e.target.value))}
                className="flex-1 accent-indigo-600"
              />
              <span className="text-sm font-mono w-6">{brushSize}</span>
            </div>
          </section>

          {/* Tools Toggle */}
          <section>
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4">Tools</h3>
            <div className="flex gap-2">
              <button 
                onClick={() => setActiveTool(ToolType.BRUSH)}
                className={`flex-1 flex flex-col items-center gap-1 p-3 rounded-xl border-2 transition-all ${activeTool === ToolType.BRUSH ? 'border-indigo-500 bg-indigo-50 text-indigo-600' : 'border-slate-100 hover:border-slate-200'}`}
              >
                <Paintbrush className="w-5 h-5" />
                <span className="text-[10px] font-bold">BRUSH</span>
              </button>
              <button 
                onClick={() => setActiveTool(ToolType.ERASER)}
                className={`flex-1 flex flex-col items-center gap-1 p-3 rounded-xl border-2 transition-all ${activeTool === ToolType.ERASER ? 'border-indigo-500 bg-indigo-50 text-indigo-600' : 'border-slate-100 hover:border-slate-200'}`}
              >
                <Eraser className="w-5 h-5" />
                <span className="text-[10px] font-bold">ERASER</span>
              </button>
              <button 
                onClick={() => (window as any).clearCanvas?.()}
                className="flex-1 flex flex-col items-center gap-1 p-3 rounded-xl border-2 border-slate-100 hover:border-red-200 hover:bg-red-50 hover:text-red-600 transition-all"
              >
                <Trash2 className="w-5 h-5" />
                <span className="text-[10px] font-bold">CLEAR</span>
              </button>
            </div>
          </section>

          {/* AI Magic Section */}
          <section className="mt-auto">
            <div className="bg-slate-50 rounded-xl p-4 border border-slate-200">
              <h3 className="text-xs font-bold text-indigo-600 uppercase tracking-wider mb-3 flex items-center gap-2">
                <MagicWand className="w-3 h-3" /> AI Enhancer
              </h3>
              <div className="relative">
                <textarea
                  placeholder="E.g., Add a cute cat next to the person..."
                  value={aiPrompt}
                  onChange={(e) => setAiPrompt(e.target.value)}
                  className="w-full text-sm p-3 rounded-lg border border-slate-200 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none resize-none h-20"
                />
                <button 
                  disabled={!image || isProcessing || !aiPrompt}
                  onClick={handleAIEdit}
                  className="mt-3 w-full bg-indigo-600 text-white p-2 rounded-lg text-sm font-bold flex items-center justify-center gap-2 disabled:opacity-50 hover:bg-indigo-700 transition-colors"
                >
                  {isProcessing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
                  Apply Magic
                </button>
              </div>
              <p className="text-[10px] text-slate-400 mt-2 leading-relaxed italic">
                Powered by Gemini 2.5 Flash. Describe changes you want to see!
              </p>
            </div>
          </section>
        </aside>

        {/* Editor Area */}
        <section className="flex-1 flex flex-col p-8 relative">
          <div className="flex-1 relative">
            {isProcessing && (
              <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-white/80 backdrop-blur-sm rounded-xl">
                <div className="bg-white p-8 rounded-2xl shadow-xl flex flex-col items-center gap-4">
                  <div className="relative">
                    <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
                    <Sparkles className="w-6 h-6 text-indigo-400 absolute -top-2 -right-2 animate-bounce" />
                  </div>
                  <div className="text-center">
                    <p className="font-bold text-slate-800">AI is sketching...</p>
                    <p className="text-sm text-slate-500">Preparing your coloring adventure</p>
                  </div>
                </div>
              </div>
            )}

            {!image && !isProcessing ? (
              <div className="h-full border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-white gap-6 text-center px-12">
                <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center">
                  <Camera className="w-10 h-10" />
                </div>
                <div>
                  <h2 className="text-2xl font-bold text-slate-800 mb-2">Start Your Creation</h2>
                  <p className="text-slate-500 max-w-sm">
                    Upload a photo, capture a memory, or draw from scratch. Our AI will turn it into a perfect line art page.
                  </p>
                </div>
                <button 
                  onClick={() => fileInputRef.current?.click()}
                  className="bg-indigo-600 text-white px-8 py-3 rounded-full font-bold hover:bg-indigo-700 transition-all transform hover:scale-105 shadow-lg shadow-indigo-200"
                >
                  Upload Your Photo
                </button>
              </div>
            ) : (
              <Editor 
                backgroundImage={image} 
                brushColor={brushColor} 
                brushSize={brushSize} 
                tool={activeTool} 
              />
            )}
          </div>

          {/* Action Bar */}
          {image && (
            <div className="mt-6 flex justify-between items-center bg-white p-3 rounded-xl border border-slate-200 shadow-sm">
              <div className="flex gap-2">
                <button 
                   onClick={() => (window as any).clearCanvas?.()}
                  className="p-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"
                  title="Undo all strokes"
                >
                  <RotateCcw className="w-5 h-5" />
                </button>
              </div>
              <div className="flex gap-3">
                <button 
                  onClick={handleDownload}
                  className="flex items-center gap-2 px-4 py-2 text-slate-600 font-semibold hover:bg-slate-50 rounded-lg transition-colors"
                >
                  <Download className="w-4 h-4" />
                  Save
                </button>
                <button 
                  onClick={handlePrint}
                  className="flex items-center gap-2 px-6 py-2 bg-slate-900 text-white font-bold rounded-lg hover:bg-slate-800 transition-all shadow-md active:scale-95"
                >
                  <Printer className="w-4 h-4" />
                  Print Now
                </button>
              </div>
            </div>
          )}
        </section>
      </main>

      {/* Footer Info */}
      <footer className="bg-white border-t border-slate-200 px-6 py-2 text-[10px] text-slate-400 flex justify-between shrink-0">
        <span>© 2024 ChromaSketch AI Studio</span>
        <div className="flex gap-4">
          <span>AI Model: Gemini 2.5 Flash Image</span>
          <span>Version 1.0.4</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState } from 'react';
import { X, Camera, RefreshCw, Loader2 } from 'lucide-react';

interface CameraModalProps {
  onCapture: (base64: string) => void;
  onClose: () => void;
}

export const CameraModal: React.FC<CameraModalProps> = ({ onCapture, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    let stream: MediaStream | null = null;

    const startCamera = async () => {
      try {
        setIsLoading(true);
        stream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } }, 
          audio: false 
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
        setIsLoading(false);
      } catch (err) {
        console.error("Camera access error:", err);
        setError("Could not access camera. Please check permissions.");
        setIsLoading(false);
      }
    };

    startCamera();

    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, []);

  const handleCapture = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const context = canvas.getContext('2d');

      if (context) {
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        context.drawImage(video, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/jpeg');
        onCapture(base64);
      }
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/95 backdrop-blur-md p-4 sm:p-8">
      <div className="relative w-full max-w-3xl bg-black rounded-3xl overflow-hidden shadow-2xl border border-slate-700">
        {/* Header */}
        <div className="absolute top-0 left-0 right-0 p-6 flex justify-between items-center z-10 bg-gradient-to-b from-black/60 to-transparent">
          <h2 className="text-white font-bold text-lg flex items-center gap-2">
            <Camera className="w-5 h-5" /> Capture Line Art
          </h2>
          <button 
            onClick={onClose}
            className="p-2 bg-white/10 hover:bg-white/20 text-white rounded-full transition-colors"
          >
            <X className="w-6 h-6" />
          </button>
        </div>

        {/* Video Preview */}
        <div className="aspect-video relative bg-slate-800 flex items-center justify-center">
          {isLoading && (
            <div className="flex flex-col items-center gap-3">
              <Loader2 className="w-10 h-10 text-indigo-500 animate-spin" />
              <p className="text-slate-400 text-sm font-medium">Starting camera...</p>
            </div>
          )}
          {error && (
            <div className="p-8 text-center">
              <p className="text-red-400 font-bold mb-4">{error}</p>
              <button 
                onClick={onClose}
                className="px-6 py-2 bg-white text-black font-bold rounded-lg"
              >
                Go Back
              </button>
            </div>
          )}
          <video 
            ref={videoRef} 
            autoPlay 
            playsInline 
            className={`w-full h-full object-cover ${isLoading || error ? 'hidden' : 'block'}`}
          />
          <canvas ref={canvasRef} className="hidden" />
        </div>

        {/* Controls */}
        {!error && !isLoading && (
          <div className="p-8 flex justify-center items-center bg-black/80 border-t border-slate-800">
            <button
              onClick={handleCapture}
              className="group relative flex items-center justify-center w-20 h-20 rounded-full border-4 border-white transition-transform active:scale-90"
            >
              <div className="w-14 h-14 bg-white rounded-full transition-colors group-hover:bg-slate-200" />
              <span className="sr-only">Capture Photo</span>
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { 
  Plus, 
  Upload, 
  Printer, 
  RotateCcw, 
  Eraser, 
  Paintbrush, 
  Sparkles, 
  Download,
  Camera,
  Loader2,
  Trash2,
  MagicWand,
  Type as TypeIcon
} from 'lucide-react';
import { ColorPicker } from './components/ColorPicker';
import { Editor } from './components/Editor';
import { CameraModal } from './components/CameraModal';
import { convertToLineArt, editWithAI } from './services/geminiService';
import { ToolType } from './types';

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [brushColor, setBrushColor] = useState('#FF0000');
  const [brushSize, setBrushSize] = useState(10);
  const [activeTool, setActiveTool] = useState<ToolType>(ToolType.BRUSH);
  const [aiPrompt, setAiPrompt] = useState('');
  const [showCamera, setShowCamera] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const processImage = async (base64: string) => {
    setIsProcessing(true);
    try {
      const lineArt = await convertToLineArt(base64);
      setImage(lineArt);
    } catch (error) {
      console.error("Processing failed", error);
      alert("Oops! Something went wrong while converting your image.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result as string;
      await processImage(base64);
    };
    reader.readAsDataURL(file);
  };

  const handleCameraCapture = async (base64: string) => {
    setShowCamera(false);
    await processImage(base64);
  };

  const handleAIEdit = async () => {
    if (!image || !aiPrompt) return;
    setIsProcessing(true);
    try {
      const edited = await editWithAI(image, aiPrompt);
      setImage(edited);
      setAiPrompt('');
    } catch (error) {
      console.error("AI edit failed", error);
      alert("AI was unable to process that request.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handlePrint = () => {
    const combined = (window as any).getCombinedImage?.();
    if (!combined) return;
    const printWindow = window.open('', '_blank');
    if (printWindow) {
      printWindow.document.write(`
        <html>
          <head><title>Print Your Coloring Page</title></head>
          <body style="margin:0; display:flex; justify-content:center; align-items:center;">
            <img src="${combined}" style="max-width:100%; max-height:100%; object-fit:contain;" />
            <script>window.onload = () => { window.print(); window.close(); };</script>
          </body>
        </html>
      `);
      printWindow.document.close();
    }
  };

  const handleDownload = () => {
    const combined = (window as any).getCombinedImage?.();
    if (!combined) return;
    const link = document.createElement('a');
    link.href = combined;
    link.download = `chromasketch-${Date.now()}.png`;
    link.click();
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-900 overflow-hidden">
      {showCamera && (
        <CameraModal 
          onCapture={handleCameraCapture} 
          onClose={() => setShowCamera(false)} 
        />
      )}

      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-lg">
            <Sparkles className="text-white w-6 h-6" />
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-tight">ChromaSketch AI</h1>
            <p className="text-xs text-slate-500 font-medium">Create. Color. Imagine.</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div className="hidden sm:flex items-center gap-2 bg-slate-100 p-1 rounded-xl">
            <button 
              onClick={() => setShowCamera(true)}
              className="flex items-center gap-2 px-4 py-2 hover:bg-white text-slate-600 hover:text-indigo-600 rounded-lg transition-all font-semibold"
            >
              <Camera className="w-4 h-4" />
              Camera
            </button>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="flex items-center gap-2 px-4 py-2 bg-white text-indigo-600 rounded-lg hover:shadow-sm transition-all font-bold"
            >
              <Plus className="w-4 h-4" />
              Upload
            </button>
          </div>
          <button 
            onClick={() => setShowCamera(true)}
            className="sm:hidden p-2 bg-indigo-600 text-white rounded-lg"
          >
            <Camera className="w-5 h-5" />
          </button>
          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            accept="image/*" 
            onChange={handleFileUpload}
          />
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        {/* Left Sidebar - Tools */}
        <aside className="w-80 bg-white border-r border-slate-200 p-6 flex flex-col gap-8 shrink-0 overflow-y-auto">
          {/* Color Section */}
          <section>
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
              <Paintbrush className="w-4 h-4" /> Colors
            </h3>
            <ColorPicker currentColor={brushColor} onChange={setBrushColor} />
          </section>

          {/* Brush Settings */}
          <section>
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4">Size</h3>
            <div className="flex items-center gap-4">
              <input 
                type="range" 
                min="1" 
                max="50" 
                value={brushSize} 
                onChange={(e) => setBrushSize(parseInt(e.target.value))}
                className="flex-1 accent-indigo-600"
              />
              <span className="text-sm font-mono w-6">{brushSize}</span>
            </div>
          </section>

          {/* Tools Toggle */}
          <section>
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4">Tools</h3>
            <div className="flex gap-2">
              <button 
                onClick={() => setActiveTool(ToolType.BRUSH)}
                className={`flex-1 flex flex-col items-center gap-1 p-3 rounded-xl border-2 transition-all ${activeTool === ToolType.BRUSH ? 'border-indigo-500 bg-indigo-50 text-indigo-600' : 'border-slate-100 hover:border-slate-200'}`}
              >
                <Paintbrush className="w-5 h-5" />
                <span className="text-[10px] font-bold">BRUSH</span>
              </button>
              <button 
                onClick={() => setActiveTool(ToolType.ERASER)}
                className={`flex-1 flex flex-col items-center gap-1 p-3 rounded-xl border-2 transition-all ${activeTool === ToolType.ERASER ? 'border-indigo-500 bg-indigo-50 text-indigo-600' : 'border-slate-100 hover:border-slate-200'}`}
              >
                <Eraser className="w-5 h-5" />
                <span className="text-[10px] font-bold">ERASER</span>
              </button>
              <button 
                onClick={() => (window as any).clearCanvas?.()}
                className="flex-1 flex flex-col items-center gap-1 p-3 rounded-xl border-2 border-slate-100 hover:border-red-200 hover:bg-red-50 hover:text-red-600 transition-all"
              >
                <Trash2 className="w-5 h-5" />
                <span className="text-[10px] font-bold">CLEAR</span>
              </button>
            </div>
          </section>

          {/* AI Magic Section */}
          <section className="mt-auto">
            <div className="bg-slate-50 rounded-xl p-4 border border-slate-200">
              <h3 className="text-xs font-bold text-indigo-600 uppercase tracking-wider mb-3 flex items-center gap-2">
                <MagicWand className="w-3 h-3" /> AI Enhancer
              </h3>
              <div className="relative">
                <textarea
                  placeholder="E.g., Add a cute cat next to the person..."
                  value={aiPrompt}
                  onChange={(e) => setAiPrompt(e.target.value)}
                  className="w-full text-sm p-3 rounded-lg border border-slate-200 bg-white focus:ring-2 focus:ring-indigo-500 focus:border-transparent outline-none resize-none h-20"
                />
                <button 
                  disabled={!image || isProcessing || !aiPrompt}
                  onClick={handleAIEdit}
                  className="mt-3 w-full bg-indigo-600 text-white p-2 rounded-lg text-sm font-bold flex items-center justify-center gap-2 disabled:opacity-50 hover:bg-indigo-700 transition-colors"
                >
                  {isProcessing ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
                  Apply Magic
                </button>
              </div>
              <p className="text-[10px] text-slate-400 mt-2 leading-relaxed italic">
                Powered by Gemini 2.5 Flash. Describe changes you want to see!
              </p>
            </div>
          </section>
        </aside>

        {/* Editor Area */}
        <section className="flex-1 flex flex-col p-8 relative">
          <div className="flex-1 relative">
            {isProcessing && (
              <div className="absolute inset-0 z-50 flex flex-col items-center justify-center bg-white/80 backdrop-blur-sm rounded-xl">
                <div className="bg-white p-8 rounded-2xl shadow-xl flex flex-col items-center gap-4">
                  <div className="relative">
                    <Loader2 className="w-12 h-12 text-indigo-600 animate-spin" />
                    <Sparkles className="w-6 h-6 text-indigo-400 absolute -top-2 -right-2 animate-bounce" />
                  </div>
                  <div className="text-center">
                    <p className="font-bold text-slate-800">AI is sketching...</p>
                    <p className="text-sm text-slate-500">Preparing your coloring adventure</p>
                  </div>
                </div>
              </div>
            )}

            {!image && !isProcessing ? (
              <div className="h-full border-2 border-dashed border-slate-200 rounded-2xl flex flex-col items-center justify-center bg-white gap-6 text-center px-12">
                <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-full flex items-center justify-center">
                  <Camera className="w-10 h-10" />
                </div>
                <div>
                  <h2 className="text-2xl font-bold text-slate-800 mb-2">Start Your Creation</h2>
                  <p className="text-slate-500 max-w-sm">
                    Upload a photo, capture a memory, or draw from scratch. Our AI will turn it into a perfect line art page.
                  </p>
                </div>
                <div className="flex flex-wrap justify-center gap-4">
                  <button 
                    onClick={() => setShowCamera(true)}
                    className="bg-indigo-600 text-white px-8 py-3 rounded-full font-bold hover:bg-indigo-700 transition-all transform hover:scale-105 shadow-lg shadow-indigo-100 flex items-center gap-2"
                  >
                    <Camera className="w-5 h-5" /> Take Photo
                  </button>
                  <button 
                    onClick={() => fileInputRef.current?.click()}
                    className="bg-white text-indigo-600 border-2 border-indigo-600 px-8 py-3 rounded-full font-bold hover:bg-indigo-50 transition-all transform hover:scale-105 flex items-center gap-2"
                  >
                    <Upload className="w-5 h-5" /> Upload File
                  </button>
                </div>
              </div>
            ) : (
              <Editor 
                backgroundImage={image} 
                brushColor={brushColor} 
                brushSize={brushSize} 
                tool={activeTool} 
              />
            )}
          </div>

          {/* Action Bar */}
          {image && (
            <div className="mt-6 flex justify-between items-center bg-white p-3 rounded-xl border border-slate-200 shadow-sm">
              <div className="flex gap-2">
                <button 
                   onClick={() => (window as any).clearCanvas?.()}
                  className="p-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg transition-colors"
                  title="Undo all strokes"
                >
                  <RotateCcw className="w-5 h-5" />
                </button>
              </div>
              <div className="flex gap-3">
                <button 
                  onClick={handleDownload}
                  className="flex items-center gap-2 px-4 py-2 text-slate-600 font-semibold hover:bg-slate-50 rounded-lg transition-colors"
                >
                  <Download className="w-4 h-4" />
                  Save
                </button>
                <button 
                  onClick={handlePrint}
                  className="flex items-center gap-2 px-6 py-2 bg-slate-900 text-white font-bold rounded-lg hover:bg-slate-800 transition-all shadow-md active:scale-95"
                >
                  <Printer className="w-4 h-4" />
                  Print Now
                </button>
              </div>
            </div>
          )}
        </section>
      </main>

      {/* Footer Info */}
      <footer className="bg-white border-t border-slate-200 px-6 py-2 text-[10px] text-slate-400 flex justify-between shrink-0">
        <span>© 2024 ChromaSketch AI Studio</span>
        <div className="flex gap-4">
          <span>AI Model: Gemini 2.5 Flash Image</span>
          <span>Version 1.1.0</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

