function App() {
  const [image, setImage] = useState('');
  const [aiPrompt, setAiPrompt] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);

  const editWithAI = async (image: string, prompt: string) => {
    // Assuming you have an API endpoint /edit-with-ai that handles the AI editing
    const response = await fetch('/edit-with-ai', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ image, prompt }),
    });

    if (!response.ok) {
      throw new Error(`AI edit failed: ${response.status}`);
