import React, { useRef, useEffect, useState, useCallback } from 'react';
import { ToolType } from '../types';

interface EditorProps {
  backgroundImage: string | null;
  brushColor: string;
  brushSize: number;
  tool: ToolType;
  onHistoryChange?: (canUndo: boolean, canRedo: boolean) => void;
}

const MAX_HISTORY = 50;

export const Editor: React.FC<EditorProps> = ({ backgroundImage, brushColor, brushSize, tool, onHistoryChange }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const drawingCanvasRef = useRef<HTMLCanvasElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);

  // Undo/Redo History
  const historyRef = useRef<ImageData[]>([]);
  const historyIndexRef = useRef<number>(-1);

  const updateHistoryStatus = useCallback(() => {
    if (onHistoryChange) {
      onHistoryChange(
        historyIndexRef.current > 0,
        historyIndexRef.current < historyRef.current.length - 1
      );
    }
  }, [onHistoryChange]);

  const saveState = useCallback(() => {
    const canvas = drawingCanvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (canvas && ctx) {
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);

      // If we are not at the end of history, truncate it
      if (historyIndexRef.current < historyRef.current.length - 1) {
        historyRef.current = historyRef.current.slice(0, historyIndexRef.current + 1);
      }

      historyRef.current.push(imageData);
      if (historyRef.current.length > MAX_HISTORY) {
        historyRef.current.shift();
      } else {
        historyIndexRef.current++;
      }
      updateHistoryStatus();
    }
  }, [updateHistoryStatus]);

  const undo = useCallback(() => {
    if (historyIndexRef.current > 0) {
      historyIndexRef.current--;
      const canvas = drawingCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (canvas && ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.putImageData(historyRef.current[historyIndexRef.current], 0, 0);
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  const redo = useCallback(() => {
    if (historyIndexRef.current < historyRef.current.length - 1) {
      historyIndexRef.current++;
      const canvas = drawingCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (canvas && ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.putImageData(historyRef.current[historyIndexRef.current], 0, 0);
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  const clearDrawing = useCallback(() => {
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.clearRect(0, 0, drawingCanvasRef.current!.width, drawingCanvasRef.current!.height);
      saveState();
    }
  }, [saveState]);

  // Initial State setup
  useEffect(() => {
    const canvas = drawingCanvasRef.current;
    if (canvas && historyRef.current.length === 0) {
      // Small delay to ensure resize has finished and dimensions are correct
      setTimeout(() => {
        const ctx = canvas.getContext('2d');
        if (ctx) {
          const emptyState = ctx.getImageData(0, 0, canvas.width, canvas.height);
          historyRef.current = [emptyState];
          historyIndexRef.current = 0;
          updateHistoryStatus();
        }
      }, 100);
    }
  }, [updateHistoryStatus]);

  // Initialize Canvas Resize
  useEffect(() => {
    const resizeHandler = () => {
      const parent = canvasRef.current?.parentElement;
      if (parent && canvasRef.current && drawingCanvasRef.current) {
        const width = parent.clientWidth;
        const height = parent.clientHeight;

        // Save current drawing content
        const ctx = drawingCanvasRef.current.getContext('2d');
        let currentDrawing: ImageData | null = null;
        if (ctx) {
          currentDrawing = ctx.getImageData(0, 0, drawingCanvasRef.current.width, drawingCanvasRef.current.height);
        }

        canvasRef.current.width = width;
        canvasRef.current.height = height;
        drawingCanvasRef.current.width = width;
        drawingCanvasRef.current.height = height;

        // Note: resizing clearing history is common, but we try to keep current frame
        if (currentDrawing && ctx) {
           // Basic attempt to restore if proportions match
           ctx.putImageData(currentDrawing, 0, 0);
        }

        // After resize, we should probably reset history or take a fresh snapshot
        const freshCtx = drawingCanvasRef.current.getContext('2d');
        if (freshCtx) {
          const snapshot = freshCtx.getImageData(0, 0, width, height);
          historyRef.current = [snapshot];
          historyIndexRef.current = 0;
          updateHistoryStatus();
        }
      }
    };

    window.addEventListener('resize', resizeHandler);
    resizeHandler();
    return () => window.removeEventListener('resize', resizeHandler);
  }, [updateHistoryStatus]);

  // Handle Background Image
  useEffect(() => {
    if (backgroundImage && canvasRef.current) {
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;

      const img = new Image();
      img.onload = () => {
        ctx.clearRect(0, 0, canvasRef.current!.width, canvasRef.current!.height);
        const canvas = canvasRef.current!;
        const scale = Math.min(canvas.width / img.width, canvas.height / img.height);
        const x = (canvas.width / 2) - (img.width / 2) * scale;
        const y = (canvas.height / 2) - (img.height / 2) * scale;
        ctx.drawImage(img, x, y, img.width * scale, img.height * scale);
      };
      img.src = backgroundImage;
    }
  }, [backgroundImage]);

  const getCoordinates = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = drawingCanvasRef.current;
    if (!canvas) return { x: 0, y: 0 };

    const rect = canvas.getBoundingClientRect();
    let clientX, clientY;

    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }

    return {
      x: (clientX - rect.left) * (canvas.width / rect.width),
      y: (clientY - rect.top) * (canvas.height / rect.height)
    };
  };

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    setIsDrawing(true);
    const coords = getCoordinates(e);
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.beginPath();
      ctx.moveTo(coords.x, coords.y);
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.strokeStyle = tool === ToolType.ERASER ? 'rgba(255,255,255,1)' : brushColor;
      ctx.lineWidth = brushSize;

      if (tool === ToolType.ERASER) {
        ctx.globalCompositeOperation = 'destination-out';
      } else {
        ctx.globalCompositeOperation = 'source-over';
      }
    }
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing) return;
    const coords = getCoordinates(e);
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.lineTo(coords.x, coords.y);
      ctx.stroke();
    }
  };

  const stopDrawing = () => {
    if (isDrawing) {
      setIsDrawing(false);
      saveState();
    }
  };

  const exportCombined = () => {
    const finalCanvas = document.createElement('canvas');
    finalCanvas.width = canvasRef.current!.width;
    finalCanvas.height = canvasRef.current!.height;
    const ctx = finalCanvas.getContext('2d');
    if (ctx) {
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, finalCanvas.width, finalCanvas.height);
      ctx.drawImage(canvasRef.current!, 0, 0);
      ctx.drawImage(drawingCanvasRef.current!, 0, 0);
      return finalCanvas.toDataURL('image/png');
    }
    return '';
  };

  // Expose methods via global object
  useEffect(() => {
    (window as any).clearCanvas = clearDrawing;
    (window as any).getCombinedImage = exportCombined;
    (window as any).undo = undo;
    (window as any).redo = redo;
  }, [clearDrawing, undo, redo]);

  return (
    <div className="relative w-full h-full bg-white rounded-xl shadow-inner overflow-hidden border-2 border-slate-200">
      <canvas
        ref={canvasRef}
        className="absolute inset-0 pointer-events-none"
      />
      <canvas
        ref={drawingCanvasRef}
        onMouseDown={startDrawing}
        onMouseMove={draw}
        onMouseUp={stopDrawing}
        onMouseLeave={stopDrawing}
        onTouchStart={startDrawing}
        onTouchMove={draw}
        onTouchEnd={stopDrawing}
        className="absolute inset-0 cursor-crosshair touch-none"
      />
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { 
  Plus, 
  Upload, 
  Printer, 
  RotateCcw, 
  Eraser, 
  Paintbrush, 
  Sparkles, 
  Download,
  Camera,
  Loader2,
  Trash2,
  MagicWand,
  Image as ImageIcon,
  Undo,
  Redo
} from 'lucide-react';
import { ColorPicker } from './components/ColorPicker';
import { Editor } from './components/Editor';
import { CameraModal } from './components/CameraModal';
import { convertToLineArt, editWithAI } from './services/geminiService';
import { ToolType } from './types';

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [brushColor, setBrushColor] = useState('#FF0000');
  const [brushSize, setBrushSize] = useState(10);
  const [activeTool, setActiveTool] = useState<ToolType>(ToolType.BRUSH);
  const [aiPrompt, setAiPrompt] = useState('');
  const [showCamera, setShowCamera] = useState(false);
  const [canUndo, setCanUndo] = useState(false);
  const [canRedo, setCanRedo] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const processImage = async (base64: string) => {
    setIsProcessing(true);
    try {
      const lineArt = await convertToLineArt(base64);
      setImage(lineArt);
    } catch (error) {
      console.error("Processing failed", error);
      alert("Oops! Something went wrong while converting your image. Make sure it's a valid photo.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result as string;
      await processImage(base64);
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsDataURL(file);
  };

  const handleCameraCapture = async (base64: string) => {
    setShowCamera(false);
    await processImage(base64);
  };

  const handleAIEdit = async () => {
    if (!image || !aiPrompt) return;
    setIsProcessing(true);
    try {
      const edited = await editWithAI(image, aiPrompt);
      setImage(edited);
      setAiPrompt('');
    } catch (error) {
      console.error("AI edit failed", error);
      alert("AI was unable to process that request.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handlePrint = () => {
    const combined = (window as any).getCombinedImage?.();
    if (!combined) return;
    const printWindow = window.open('', '_blank');
    if (printWindow) {
      printWindow.document.write(`
        <html>
          <head>
            <title>Print Your Coloring Page</title>
            <style>
              body { margin: 0; display: flex; justify-content: center; align-items: center; height: 100vh; background: white; }
              img { max-width: 100%; max-height: 100%; object-fit: contain; }
              @media print { img { width: 100%; height: auto; } }
            </style>
          </head>
          <body>
            <img src="${combined}" />
            <script>window.onload = () => { window.print(); setTimeout(() => window.close(), 500); };</script>
          </body>
        </html>
      `);
      printWindow.document.close();
    }
  };

  const handleDownload = () => {
    const combined = (window as any).getCombinedImage?.();
    if (!combined) return;
    const link = document.createElement('a');
    link.href = combined;
    link.download = `chromasketch-${Date.now()}.png`;
    link.click();
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-900 overflow-hidden">
      {showCamera && (
        <CameraModal 
          onCapture={handleCameraCapture} 
          onClose={() => setShowCamera(false)} 
        />
      )}

      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-lg">
            <Sparkles className="text-white w-6 h-6" />
