import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

// Always use gemini-2.5-flash-image for general image editing tasks
export const convertToLineArt = async (base64Image: string): Promise<string> => {
  // Creating a new GoogleGenAI instance right before the call to ensure it uses the latest API key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const mimeType = base64Image.split(';')[0].split(':')[1];
  const base64Data = base64Image.split(',')[1];

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType,
            data: base64Data,
          },
        },
        {
          text: "Transform this image into a clean, high-contrast black and white coloring book page. Use only solid black lines for outlines and ensure the background is pure white with no shading, gradients, or textures. The result should be perfect for a child's coloring book.",
        },
      ],
    },
  });

  // Iterate through all parts to find the image part as recommended
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Failed to generate line art");
};

export const editWithAI = async (base64Image: string, prompt: string): Promise<string> => {
  // Creating a new GoogleGenAI instance right before the call
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const mimeType = base64Image.split(';')[0].split(':')[1];
  const base64Data = base64Image.split(',')[1];

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        {
          inlineData: {
            mimeType,
            data: base64Data,
          },
        },
        {
          text: `Modify this coloring page: ${prompt}. Maintain the black and white line art style for coloring.`,
        },
      ],
    },
  });

  // Iterate through all parts to find the image part
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Failed to edit image");
};

