            ) : (
              <Editor 
                backgroundImage={image} 
                brushColor={brushColor} 
                brushSize={brushSize} 
                tool={activeTool}
                onHistoryChange={(undo, redo) => {
                  setCanUndo(undo);
                  setCanRedo(redo);
                }}
              />
            )}
          </div>

          {/* Action Bar */}
          {image && (
            <div className="mt-6 flex justify-between items-center bg-white p-3 rounded-xl border border-slate-200 shadow-sm">
              <div className="flex gap-2">
                <button 
                   onClick={() => (window as any).undo?.()}
                   disabled={!canUndo}
                  className={`p-2 rounded-lg transition-colors flex items-center gap-2 px-3 ${canUndo ? 'text-indigo-600 hover:bg-indigo-50' : 'text-slate-300 cursor-not-allowed'}`}
                  title="Undo last stroke"
                >
                  <Undo className="w-4 h-4" />
                </button>
                <button 
                   onClick={() => (window as any).redo?.()}
                   disabled={!canRedo}
                  className={`p-2 rounded-lg transition-colors flex items-center gap-2 px-3 ${canRedo ? 'text-indigo-600 hover:bg-indigo-50' : 'text-slate-300 cursor-not-allowed'}`}
                  title="Redo last stroke"
                >
                  <Redo className="w-4 h-4" />
                </button>
                <div className="w-[1px] h-6 bg-slate-200 mx-1 self-center" />
                <button 
                   onClick={() => (window as any).clearCanvas?.()}
                  className="p-2 text-slate-500 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors flex items-center gap-2 px-3"
                  title="Clear all coloring"
                >
                  <RotateCcw className="w-4 h-4" />
                  <span className="text-xs font-bold uppercase">Reset</span>
                </button>
              </div>
              <div className="flex gap-3">
                <button 
                  onClick={handleDownload}
                  className="flex items-center gap-2 px-4 py-2 text-slate-600 font-semibold hover:bg-slate-50 rounded-lg transition-colors"
                >
                  <Download className="w-4 h-4" />
