import React, { useState } from 'react';
import { Palette, Hash } from 'lucide-react';

interface ColorPickerProps {
  currentColor: string;
  onChange: (color: string) => void;
}

const PALETTES = {
  Classic: [
    '#000000', '#FFFFFF', '#FF0000', '#00FF00', '#0000FF', '#FFFF00', '#FF00FF', '#00FFFF',
    '#808080', '#800000', '#808000', '#008000', '#800080', '#008080', '#000080', '#A52A2A'
  ],
  Pastel: [
    '#FFB7B2', '#FFDAC1', '#E2F0CB', '#B5EAD7', '#C7CEEA', '#F3D1F4', '#FF9AA2', '#FFFFD8',
    '#D4F0F0', '#CCE2CB', '#E8D1C5', '#FCE1E4', '#DAEAF1', '#E2D1F9', '#D1E8E2', '#FFF5E1'
  ],
  Neon: [
    '#FF00FF', '#00FFFF', '#00FF00', '#FFFF00', '#FF00AA', '#AA00FF', '#00AAFF', '#AAFF00',
    '#FF5500', '#00FF55', '#5500FF', '#FF0055', '#0055FF', '#55FF00', '#FFAA00', '#00FFAA'
  ],
  Earth: [
    '#4B3621', '#6E4F32', '#8B5A2B', '#A67B5B', '#C2A385', '#D9C5B2', '#2E3B23', '#4A5D23',
    '#738625', '#9EAD3D', '#2F4F4F', '#556B2F', '#8FBC8F', '#BDB76B', '#BC8F8F', '#DEB887'
  ]
};

type PaletteName = keyof typeof PALETTES;

export const ColorPicker: React.FC<ColorPickerProps> = ({ currentColor, onChange }) => {
  const [activePalette, setActivePalette] = useState<PaletteName>('Classic');
  const [hexInput, setHexInput] = useState(currentColor);

  const handleHexChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const val = e.target.value;
    setHexInput(val);
    if (/^#[0-9A-F]{6}$/i.test(val)) {
      onChange(val);
    }
  };

  const handleColorSelect = (color: string) => {
    onChange(color);
    setHexInput(color);
  };

  return (
    <div className="flex flex-col gap-4">
      {/* Active Color Preview & Custom Hex */}
      <div className="flex items-center gap-3 p-3 bg-slate-50 rounded-xl border border-slate-200">
        <div className="relative group">
          <input
            type="color"
            value={currentColor}
            onChange={(e) => handleColorSelect(e.target.value)}
            className="w-12 h-12 rounded-lg cursor-pointer border-2 border-white shadow-sm appearance-none bg-transparent overflow-hidden"
          />
          <div className="absolute inset-0 rounded-lg pointer-events-none border border-slate-200 group-hover:border-indigo-300 transition-colors" />
        </div>

        <div className="flex-1 flex flex-col gap-1">
          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter flex items-center gap-1">
            <Hash className="w-2.5 h-2.5" /> Hex Code
          </label>
          <input
            type="text"
            value={hexInput}
            onChange={handleHexChange}
            placeholder="#000000"
            className="text-sm font-mono font-bold text-slate-700 bg-transparent border-none p-0 focus:ring-0 uppercase w-full"
          />
        </div>
      </div>

      {/* Palette Tabs */}
      <div className="flex gap-1 p-1 bg-slate-100 rounded-lg">
        {(Object.keys(PALETTES) as PaletteName[]).map((name) => (
          <button
            key={name}
            onClick={() => setActivePalette(name)}
            className={`flex-1 py-1.5 text-[10px] font-bold rounded-md transition-all ${
              activePalette === name
                ? 'bg-white text-indigo-600 shadow-sm'
                : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            {name}
          </button>
        ))}
      </div>

      {/* Color Grid */}
      <div className="grid grid-cols-8 gap-2">
        {PALETTES[activePalette].map((color) => (
          <button
            key={color}
            onClick={() => handleColorSelect(color)}
            title={color}
            className={`w-full aspect-square rounded-md border-2 transition-all hover:scale-110 active:scale-95 ${
              currentColor.toLowerCase() === color.toLowerCase()
                ? 'border-indigo-500 ring-2 ring-indigo-100 scale-110 z-10'
                : 'border-white shadow-sm'
            }`}
            style={{ backgroundColor: color }}
          />
        ))}
      </div>

      <div className="flex items-center gap-2 mt-1 px-1">
        <Palette className="w-3 h-3 text-slate-300" />
        <span className="text-[10px] text-slate-400 italic">Select a theme to see more colors</span>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { 
  Plus, 
  Upload, 
  Printer, 
  RotateCcw, 
  Eraser, 
  Paintbrush, 
  Sparkles, 
  Download,
  Camera,
  Loader2,
  Trash2,
  Wand2,
  Image as ImageIcon,
  Undo,
  Redo,
  PaintBucket
} from 'lucide-react';
import { ColorPicker } from './components/ColorPicker';
import { Editor } from './components/Editor';
import { CameraModal } from './components/CameraModal';
import { convertToLineArt, editWithAI } from './services/geminiService';
import { ToolType } from './types';

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [brushColor, setBrushColor] = useState('#FF0000');
  const [brushSize, setBrushSize] = useState(10);
  const [activeTool, setActiveTool] = useState<ToolType>(ToolType.BRUSH);
  const [aiPrompt, setAiPrompt] = useState('');
  const [showCamera, setShowCamera] = useState(false);
  const [canUndo, setCanUndo] = useState(false);
  const [canRedo, setCanRedo] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const processImage = async (base64: string) => {
    setIsProcessing(true);
    try {
      const lineArt = await convertToLineArt(base64);
      setImage(lineArt);
    } catch (error) {
      console.error("Processing failed", error);
      alert("Oops! Something went wrong while converting your image. Make sure it's a valid photo.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result as string;
      await processImage(base64);
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsDataURL(file);
  };

  const handleCameraCapture = async (base64: string) => {
    setShowCamera(false);
    await processImage(base64);
  };

  const handleAIEdit = async () => {
    if (!image || !aiPrompt) return;
    setIsProcessing(true);
    try {
      const edited = await editWithAI(image, aiPrompt);
      setImage(edited);
      setAiPrompt('');
    } catch (error) {
      console.error("AI edit failed", error);
      alert("AI was unable to process that request.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handlePrint = () => {
    const combined = (window as any).getCombinedImage?.();
    if (!combined) return;
    const printWindow = window.open('', '_blank');
    if (printWindow) {
      printWindow.document.write(`
        <html>
          <head>
            <title>Print Your Coloring Page</title>
            <style>
              body { margin: 0; display: flex; justify-content: center; align-items: center; height: 100vh; background: white; }
              img { max-width: 100%; max-height: 100%; object-fit: contain; }
              @media print { img { width: 100%; height: auto; } }
            </style>
          </head>
          <body>
            <img src="${combined}" />
            <script>window.onload = () => { window.print(); setTimeout(() => window.close(), 500); };</script>
          </body>
        </html>
      `);
      printWindow.document.close();
    }
  };

  const handleDownload = () => {
    const combined = (window as any).getCombinedImage?.();
    if (!combined) return;
    const link = document.createElement('a');
    link.href = combined;
    link.download = `chromasketch-${Date.now()}.png`;
    link.click();
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-900 overflow-hidden">
      {showCamera && (
        <CameraModal 
          onCapture={handleCameraCapture} 
          onClose={() => setShowCamera(false)} 
        />
      )}

      {/* Header */}
      <header className="bg-white border-b border-slate-200 px-6 py-4 flex justify-between items-center shrink-0">
        <div className="flex items-center gap-2">
          <div className="bg-indigo-600 p-2 rounded-lg">
            <Sparkles className="text-white w-6 h-6" />
          </div>
          <div>
            <h1 className="text-xl font-bold tracking-tight">ChromaSketch AI</h1>
            <p className="text-xs text-slate-500 font-medium">Transform photos into coloring pages</p>
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div className="hidden sm:flex items-center gap-2 bg-slate-100 p-1 rounded-xl">
            <button 
              onClick={() => setShowCamera(true)}
              className="flex items-center gap-2 px-4 py-2 hover:bg-white text-slate-600 hover:text-indigo-600 rounded-lg transition-all font-semibold"
            >
              <Camera className="w-4 h-4" />
              Camera
            </button>
            <button 
              onClick={() => fileInputRef.current?.click()}
              className="flex items-center gap-2 px-4 py-2 bg-white text-indigo-600 rounded-lg hover:shadow-sm transition-all font-bold"
            >
              <Upload className="w-4 h-4" />
              Upload Photo
            </button>
          </div>
          <button 
            onClick={() => setShowCamera(true)}
            className="sm:hidden p-2 bg-indigo-600 text-white rounded-lg"
          >
            <Camera className="w-5 h-5" />
          </button>
          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            accept="image/*" 
            onChange={handleFileUpload}
          />
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        {/* Left Sidebar - Tools */}
        <aside className="w-80 bg-white border-r border-slate-200 p-6 flex flex-col gap-8 shrink-0 overflow-y-auto">

          {/* Action Tools */}
          <section>
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
               Quick Actions
            </h3>
            <div className="flex flex-col gap-2">
              <button 
                onClick={() => fileInputRef.current?.click()}
                className="w-full flex items-center gap-3 p-3 rounded-xl border-2 border-slate-100 hover:border-indigo-200 hover:bg-indigo-50 transition-all text-slate-700 hover:text-indigo-700 font-semibold"
              >
                <div className="p-2 bg-indigo-100 text-indigo-600 rounded-lg">
                  <ImageIcon className="w-4 h-4" />
                </div>
                Convert New Photo
              </button>
            </div>
          </section>

          {/* Color Section */}
          <section>
            <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider mb-4 flex items-center gap-2">
              <Paintbrush className="w-4 h-4" /> Colors
