export default App;

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { ToolType } from '../types';

interface EditorProps {
  backgroundImage: string | null;
  brushColor: string;
  brushSize: number;
  tool: ToolType;
  onHistoryChange?: (canUndo: boolean, canRedo: boolean) => void;
}

const MAX_HISTORY = 50;

function hexToRgb(hex: string) {
  var result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16),
    g: parseInt(result[2], 16),
    b: parseInt(result[3], 16)
  } : { r: 0, g: 0, b: 0 };
}

export const Editor: React.FC<EditorProps> = ({ backgroundImage, brushColor, brushSize, tool, onHistoryChange }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null); // Line Art Canvas
  const drawingCanvasRef = useRef<HTMLCanvasElement>(null); // Coloring Canvas
  const [isDrawing, setIsDrawing] = useState(false);

  // Undo/Redo History
  const historyRef = useRef<ImageData[]>([]);
  const historyIndexRef = useRef<number>(-1);

  const updateHistoryStatus = useCallback(() => {
    if (onHistoryChange) {
      onHistoryChange(
        historyIndexRef.current > 0,
        historyIndexRef.current < historyRef.current.length - 1
      );
    }
  }, [onHistoryChange]);

  const saveState = useCallback(() => {
    const canvas = drawingCanvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (canvas && ctx) {
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);

      if (historyIndexRef.current < historyRef.current.length - 1) {
        historyRef.current = historyRef.current.slice(0, historyIndexRef.current + 1);
      }

      historyRef.current.push(imageData);
      if (historyRef.current.length > MAX_HISTORY) {
        historyRef.current.shift();
      } else {
        historyIndexRef.current++;
      }
      updateHistoryStatus();
    }
  }, [updateHistoryStatus]);

  const undo = useCallback(() => {
    if (historyIndexRef.current > 0) {
      historyIndexRef.current--;
      const canvas = drawingCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (canvas && ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.putImageData(historyRef.current[historyIndexRef.current], 0, 0);
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  const redo = useCallback(() => {
    if (historyIndexRef.current < historyRef.current.length - 1) {
      historyIndexRef.current++;
      const canvas = drawingCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (canvas && ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.putImageData(historyRef.current[historyIndexRef.current], 0, 0);
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  const clearDrawing = useCallback(() => {
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.clearRect(0, 0, drawingCanvasRef.current!.width, drawingCanvasRef.current!.height);
      saveState();
    }
  }, [saveState]);

  // Initial State setup
  useEffect(() => {
    const canvas = drawingCanvasRef.current;
    if (canvas && historyRef.current.length === 0) {
      setTimeout(() => {
        const ctx = canvas.getContext('2d');
        if (ctx) {
          const emptyState = ctx.getImageData(0, 0, canvas.width, canvas.height);
          historyRef.current = [emptyState];
          historyIndexRef.current = 0;
          updateHistoryStatus();
        }
      }, 100);
    }
  }, [updateHistoryStatus]);

  // Initialize Canvas Resize
  useEffect(() => {
    const resizeHandler = () => {
      const parent = drawingCanvasRef.current?.parentElement;
      if (parent && canvasRef.current && drawingCanvasRef.current) {
        const width = parent.clientWidth;
        const height = parent.clientHeight;

        const ctx = drawingCanvasRef.current.getContext('2d');
        let currentDrawing: ImageData | null = null;
        if (ctx) {
          currentDrawing = ctx.getImageData(0, 0, drawingCanvasRef.current.width, drawingCanvasRef.current.height);
        }

        canvasRef.current.width = width;
        canvasRef.current.height = height;
        drawingCanvasRef.current.width = width;
        drawingCanvasRef.current.height = height;

        if (currentDrawing && ctx) {
           ctx.putImageData(currentDrawing, 0, 0);
        }

        const freshCtx = drawingCanvasRef.current.getContext('2d');
        if (freshCtx) {
          const snapshot = freshCtx.getImageData(0, 0, width, height);
          historyRef.current = [snapshot];
          historyIndexRef.current = 0;
          updateHistoryStatus();
        }

        // Re-draw background if exists
        if (backgroundImage) {
          const bgCtx = canvasRef.current.getContext('2d');
          if (bgCtx) {
            const img = new Image();
            img.onload = () => {
              bgCtx.clearRect(0, 0, width, height);
              const scale = Math.min(width / img.width, height / img.height);
              const x = (width / 2) - (img.width / 2) * scale;
              const y = (height / 2) - (img.height / 2) * scale;
              bgCtx.drawImage(img, x, y, img.width * scale, img.height * scale);
            };
            img.src = backgroundImage;
          }
        }
      }
    };

    window.addEventListener('resize', resizeHandler);
    resizeHandler();
    return () => window.removeEventListener('resize', resizeHandler);
  }, [backgroundImage, updateHistoryStatus]);

  // Handle Background Image
  useEffect(() => {
    if (backgroundImage && canvasRef.current) {
      const ctx = canvasRef.current.getContext('2d');
      if (!ctx) return;

      const img = new Image();
      img.onload = () => {
        ctx.clearRect(0, 0, canvasRef.current!.width, canvasRef.current!.height);
        const canvas = canvasRef.current!;
        const scale = Math.min(canvas.width / img.width, canvas.height / img.height);
        const x = (canvas.width / 2) - (img.width / 2) * scale;
        const y = (canvas.height / 2) - (img.height / 2) * scale;
        ctx.drawImage(img, x, y, img.width * scale, img.height * scale);
      };
      img.src = backgroundImage;
    }
  }, [backgroundImage]);

  const getCoordinates = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = drawingCanvasRef.current;
    if (!canvas) return { x: 0, y: 0 };

    const rect = canvas.getBoundingClientRect();
    let clientX, clientY;

    if ('touches' in e) {
      clientX = e.touches[0].clientX;
      clientY = e.touches[0].clientY;
    } else {
      clientX = e.clientX;
      clientY = e.clientY;
    }

    return {
      x: (clientX - rect.left) * (canvas.width / rect.width),
      y: (clientY - rect.top) * (canvas.height / rect.height)
    };
  };

  const matchColor = (pixels: Uint8ClampedArray, pos: number, r: number, g: number, b: number, a: number) => {
    const threshold = 40; // High threshold to handle anti-aliasing in line art
    return (
      Math.abs(pixels[pos] - r) <= threshold &&
      Math.abs(pixels[pos + 1] - g) <= threshold &&
      Math.abs(pixels[pos + 2] - b) <= threshold &&
      Math.abs(pixels[pos + 3] - a) <= threshold
    );
  };

  const handleBucketFill = (startX: number, startY: number) => {
    const canvas = drawingCanvasRef.current;
    const bgCanvas = canvasRef.current;
    if (!canvas || !bgCanvas) return;

    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    const width = canvas.width;
    const height = canvas.height;

    // Create merged image to detect boundaries
    const tempCanvas = document.createElement('canvas');
    tempCanvas.width = width;
    tempCanvas.height = height;
    const tempCtx = tempCanvas.getContext('2d', { willReadFrequently: true });
    if (!tempCtx) return;

    tempCtx.fillStyle = '#ffffff'; // Treat background as white
    tempCtx.fillRect(0, 0, width, height);
    tempCtx.drawImage(bgCanvas, 0, 0);
    tempCtx.drawImage(canvas, 0, 0);

    const imgData = tempCtx.getImageData(0, 0, width, height);
    const pixels = imgData.data;

    const x = Math.round(startX);
    const y = Math.round(startY);
    const targetPos = (y * width + x) * 4;
    const targetR = pixels[targetPos];
    const targetG = pixels[targetPos + 1];
    const targetB = pixels[targetPos + 2];
    const targetA = pixels[targetPos + 3];

    const fillColor = hexToRgb(brushColor);

    // Avoid infinite loop if clicking same color
    if (matchColor(pixels, targetPos, fillColor.r, fillColor.g, fillColor.b, 255)) return;

    const pixelStack = [[x, y]];
    const filledPixels = new Uint8Array(width * height);

    while (pixelStack.length) {
      const current = pixelStack.pop()!;
      let curX = current[0];
      let curY = current[1];

      let pixelPos = (curY * width + curX) * 4;
      while (curY >= 0 && matchColor(pixels, pixelPos, targetR, targetG, targetB, targetA)) {
        curY--;
        pixelPos -= width * 4;
      }
      pixelPos += width * 4;
      curY++;

      let reachLeft = false;
      let reachRight = false;

      while (curY < height && matchColor(pixels, pixelPos, targetR, targetG, targetB, targetA)) {
        pixels[pixelPos] = fillColor.r;
        pixels[pixelPos + 1] = fillColor.g;
        pixels[pixelPos + 2] = fillColor.b;
        pixels[pixelPos + 3] = 255;

        filledPixels[curY * width + curX] = 1;

        if (curX > 0) {
          if (matchColor(pixels, pixelPos - 4, targetR, targetG, targetB, targetA)) {
            if (!reachLeft) {
              pixelStack.push([curX - 1, curY]);
              reachLeft = true;
            }
          } else if (reachLeft) {
            reachLeft = false;
          }
        }

        if (curX < width - 1) {
          if (matchColor(pixels, pixelPos + 4, targetR, targetG, targetB, targetA)) {
            if (!reachRight) {
              pixelStack.push([curX + 1, curY]);
              reachRight = true;
            }
          } else if (reachRight) {
            reachRight = false;
          }
        }

        curY++;
        pixelPos += width * 4;
      }
    }

    // Apply only filled area to the drawing canvas
    const fillImgData = ctx.createImageData(width, height);
    for (let i = 0; i < width * height; i++) {
      if (filledPixels[i]) {
        fillImgData.data[i * 4] = fillColor.r;
        fillImgData.data[i * 4 + 1] = fillColor.g;
        fillImgData.data[i * 4 + 2] = fillColor.b;
        fillImgData.data[i * 4 + 3] = 255;
      }
    }

    const scratchCanvas = document.createElement('canvas');
    scratchCanvas.width = width;
    scratchCanvas.height = height;
    scratchCanvas.getContext('2d')?.putImageData(fillImgData, 0, 0);

    ctx.globalCompositeOperation = 'source-over';
    ctx.drawImage(scratchCanvas, 0, 0);

    saveState();
  };

  const startDrawing = (e: React.MouseEvent | React.TouchEvent) => {
    const coords = getCoordinates(e);

    if (tool === ToolType.BUCKET) {
      handleBucketFill(coords.x, coords.y);
      return;
    }

    setIsDrawing(true);
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.beginPath();
      ctx.moveTo(coords.x, coords.y);
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.strokeStyle = tool === ToolType.ERASER ? 'rgba(255,255,255,1)' : brushColor;
      ctx.lineWidth = brushSize;

      if (tool === ToolType.ERASER) {
        ctx.globalCompositeOperation = 'destination-out';
      } else {
        ctx.globalCompositeOperation = 'source-over';
      }
    }
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDrawing || tool === ToolType.BUCKET) return;
    const coords = getCoordinates(e);
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.lineTo(coords.x, coords.y);
      ctx.stroke();
    }
  };

  const stopDrawing = () => {
    if (isDrawing) {
      setIsDrawing(false);
      saveState();
    }
  };

  const exportCombined = () => {
    const finalCanvas = document.createElement('canvas');
    finalCanvas.width = canvasRef.current!.width;
    finalCanvas.height = canvasRef.current!.height;
    const ctx = finalCanvas.getContext('2d');
    if (ctx) {
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, finalCanvas.width, finalCanvas.height);
      // Drawing canvas first (colors), then background (lines) with multiply blend
      ctx.drawImage(drawingCanvasRef.current!, 0, 0);
      ctx.globalCompositeOperation = 'multiply';
      ctx.drawImage(canvasRef.current!, 0, 0);
      return finalCanvas.toDataURL('image/png');
    }
    return '';
  };

  useEffect(() => {
    (window as any).clearCanvas = clearDrawing;
    (window as any).getCombinedImage = exportCombined;
    (window as any).undo = undo;
    (window as any).redo = redo;
  }, [clearDrawing, undo, redo]);

  return (
    <div className="relative w-full h-full bg-white rounded-xl shadow-inner overflow-hidden border-2 border-slate-200">
      {/* coloring is at the bottom, events handled here */}
      <canvas
        ref={drawingCanvasRef}
        onMouseDown={startDrawing}
        onMouseMove={draw}
        onMouseUp={stopDrawing}
        onMouseLeave={stopDrawing}
        onTouchStart={startDrawing}
        onTouchMove={draw}
        onTouchEnd={stopDrawing}
        className="absolute inset-0 cursor-crosshair touch-none"
      />
      {/* line art is on top with multiply blend mode so white is transparent */}
      <canvas
        ref={canvasRef}
        className="absolute inset-0 pointer-events-none mix-blend-multiply"
      />
    </div>
  );
};

