interface CameraModalProps {
  onCapture: (base64: string, style: ColoringStyle) => void;
  onClose: () => void;
}

const UPGRADES: { id: ColoringStyle; label: string; icon: any; description: string; color: string }[] = [
  { id: 'standard', label: 'Classic', icon: Camera, description: 'True-to-life outlines', color: 'bg-blue-500' },
  { id: 'bold', label: 'Bold Pop', icon: Star, description: 'Thick sticker outlines', color: 'bg-yellow-500' },
  { id: 'detailed', label: 'Fine Art', icon: Layers, description: 'Intricate & complex', color: 'bg-indigo-500' },
