];

export const CameraModal: React.FC<CameraModalProps> = ({ onCapture, onClose }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);

  useEffect(() => {
    let stream: MediaStream | null = null;

    const startCamera = async () => {
      try {
        setIsLoading(true);
        stream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } }, 
          audio: false 
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
        setIsLoading(false);
      } catch (err) {
        console.error("Camera access error:", err);
        setError("Could not access camera. Please check permissions.");
        setIsLoading(false);
      }
    };

    if (!capturedImage) {
      startCamera();
    }

    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, [capturedImage]);

  const handleSnap = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const context = canvas.getContext('2d');

      if (context) {
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        context.drawImage(video, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/jpeg');
        setCapturedImage(base64);
      }
    }
  };

  const handleSelectStyle = (style: ColoringStyle) => {
    if (capturedImage) {
      onCapture(capturedImage, style);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/95 backdrop-blur-md p-4 sm:p-8">
      <div className="relative w-full max-w-4xl bg-slate-900 rounded-[2.5rem] overflow-hidden shadow-2xl border border-white/10 flex flex-col md:flex-row h-full max-h-[800px]">

        {/* Main Content Area */}
        <div className="flex-1 relative bg-black flex flex-col min-h-0">
          {/* Header */}
          <div className="absolute top-0 left-0 right-0 p-6 flex justify-between items-center z-20 bg-gradient-to-b from-black/80 to-transparent">
            <h2 className="text-white font-black text-xl flex items-center gap-3">
              {capturedImage ? <Sparkles className="w-6 h-6 text-yellow-400" /> : <Camera className="w-6 h-6" />}
              {capturedImage ? 'Select Your Upgrade' : 'Capture New Photo'}
            </h2>
            <button 
              onClick={onClose}
              className="p-3 bg-white/10 hover:bg-white/20 text-white rounded-full transition-all backdrop-blur-md border border-white/10"
            >
              <X className="w-6 h-6" />
            </button>
          </div>

          <div className="flex-1 flex items-center justify-center relative overflow-hidden">
            {isLoading && !capturedImage && (
              <div className="flex flex-col items-center gap-4">
                <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
                <p className="text-slate-400 text-sm font-bold tracking-widest uppercase">Initializing lens...</p>
              </div>
            )}

            {error && (
              <div className="p-8 text-center max-w-sm">
                <p className="text-red-400 font-black text-lg mb-4">{error}</p>
                <button 
                  onClick={onClose}
                  className="px-8 py-3 bg-white text-black font-black rounded-2xl hover:bg-slate-100 transition-all"
                >
                  Go Back
                </button>
              </div>
            )}

            {!capturedImage ? (
              <video 
                ref={videoRef} 
                autoPlay 
                playsInline 
                className={`w-full h-full object-cover ${isLoading || error ? 'hidden' : 'block'}`}
              />
            ) : (
              <img 
                src={capturedImage} 
                className="w-full h-full object-cover"
                alt="Captured"
              />
            )}
            <canvas ref={canvasRef} className="hidden" />
          </div>

          {/* Capture Button (Only in camera mode) */}
          {!capturedImage && !error && !isLoading && (
            <div className="p-10 flex justify-center items-center bg-gradient-to-t from-black/80 to-transparent absolute bottom-0 left-0 right-0">
              <button
                onClick={handleSnap}
                className="group relative flex items-center justify-center w-24 h-24 rounded-full border-4 border-white transition-all transform active:scale-90 hover:scale-105"
              >
                <div className="w-18 h-18 bg-white rounded-full transition-all group-hover:bg-indigo-50 flex items-center justify-center shadow-xl">
                    <Camera className="w-8 h-8 text-slate-900" />
                </div>
              </button>
            </div>
          )}
        </div>

        {/* Upgrade Sidebar (Only when image is captured) */}
        {capturedImage && (
          <aside className="w-full md:w-80 bg-slate-900 border-l border-white/10 p-6 flex flex-col gap-6 overflow-y-auto">
            <div className="mb-2">
              <h3 className="text-white font-black text-2xl tracking-tight mb-2">Stylize</h3>
              <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Choose a coloring upgrade</p>
            </div>

            <div className="flex flex-col gap-3 flex-1">
              {UPGRADES.map((upgrade) => (
                <button
                  key={upgrade.id}
                  onClick={() => handleSelectStyle(upgrade.id)}
                  className="group flex items-center gap-4 p-4 rounded-3xl bg-white/5 border border-white/10 hover:bg-white/10 hover:border-indigo-500/50 transition-all text-left"
                >
                  <div className={`p-3 rounded-2xl ${upgrade.color} text-white shadow-lg shadow-black/20 group-hover:scale-110 transition-transform`}>
                    <upgrade.icon className="w-6 h-6" />
                  </div>
                  <div>
                    <h4 className="text-white font-black text-sm uppercase tracking-wide">{upgrade.label}</h4>
                    <p className="text-slate-500 text-[10px] font-bold mt-0.5">{upgrade.description}</p>
                  </div>
                </button>
              ))}
            </div>

            <button
              onClick={() => setCapturedImage(null)}
              className="mt-4 flex items-center justify-center gap-3 p-4 rounded-2xl text-slate-400 font-bold hover:text-white hover:bg-white/5 transition-all text-sm border border-transparent hover:border-white/10"
