                >
                  Go Back
                </button>
              </div>
            )}

            {!capturedImage ? (
              <video 
                ref={videoRef} 
                autoPlay 
                playsInline 
                className={`w-full h-full object-cover ${isLoading || error ? 'hidden' : 'block'}`}
              />
            ) : (
              <img 
                src={capturedImage} 
                className="w-full h-full object-cover"
                alt="Captured"
              />
            )}
            <canvas ref={canvasRef} className="hidden" />
