            <div className="p-10 flex justify-center items-center bg-gradient-to-t from-black/80 to-transparent absolute bottom-0 left-0 right-0">
              <button
                onClick={handleSnap}
                className="group relative flex items-center justify-center w-24 h-24 rounded-full border-4 border-white transition-all transform active:scale-90 hover:scale-105"
              >
                <div className="w-18 h-18 bg-white rounded-full transition-all group-hover:bg-indigo-50 flex items-center justify-center shadow-xl">
                    <Camera className="w-8 h-8 text-slate-900" />
                </div>
              </button>
            </div>
          )}
        </div>

        {/* Upgrade Sidebar (Only when image is captured) */}
        {capturedImage && (
          <aside className="w-full md:w-80 bg-slate-900 border-l border-white/10 p-6 flex flex-col gap-6 overflow-y-auto">
            <div className="mb-2">
              <h3 className="text-white font-black text-2xl tracking-tight mb-2">Stylize</h3>
              <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Choose a coloring upgrade</p>
            </div>

            <div className="flex flex-col gap-3 flex-1">
              {UPGRADES.map((upgrade) => (
                <button
                  key={upgrade.id}
                  onClick={() => handleSelectStyle(upgrade.id)}
