}

const UPGRADES: { id: ColoringStyle; label: string; icon: any; description: string; color: string; isNew?: boolean }[] = [
  { id: 'sketchy', label: 'Sketchy', icon: Pencil, description: 'Raw artist pencil strokes', color: 'bg-emerald-500', isNew: true },
  { id: 'standard', label: 'Classic', icon: Camera, description: 'Clean & true outlines', color: 'bg-blue-500' },
  { id: 'bold', label: 'Bold Pop', icon: Star, description: 'Thick sticker outlines', color: 'bg-yellow-500' },
  { id: 'vintage', label: 'Vintage', icon: History, description: 'Classic storybook feel', color: 'bg-orange-500' },
  { id: 'comic', label: 'Comic', icon: Zap, description: 'Graphic novel style', color: 'bg-purple-500' },
  { id: 'popart', label: 'Pop Art', icon: Palette, description: 'Retro halftone dots', color: 'bg-rose-500', isNew: true },
  { id: 'detailed', label: 'Fine Art', icon: Layers, description: 'Intricate & complex', color: 'bg-indigo-500' },
