            )}

            {error && (
              <div className="p-8 text-center max-w-sm">
                <p className="text-red-400 font-black text-lg mb-4">{error}</p>
                <button 
                  onClick={onClose}
                  className="px-8 py-3 bg-white text-black font-black rounded-2xl hover:bg-slate-100 transition-all"
                >
                  Go Back
                </button>
              </div>
            )}

            {!capturedImage ? (
              <video 
                ref={videoRef} 
                autoPlay 
                playsInline 
                className={`w-full h-full object-cover ${isLoading || error ? 'hidden' : 'block'}`}
              />
            ) : (
              <img 
                src={capturedImage} 
                className="w-full h-full object-cover"
                alt="Captured"
              />
            )}
            <canvas ref={canvasRef} className="hidden" />
          </div>

          {/* Capture Button (Only in camera mode) */}
          {!capturedImage && !error && !isLoading && (
            <div className="p-10 flex justify-center items-center bg-gradient-to-t from-black/80 to-transparent absolute bottom-0 left-0 right-0">
              <button
                onClick={handleSnap}
                className="group relative flex items-center justify-center w-24 h-24 rounded-full border-4 border-white transition-all transform active:scale-90 hover:scale-105"
              >
                <div className="w-18 h-18 bg-white rounded-full transition-all group-hover:bg-indigo-50 flex items-center justify-center shadow-xl">
                    <Camera className="w-8 h-8 text-slate-900" />
                </div>
              </button>
            </div>
          )}
        </div>

        {/* Upgrade Sidebar (Only when image is captured) */}
        {capturedImage && (
          <aside className="w-full md:w-80 bg-slate-900 border-l border-white/10 p-6 flex flex-col gap-6 overflow-y-auto">
            <div className="mb-2">
              <h3 className="text-white font-black text-2xl tracking-tight mb-2">Stylize</h3>
              <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">Premium AI Upgrades</p>
            </div>

            <div className="flex flex-col gap-3 flex-1">
              {UPGRADES.map((upgrade) => (
                <button
                  key={upgrade.id}
                  onClick={() => handleSelectStyle(upgrade.id)}
                  className="group relative flex items-center gap-4 p-4 rounded-3xl bg-white/5 border border-white/10 hover:bg-white/10 hover:border-indigo-500/50 transition-all text-left"
                >
                  {upgrade.isNew && (
                    <span className="absolute -top-1 -right-1 bg-indigo-600 text-white text-[8px] font-black px-2 py-0.5 rounded-full shadow-lg z-10 animate-pulse uppercase tracking-tighter">
                      New Style
                    </span>
                  )}
                  <div className={`p-3 rounded-2xl ${upgrade.color} text-white shadow-lg shadow-black/20 group-hover:scale-110 transition-transform`}>
                    <upgrade.icon className="w-6 h-6" />
                  </div>
                  <div>
                    <h4 className="text-white font-black text-sm uppercase tracking-wide">{upgrade.label}</h4>
                    <p className="text-slate-500 text-[10px] font-bold mt-0.5">{upgrade.description}</p>
                  </div>
                </button>
              ))}
            </div>

            <button
              onClick={() => setCapturedImage(null)}
              className="mt-4 flex items-center justify-center gap-3 p-4 rounded-2xl text-slate-400 font-bold hover:text-white hover:bg-white/5 transition-all text-sm border border-transparent hover:border-white/10"
            >
              <RefreshCw className="w-4 h-4" />
              Retake Photo
            </button>
          </aside>
        )}
      </div>
    </div>
  );
};

