// Extend window for AI Studio APIs
declare global {
  // Define AIStudio interface to match the environment's expectation
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    // Property must match the existing global declaration's type and modifiers
    readonly aistudio: AIStudio;
  }
}

const AI_SUGGESTIONS = [
  "Add some cute flowers",
  "Make it a space adventure",
  "Add a friendly dragon",
  "Add a birthday cake",
  "Make the person a superhero"
];

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [brushColor, setBrushColor] = useState('#FF0000');
  const [brushSize, setBrushSize] = useState(10);
  const [activeTool, setActiveTool] = useState<ToolType>(ToolType.BRUSH);
  const [aiPrompt, setAiPrompt] = useState('');
  const [showCamera, setShowCamera] = useState(false);
  const [canUndo, setCanUndo] = useState(false);
  const [canRedo, setCanRedo] = useState(false);

  // New Quality States
  const [isProMode, setIsProMode] = useState(false);
  const [resolution, setResolution] = useState<ImageResolution>('1K');

  const fileInputRef = useRef<HTMLInputElement>(null);

  const checkProPermissions = async () => {
    try {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
        // Proceeding assuming selection was successful per guidelines
      }
      return true;
    } catch (e) {
      console.error("Key selection failed", e);
      return false;
    }
  };

  const toggleProMode = async () => {
    if (!isProMode) {
      const success = await checkProPermissions();
      if (success) setIsProMode(true);
    } else {
      setIsProMode(false);
      setResolution('1K');
    }
  };

  const handleResolutionChange = async (res: ImageResolution) => {
    if (res !== '1K' && !isProMode) {
      const success = await checkProPermissions();
      if (success) {
        setIsProMode(true);
        setResolution(res);
      }
    } else {
      setResolution(res);
    }
  };

  const processImage = async (base64: string, style: ColoringStyle = 'standard') => {
    setIsProcessing(true);
    try {
      const lineArt = await convertToLineArt(base64, style, resolution, isProMode);
      setImage(lineArt);
    } catch (error: any) {
      console.error("Processing failed", error);
      if (error?.message?.includes("Requested entity was not found")) {
        alert("API Key needs re-validation for Pro features.");
        await window.aistudio.openSelectKey();
      } else {
        alert("Oops! Something went wrong. Make sure it's a clear photo.");
      }
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result as string;
      await processImage(base64);
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsDataURL(file);
  };

  const handleAIEdit = async () => {
    if (!image || !aiPrompt) return;
    setIsProcessing(true);
    try {
      const edited = await editWithAI(image, aiPrompt, isProMode);
      setImage(edited);
      setAiPrompt('');
    } catch (error) {
      console.error("AI edit failed", error);
      alert("AI was unable to process that request.");
