                    <button onClick={() => (window as any).clearCanvas?.()} className="p-3 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-2xl transition-all flex items-center gap-2 px-4" title="Reset All Colors"><RotateCcw className="w-5 h-5" /><span className="text-[10px] font-black uppercase tracking-widest">Reset</span></button>
