import { convertToLineArt, editWithAI, ColoringStyle, ImageResolution } from './services/geminiService';
import { ToolType } from './types';

// Extend window for AI Studio APIs
declare global {
  // Define AIStudio interface to match the environment's expectation
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    // Removed readonly modifier to avoid "identical modifiers" conflict with existing environment declarations
    aistudio: AIStudio;
  }
}

const AI_SUGGESTIONS = [
  "Add some cute flowers",
  "Make it a space adventure",
  "Add a friendly dragon",
  "Add a birthday cake",
  "Make the person a superhero"
];

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [brushColor, setBrushColor] = useState('#FF0000');
  const [brushSize, setBrushSize] = useState(10);
  const [activeTool, setActiveTool] = useState<ToolType>(ToolType.BRUSH);
  const [aiPrompt, setAiPrompt] = useState('');
  const [showCamera, setShowCamera] = useState(false);
  const [canUndo, setCanUndo] = useState(false);
  const [canRedo, setCanRedo] = useState(false);

  // New Quality States
  const [isProMode, setIsProMode] = useState(false);
  const [resolution, setResolution] = useState<ImageResolution>('1K');

  const fileInputRef = useRef<HTMLInputElement>(null);

  const checkProPermissions = async () => {
    try {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
        // Proceeding assuming selection was successful per guidelines
      }
      return true;
    } catch (e) {
      console.error("Key selection failed", e);
      return false;
    }
  };

  const toggleProMode = async () => {
    if (!isProMode) {
      const success = await checkProPermissions();
      if (success) setIsProMode(true);
    } else {
      setIsProMode(false);
      setResolution('1K');
    }
  };

  const handleResolutionChange = async (res: ImageResolution) => {
    if (res !== '1K' && !isProMode) {
      const success = await checkProPermissions();
      if (success) {
        setIsProMode(true);
        setResolution(res);
      }
    } else {
      setResolution(res);
    }
  };

  const processImage = async (base64: string, style: ColoringStyle = 'standard') => {
    setIsProcessing(true);
    try {
      const lineArt = await convertToLineArt(base64, style, resolution, isProMode);
      setImage(lineArt);
    } catch (error: any) {
      console.error("Processing failed", error);
      if (error?.message?.includes("Requested entity was not found")) {
        alert("API Key needs re-validation for Pro features.");
        await window.aistudio.openSelectKey();
      } else {
        alert("Oops! Something went wrong. Make sure it's a clear photo.");
      }
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result as string;
      await processImage(base64);
      if (fileInputRef.current) fileInputRef.current.value = '';
    };
    reader.readAsDataURL(file);
  };

  const handleAIEdit = async () => {
    if (!image || !aiPrompt) return;
    setIsProcessing(true);
    try {
      const edited = await editWithAI(image, aiPrompt, isProMode);
      setImage(edited);
      setAiPrompt('');
    } catch (error) {
      console.error("AI edit failed", error);
      alert("AI was unable to process that request.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handlePrint = () => {
    const combined = (window as any).getCombinedImage?.();
    if (!combined) return;
    const printWindow = window.open('', '_blank');
    if (printWindow) {
      printWindow.document.write(`
        <html>
          <body style="margin:0; display:flex; justify-content:center; align-items:center; height:100vh; background:white;">
            <img src="${combined}" style="max-width:100%; max-height:100%; object-fit:contain;" />
            <script>window.onload = () => { window.print(); window.close(); };</script>
          </body>
        </html>
      `);
      printWindow.document.close();
    }
  };

  const handleDownload = (onlyLineArt = false) => {
    const data = onlyLineArt ? (window as any).getLineArtOnly?.() : (window as any).getCombinedImage?.();
    if (!data) return;
    const link = document.createElement('a');
    link.href = data;
    link.download = `chromasketch-${onlyLineArt ? 'lines' : 'art'}-${resolution}-${Date.now()}.png`;
    link.click();
  };

  const handleCropComplete = (newImageData: string) => {
    setImage(newImageData);
    setActiveTool(ToolType.BRUSH);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-900 overflow-hidden font-sans">
      {showCamera && (
        <CameraModal 
          onCapture={(base64, style) => { 
            setShowCamera(false); 
            processImage(base64, style); 
          }} 
          onClose={() => setShowCamera(false)} 
        />
      )}

      <header className="bg-white border-b border-slate-200 px-6 py-4 flex justify-between items-center shrink-0 shadow-sm z-20">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2.5 rounded-2xl shadow-lg shadow-indigo-100">
              <Sparkles className="text-white w-6 h-6" />
            </div>
            <div>
              <h1 className="text-xl font-extrabold tracking-tight text-slate-800">ChromaSketch AI</h1>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Digital Arts Studio</p>
            </div>
          </div>

          <div className="hidden lg:flex items-center gap-2 bg-slate-50 p-1.5 rounded-2xl border border-slate-200">
            <button 
              onClick={toggleProMode}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl transition-all font-black text-xs uppercase tracking-wider ${isProMode ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-white'}`}
            >
              <ShieldCheck className={`w-4 h-4 ${isProMode ? 'animate-pulse' : ''}`} />
              Studio Pro
            </button>
            <div className="w-[1px] h-4 bg-slate-200 mx-1" />
            {(['1K', '2K', '4K'] as ImageResolution[]).map(res => (
              <button
                key={res}
                onClick={() => handleResolutionChange(res)}
                className={`px-3 py-2 rounded-xl text-[10px] font-black transition-all ${resolution === res ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
              >
                {res}
              </button>
            ))}
          </div>
        </div>

        <div className="flex items-center gap-3">
          <div className="hidden sm:flex items-center gap-2 bg-slate-100 p-1 rounded-xl border border-slate-200">
            <button onClick={() => setShowCamera(true)} className="flex items-center gap-2 px-4 py-2 hover:bg-white text-slate-600 hover:text-indigo-600 rounded-lg transition-all font-semibold"><Camera className="w-4 h-4" /> Camera</button>
            <button onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 px-4 py-2 bg-white text-indigo-600 rounded-lg shadow-sm hover:shadow-md transition-all font-bold border border-indigo-50"><Upload className="w-4 h-4" /> Upload</button>
          </div>
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <aside className="w-80 bg-white border-r border-slate-200 p-6 flex flex-col gap-8 shrink-0 overflow-y-auto shadow-[4px_0_24px_rgba(0,0,0,0.02)] z-10">

          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-[0.2em] mb-4">Color Palette</h3>
            <ColorPicker currentColor={brushColor} onChange={setBrushColor} />
          </section>

          <section>
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-xs font-bold text-slate-400 uppercase tracking-[0.2em]">Brush Size</h3>
              <div 
                className="w-4 h-4 rounded-full border border-slate-200 shadow-inner" 
                style={{ backgroundColor: brushColor, transform: `scale(${Math.max(0.2, brushSize / 25)})` }}
              />
            </div>
            <div className="flex items-center gap-4 group">
              <input type="range" min="1" max="50" value={brushSize} onChange={(e) => setBrushSize(parseInt(e.target.value))} className="flex-1 h-1.5 bg-slate-100 rounded-lg appearance-none cursor-pointer accent-indigo-600" />
              <span className="text-xs font-mono font-bold text-slate-500 w-6">{brushSize}</span>
            </div>
          </section>

          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-[0.2em] mb-4">Artist's Tools</h3>
            <div className="grid grid-cols-2 gap-2">
              {[
                { id: ToolType.BRUSH, icon: Paintbrush, label: 'Brush' },
                { id: ToolType.HIGHLIGHTER, icon: Highlighter, label: 'Marker' },
                { id: ToolType.SPRAY, icon: Wind, label: 'Spray' },
                { id: ToolType.CALLIGRAPHY, icon: PenTool, label: 'Chisel' },
                { id: ToolType.RAINBOW, icon: Sparkles, label: 'Rainbow' },
                { id: ToolType.BUCKET, icon: PaintBucket, label: 'Fill' },
                { id: ToolType.ERASER, icon: Eraser, label: 'Eraser' },
                { id: ToolType.CROP, icon: Crop, label: 'Crop' }
              ].map(t => (
                <button 
                  key={t.id} 
                  onClick={() => setActiveTool(t.id)} 
                  className={`flex items-center gap-3 p-3 rounded-xl border-2 transition-all ${activeTool === t.id ? 'border-indigo-600 bg-indigo-50/50 text-indigo-700 font-bold shadow-sm' : 'border-slate-50 text-slate-500 hover:border-slate-200 hover:bg-slate-50'}`}
                >
                  <t.icon className="w-4 h-4" />
                  <span className="text-[10px] font-black uppercase tracking-tight">{t.label}</span>
                </button>
              ))}
            </div>
          </section>

          <section className="mt-auto space-y-4">
            <div className="bg-gradient-to-br from-indigo-50 to-slate-50 rounded-2xl p-4 border border-indigo-100 shadow-sm">
              <h3 className="text-xs font-bold text-indigo-600 uppercase tracking-wider mb-3 flex items-center gap-2">
                <Wand2 className="w-3 h-3" /> AI Enhancer {isProMode && <span className="bg-indigo-600 text-white px-1.5 py-0.5 rounded text-[8px] font-black ml-1">PRO</span>}
              </h3>
              <textarea
                placeholder="E.g. Add butterflies..."
                value={aiPrompt}
                onChange={(e) => setAiPrompt(e.target.value)}
                className="w-full text-xs p-3 rounded-xl border border-white bg-white/50 focus:bg-white focus:ring-2 focus:ring-indigo-500 outline-none resize-none h-20 transition-all shadow-inner"
              />
              <div className="flex flex-wrap gap-1.5 mt-3">
                {AI_SUGGESTIONS.slice(0, 3).map(s => (
                  <button key={s} onClick={() => setAiPrompt(s)} className="text-[9px] px-2 py-1 bg-white border border-slate-100 text-slate-500 rounded-full hover:border-indigo-200 transition-colors">
                    {s}
                  </button>
                ))}
              </div>
              <button disabled={!image || isProcessing || !aiPrompt} onClick={handleAIEdit} className="mt-4 w-full bg-indigo-600 text-white p-2.5 rounded-xl text-xs font-bold flex items-center justify-center gap-2 disabled:opacity-30 hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 active:scale-95">
                {isProcessing ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Sparkles className="w-3.5 h-3.5" />}
                Apply Magic
              </button>
            </div>
          </section>
        </aside>

        <section className="flex-1 flex flex-col p-8 relative overflow-hidden">
          <div className="flex-1 relative">
            {isProcessing && (
              <div className="absolute inset-0 z-[100] flex items-center justify-center bg-white/60 backdrop-blur-sm rounded-3xl">
                <div className="bg-white p-12 rounded-[2.5rem] shadow-2xl flex flex-col items-center gap-8 border border-slate-100 max-w-sm text-center">
                  <div className="relative">
                    <div className="w-24 h-24 border-[6px] border-slate-50 border-t-indigo-600 rounded-full animate-spin"></div>
                    <Sparkles className="w-10 h-10 text-indigo-500 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 animate-pulse" />
                  </div>
                  <div>
                    <h4 className="text-2xl font-black text-slate-800 mb-2">Creating Magic...</h4>
                    <p className="text-slate-400 font-medium leading-relaxed">Gemini {isProMode ? 'Pro' : ''} is transforming your photo into a {resolution} masterpiece.</p>
                  </div>
                </div>
              </div>
            )}

            {!image && !isProcessing ? (
              <div className="h-full border-4 border-dashed border-slate-100 rounded-[2.5rem] flex flex-col items-center justify-center bg-white gap-8 text-center px-16 group transition-all hover:border-indigo-100">
                <div className="relative">
                  <div className="w-32 h-32 bg-indigo-50/50 text-indigo-600 rounded-[2rem] flex items-center justify-center transform group-hover:rotate-6 transition-transform">
                    <ImageIcon className="w-16 h-16" />
                  </div>
                  <Sparkles className="w-8 h-8 text-yellow-400 absolute -top-4 -right-4 animate-bounce" />
                </div>
                <div>
                  <h2 className="text-4xl font-black text-slate-800 mb-4 tracking-tight">Your Digital Canvas</h2>
                  <p className="text-slate-400 max-w-sm font-medium leading-relaxed text-lg">Upload any photo or snap a picture. Our AI turns it into a perfect line art page.</p>
                </div>
                <div className="flex flex-col sm:flex-row gap-4">
                  <button onClick={() => setShowCamera(true)} className="bg-indigo-600 text-white px-10 py-4 rounded-2xl font-black text-lg hover:bg-indigo-700 transition-all transform hover:-translate-y-1 shadow-xl shadow-indigo-100 flex items-center gap-3">
                    <Camera className="w-6 h-6" /> Camera
                  </button>
                  <button onClick={() => fileInputRef.current?.click()} className="bg-white text-indigo-600 border-2 border-indigo-600 px-10 py-4 rounded-2xl font-black text-lg hover:bg-indigo-50 transition-all transform hover:-translate-y-1 flex items-center gap-3">
                    <Upload className="w-6 h-6" /> Upload Photo
                  </button>
                </div>
                <div className="mt-4 flex items-center gap-2 text-slate-300 font-bold text-xs uppercase tracking-widest">
                   <Maximize2 className="w-4 h-4" /> Supports up to 4K resolution in Studio Pro mode
                </div>
              </div>
            ) : (
              <Editor 
                backgroundImage={image} 
                brushColor={brushColor} 
                brushSize={brushSize} 
                tool={activeTool}
                onHistoryChange={(u, r) => { setCanUndo(u); setCanRedo(r); }}
                onCropComplete={handleCropComplete}
              />
            )}
          </div>

          {image && (
            <div className="mt-8 flex justify-between items-center bg-white p-4 rounded-3xl border border-slate-200 shadow-[0_8px_32px_rgba(0,0,0,0.04)]">
              <div className="flex gap-2">
                {activeTool === ToolType.CROP ? (
                  <button 
                    onClick={() => (window as any).applyCrop?.()}
                    className="p-3 bg-indigo-600 text-white rounded-2xl transition-all flex items-center gap-3 px-6 hover:bg-indigo-700 shadow-md active:scale-95"
                  >
                    <Check className="w-5 h-5" />
                    <span className="text-[12px] font-black uppercase tracking-widest">Confirm Crop</span>
                  </button>
                ) : (
                  <>
                    <button onClick={() => (window as any).undo?.()} disabled={!canUndo} className={`p-3 rounded-2xl transition-all ${canUndo ? 'text-indigo-600 bg-indigo-50/50 hover:bg-indigo-100' : 'text-slate-200 cursor-not-allowed'}`} title="Undo"><Undo className="w-5 h-5" /></button>
                    <button onClick={() => (window as any).redo?.()} disabled={!canRedo} className={`p-3 rounded-2xl transition-all ${canRedo ? 'text-indigo-600 bg-indigo-50/50 hover:bg-indigo-100' : 'text-slate-200 cursor-not-allowed'}`} title="Redo"><Redo className="w-5 h-5" /></button>
                    <div className="w-[1px] h-10 bg-slate-100 mx-2 self-center" />
                    <button onClick={() => (window as any).clearCanvas?.()} className="p-3 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-2xl transition-all flex items-center gap-2 px-4" title="Reset All Colors"><RotateCcw className="w-5 h-5" /><span className="text-[10px] font-black uppercase tracking-widest">Reset</span></button>
                  </>
                )}
              </div>
              <div className="flex gap-4">
                <div className="flex bg-slate-100 p-1 rounded-2xl border border-slate-200">
                  <button onClick={() => handleDownload(true)} className="px-5 py-2.5 text-slate-600 hover:bg-white rounded-xl transition-all font-bold text-xs">Lines Only</button>
                  <button onClick={() => handleDownload(false)} className="px-5 py-2.5 bg-white text-indigo-600 rounded-xl shadow-sm font-bold text-xs">Save Art</button>
                </div>
                <button onClick={handlePrint} className="flex items-center gap-3 px-8 py-3 bg-indigo-600 text-white font-black text-sm rounded-2xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 active:scale-95"><Printer className="w-5 h-5" /> Print Now</button>
              </div>
            </div>
          )}
        </section>
      </main>

      <footer className="bg-white border-t border-slate-100 px-8 py-3 text-[10px] text-slate-300 font-bold uppercase tracking-[0.3em] flex justify-between shrink-0">
        <div className="flex gap-4 items-center">
          <span>© 2025 ChromaSketch AI Studio</span>
          {isProMode && <span className="text-indigo-500 flex items-center gap-1"><ShieldCheck className="w-3 h-3" /> Studio Pro Active</span>}
        </div>
        <div className="flex gap-8">
          <span>AI Engine: Gemini {isProMode ? '3 Pro' : '2.5 Flash'}</span>
          <span>Resolution: {resolution} Precision</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

