import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

export type ColoringStyle = 'standard' | 'bold' | 'detailed' | 'cute' | 'vintage' | 'sketchy' | 'comic' | 'popart' | 'zentangle';
export type ImageResolution = '1K' | '2K' | '4K';

const STYLE_PROMPTS: Record<ColoringStyle, string> = {
  standard: "Transform this image into a clean, high-contrast black and white coloring book page. Use only solid black lines for outlines and ensure the background is pure white with no shading, gradients, or textures.",
  bold: "Transform this image into a bold sticker-style coloring page. Use very thick, solid black outlines and extremely simplified shapes. Remove all small details. Perfect for young children.",
  detailed: "Transform this image into an intricate, highly detailed fine-line coloring page. Capture complex textures and patterns using only thin black lines. Suitable for adult coloring books.",
  cute: "Transform this image into a cute, bubbly cartoon coloring page. Exaggerate features like eyes to make them bigger and rounder. Use soft but clear black outlines and a simplified, playful style.",
  vintage: "Transform this image into a vintage-style coloring page. Use slightly textured, organic black lines that mimic 19th-century woodcuts, antique engravings, or classic storybook illustrations. Add subtle cross-hatching and etched details, but keep it clear for coloring. Pure black ink on white background.",
  sketchy: "Transform this image into an expressive, artistic sketchy pencil-drawing style coloring page. Use multiple overlapping thin black lines, rough strokes, and varied line weights to create a hand-drawn, energetic look. Maintain clear white space for coloring.",
  comic: "Transform this image into a dramatic comic book coloring page. Use deep black shadows (chiaroscuro style), bold dynamic outlines, and stylized action details. Ensure it remains a white-background coloring page with pure black ink for a professional graphic novel look.",
  popart: "Transform this image into a retro Pop Art coloring page. Use bold black outlines and incorporate halftone dot patterns (ben-day dots) for shading. Keep the style graphic and iconic, similar to 1960s comic art, but optimized for coloring.",
  zentangle: "Transform this image into a complex Zentangle coloring page. Fill the large shapes and background areas with intricate repetitive patterns like swirls, dots, scales, and geometric shapes. Ensure all patterns are made of clean black lines on a white background."
};

/**
 * Converts an image to line art.
 */
export const convertToLineArt = async (
  base64Image: string, 
  style: ColoringStyle = 'standard',
  resolution: ImageResolution = '1K',
  usePro: boolean = false
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const mimeType = base64Image.split(';')[0].split(':')[1];
  const base64Data = base64Image.split(',')[1];

  const stylePrompt = STYLE_PROMPTS[style] || STYLE_PROMPTS.standard;
  const isHighRes = resolution === '2K' || resolution === '4K';
  const modelName = (usePro || isHighRes) ? 'gemini-3-pro-image-preview' : 'gemini-2.5-flash-image';

  // Specific enhancement for high-res requests
  const qualityInstruction = isHighRes 
    ? " CRITICAL: Output MUST have vector-like precision. Zero anti-aliasing artifacts. Lines must be razor sharp even when zoomed in 400%. Purest possible #000000 ink."
    : "";

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: modelName,
    contents: {
      parts: [
        { inlineData: { mimeType, data: base64Data } },
        { text: stylePrompt + qualityInstruction + " The result MUST be pure black and white line art on a white background. Optimize for professional ultra-large scale printing." },
      ],
    },
    config: modelName === 'gemini-3-pro-image-preview' ? {
      imageConfig: {
        aspectRatio: "1:1",
        imageSize: resolution
      }
    } : undefined
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Failed to generate line art");
};

/**
 * Specifically master/upscale the current work using Pro 4K model
 */
export const upscaleToStudioMaster = async (base64Artwork: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const mimeType = base64Artwork.split(';')[0].split(':')[1];
  const base64Data = base64Artwork.split(',')[1];

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: {
      parts: [
        { inlineData: { mimeType, data: base64Data } },
        { text: "This is a completed coloring art piece. REGENERATE this entire image with 4K Studio Quality. Enhance the line precision, remove any digital noise, and ensure the colored areas are solid and vibrant with perfect edges. Maintain the exact composition. This will be used for a 1-meter wide wall print." },
      ],
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1",
        imageSize: "4K"
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Failed to master image in 4K");
};

export const editWithAI = async (base64Image: string, prompt: string, usePro: boolean = false): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const mimeType = base64Image.split(';')[0].split(':')[1];
  const base64Data = base64Image.split(',')[1];

  const modelName = usePro ? 'gemini-3-pro-image-preview' : 'gemini-2.5-flash-image';

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: modelName,
    contents: {
      parts: [
        { inlineData: { mimeType, data: base64Data } },
        { text: `Modify this coloring page: ${prompt}. Maintain the sharp black and white line art style for coloring.` },
      ],
    },
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Failed to edit image");
};

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { ToolType } from '../types';
import { ZoomIn, ZoomOut, Maximize, Hand } from 'lucide-react';

interface EditorProps {
  backgroundImage: string | null;
  brushColor: string;
  brushSize: number;
  tool: ToolType;
  onHistoryChange?: (canUndo: boolean, canRedo: boolean) => void;
  onCropComplete?: (newLineArt: string) => void;
}

const MAX_HISTORY = 50;
const HANDLE_SIZE = 12;

function hexToRgb(hex: string) {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16),
    g: parseInt(result[2], 16),
    b: parseInt(result[3], 16)
  } : { r: 0, g: 0, b: 0 };
}

export const Editor: React.FC<EditorProps> = ({ backgroundImage, brushColor, brushSize, tool, onHistoryChange, onCropComplete }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null); // Line Art Canvas
  const drawingCanvasRef = useRef<HTMLCanvasElement>(null); // Coloring Canvas
  const [isDrawing, setIsDrawing] = useState(false);
  const rainbowHueRef = useRef(0);

  // View State (Enlargement/Navigation)
  const [scale, setScale] = useState(1);
  const [offset, setOffset] = useState({ x: 0, y: 0 });

  // Crop States
  const [cropRect, setCropRect] = useState({ x: 50, y: 50, w: 300, h: 300 });
  const [dragMode, setDragMode] = useState<'none' | 'move' | number>('none');
  const [startDragCoords, setStartDragCoords] = useState({ x: 0, y: 0 });
  const [initialCropRect, setInitialCropRect] = useState({ x: 0, y: 0, w: 0, h: 0 });

  const historyRef = useRef<ImageData[]>([]);
  const historyIndexRef = useRef<number>(-1);

  const updateHistoryStatus = useCallback(() => {
    if (onHistoryChange) {
      onHistoryChange(
        historyIndexRef.current > 0,
        historyIndexRef.current < historyRef.current.length - 1
      );
    }
  }, [onHistoryChange]);

  const saveState = useCallback(() => {
    const canvas = drawingCanvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (canvas && ctx) {
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      if (historyIndexRef.current < historyRef.current.length - 1) {
        historyRef.current = historyRef.current.slice(0, historyIndexRef.current + 1);
      }
      historyRef.current.push(imageData);
      if (historyRef.current.length > MAX_HISTORY) {
        historyRef.current.shift();
      } else {
        historyIndexRef.current++;
      }
      updateHistoryStatus();
    }
  }, [updateHistoryStatus]);

  const undo = useCallback(() => {
    if (historyIndexRef.current > 0) {
      historyIndexRef.current--;
      const canvas = drawingCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (canvas && ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.putImageData(historyRef.current[historyIndexRef.current], 0, 0);
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  const redo = useCallback(() => {
    if (historyIndexRef.current < historyRef.current.length - 1) {
      historyIndexRef.current++;
      const canvas = drawingCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (canvas && ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.putImageData(historyRef.current[historyIndexRef.current], 0, 0);
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  const clearDrawing = useCallback(() => {
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.clearRect(0, 0, drawingCanvasRef.current!.width, drawingCanvasRef.current!.height);
      saveState();
    }
  }, [saveState]);

  useEffect(() => {
    if (drawingCanvasRef.current && historyRef.current.length === 0) {
      const ctx = drawingCanvasRef.current.getContext('2d');
      if (ctx) {
        const empty = ctx.getImageData(0, 0, drawingCanvasRef.current.width, drawingCanvasRef.current.height);
        historyRef.current = [empty];
        historyIndexRef.current = 0;
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  useEffect(() => {
    const resize = () => {
      const parent = drawingCanvasRef.current?.parentElement;
      if (!parent || !canvasRef.current || !drawingCanvasRef.current) return;

      const { clientWidth: w, clientHeight: h } = parent;

      const temp = document.createElement('canvas');
      temp.width = drawingCanvasRef.current.width;
      temp.height = drawingCanvasRef.current.height;
      temp.getContext('2d')?.drawImage(drawingCanvasRef.current, 0, 0);

      canvasRef.current.width = w;
      canvasRef.current.height = h;
      drawingCanvasRef.current.width = w;
      drawingCanvasRef.current.height = h;

      const ctx = drawingCanvasRef.current.getContext('2d');
      if (ctx) {
        ctx.drawImage(temp, 0, 0, temp.width, temp.height, 0, 0, w, h);
      }

      if (backgroundImage) {
        const bgCtx = canvasRef.current.getContext('2d');
        if (bgCtx) {
          const img = new Image();
          img.onload = () => {
            bgCtx.clearRect(0, 0, w, h);
            const scaleFactor = Math.min(w / img.width, h / img.height);
            const x = (w / 2) - (img.width / 2) * scaleFactor;
            const y = (h / 2) - (img.height / 2) * scaleFactor;
            bgCtx.drawImage(img, x, y, img.width * scaleFactor, img.height * scaleFactor);
          };
          img.src = backgroundImage;
        }
      }
      setCropRect({ x: w * 0.1, y: h * 0.1, w: w * 0.8, h: h * 0.8 });
    };

    window.addEventListener('resize', resize);
    resize();
    return () => window.removeEventListener('resize', resize);
  }, [backgroundImage]);

  const getCoords = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = drawingCanvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = canvas.getBoundingClientRect();
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    // Adjust for current Scale and Offset (Zoom/Pan)
    const rawX = (clientX - rect.left) * (canvas.width / rect.width);
    const rawY = (clientY - rect.top) * (canvas.height / rect.height);

    return {
      x: (rawX - offset.x) / scale,
      y: (rawY - offset.y) / scale
    };
  };

  const applyCrop = useCallback(() => {
    if (!canvasRef.current || !drawingCanvasRef.current) return;
    const { x, y, w, h } = cropRect;
    if (w <= 5 || h <= 5) return;

    const lineArtCrop = document.createElement('canvas');
    lineArtCrop.width = w;
    lineArtCrop.height = h;
    lineArtCrop.getContext('2d')?.drawImage(canvasRef.current, x, y, w, h, 0, 0, w, h);
    const newLineArt = lineArtCrop.toDataURL('image/png');

    const drawingCrop = document.createElement('canvas');
    drawingCrop.width = w;
    drawingCrop.height = h;
    drawingCrop.getContext('2d')?.drawImage(drawingCanvasRef.current, x, y, w, h, 0, 0, w, h);

    if (onCropComplete) {
      onCropComplete(newLineArt);
      const dCtx = drawingCanvasRef.current.getContext('2d');
      if (dCtx) {
        dCtx.clearRect(0, 0, drawingCanvasRef.current.width, drawingCanvasRef.current.height);
        dCtx.drawImage(drawingCrop, 0, 0, w, h, 0, 0, drawingCanvasRef.current.width, drawingCanvasRef.current.height);
        saveState();
      }
    }
  }, [cropRect, onCropComplete, saveState]);

  const handleBucketFill = (startX: number, startY: number) => {
    const canvas = drawingCanvasRef.current;
    const bgCanvas = canvasRef.current;
    if (!canvas || !bgCanvas) return;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    const { width, height } = canvas;
    const tempCanvas = document.createElement('canvas');
    tempCanvas.width = width;
    tempCanvas.height = height;
    const tCtx = tempCanvas.getContext('2d', { willReadFrequently: true })!;
    tCtx.fillStyle = '#ffffff';
    tCtx.fillRect(0, 0, width, height);
    tCtx.drawImage(bgCanvas, 0, 0);
    tCtx.drawImage(canvas, 0, 0);

    const imgData = tCtx.getImageData(0, 0, width, height);
    const pixels = imgData.data;
    const x = Math.round(startX);
    const y = Math.round(startY);
    const pos = (y * width + x) * 4;
    const [tR, tG, tB] = [pixels[pos], pixels[pos+1], pixels[pos+2]];
    const fill = hexToRgb(brushColor);

    if (Math.abs(tR - fill.r) < 10 && Math.abs(tG - fill.g) < 10 && Math.abs(tB - fill.b) < 10) return;

    const stack = [[x, y]];
    const seen = new Uint8Array(width * height);
    const fillPixels = new Uint8Array(width * height);
    const threshold = 60;

    while (stack.length) {
      const [cx, cy] = stack.pop()!;
      if (cx < 0 || cx >= width || cy < 0 || cy >= height) continue;
      const idx = cy * width + cx;
      if (seen[idx]) continue;
      seen[idx] = 1;

      const p = idx * 4;
      if (Math.abs(pixels[p] - tR) < threshold && Math.abs(pixels[p+1] - tG) < threshold && Math.abs(pixels[p+2] - tB) < threshold) {
        fillPixels[idx] = 1;
        stack.push([cx + 1, cy], [cx - 1, cy], [cx, cy + 1], [cx, cy - 1]);
      }
    }

    const res = ctx.createImageData(width, height);
    for (let i = 0; i < width * height; i++) {
      if (fillPixels[i]) {
        const p = i * 4;
        res.data[p] = fill.r;
        res.data[p+1] = fill.g;
        res.data[p+2] = fill.b;
        res.data[p+3] = 255;
      }
    }
    const scratch = document.createElement('canvas');
    scratch.width = width;
    scratch.height = height;
    scratch.getContext('2d')?.putImageData(res, 0, 0);
    ctx.globalCompositeOperation = 'source-over';
    ctx.drawImage(scratch, 0, 0);
    saveState();
  };

  const getHandleAt = (px: number, py: number) => {
    const { x, y, w, h } = cropRect;
    const handles = [
      { x: x, y: y }, { x: x + w, y: y }, { x: x + w, y: y + h }, { x: x, y: y + h },
      { x: x + w / 2, y: y }, { x: x + w, y: y + h / 2 }, { x: x + w / 2, y: y + h }, { x: x, y: y + h / 2 }
    ];
    for (let i = 0; i < handles.length; i++) {
      if (Math.abs(px - handles[i].x) < HANDLE_SIZE && Math.abs(py - handles[i].y) < HANDLE_SIZE) return i;
    }
    return -1;
  };

  const start = (e: React.MouseEvent | React.TouchEvent) => {
    const coords = getCoords(e);

    if (tool === ToolType.PAN) {
      setDragMode('move');
      const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
      const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;
      setStartDragCoords({ x: clientX, y: clientY });
      setInitialCropRect({ x: offset.x, y: offset.y, w: 0, h: 0 });
      return;
    }

    if (tool === ToolType.CROP) {
      const handleIdx = getHandleAt(coords.x, coords.y);
      if (handleIdx !== -1) setDragMode(handleIdx);
      else if (coords.x >= cropRect.x && coords.x <= cropRect.x + cropRect.w && coords.y >= cropRect.y && coords.y <= cropRect.y + cropRect.h) setDragMode('move');
      else return;
      setStartDragCoords(coords);
      setInitialCropRect({ ...cropRect });
      return;
    }

    if (tool === ToolType.BUCKET) return handleBucketFill(coords.x, coords.y);
    setIsDrawing(true);
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.beginPath();
      ctx.moveTo(coords.x, coords.y);
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.globalCompositeOperation = tool === ToolType.ERASER ? 'destination-out' : 'source-over';
      ctx.globalAlpha = tool === ToolType.HIGHLIGHTER ? 0.35 : 1.0;
      ctx.lineWidth = brushSize;
      if (tool === ToolType.CALLIGRAPHY) ctx.lineCap = 'butt';
    }
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    const coords = getCoords(e);

    if (tool === ToolType.PAN && dragMode === 'move') {
      const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
      const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;
      const dx = clientX - startDragCoords.x;
      const dy = clientY - startDragCoords.y;
      setOffset({ x: initialCropRect.x + dx, y: initialCropRect.y + dy });
      return;
    }

    if (tool === ToolType.CROP && dragMode !== 'none') {
      const dx = coords.x - startDragCoords.x;
      const dy = coords.y - startDragCoords.y;
      const newRect = { ...initialCropRect };
      if (dragMode === 'move') { newRect.x += dx; newRect.y += dy; }
      else {
        switch (dragMode) {
          case 0: newRect.x += dx; newRect.y += dy; newRect.w -= dx; newRect.h -= dy; break;
          case 1: newRect.y += dy; newRect.w += dx; newRect.h -= dy; break;
          case 2: newRect.w += dx; newRect.h += dy; break;
          case 3: newRect.x += dx; newRect.w -= dx; newRect.h += dy; break;
          case 4: newRect.y += dy; newRect.h -= dy; break;
          case 5: newRect.w += dx; break;
          case 6: newRect.h += dy; break;
          case 7: newRect.x += dx; newRect.w -= dx; break;
        }
      }
      if (newRect.w < 10) newRect.w = 10;
      if (newRect.h < 10) newRect.h = 10;
      setCropRect(newRect);
      return;
    }

    if (!isDrawing || tool === ToolType.BUCKET) return;
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (!ctx) return;

    if (tool === ToolType.SPRAY) {
      ctx.fillStyle = brushColor;
      const density = 20 + brushSize / 2;
      for (let i = 0; i < density; i++) {
        const angle = Math.random() * Math.PI * 2;
        const dist = Math.random() * brushSize;
        const px = coords.x + Math.cos(angle) * dist;
        const py = coords.y + Math.sin(angle) * dist;
        ctx.fillRect(px, py, 1.2, 1.2);
      }
    } else if (tool === ToolType.RAINBOW) {
      rainbowHueRef.current = (rainbowHueRef.current + 3) % 360;
      ctx.strokeStyle = `hsl(${rainbowHueRef.current}, 100%, 50%)`;
      ctx.lineTo(coords.x, coords.y);
      ctx.stroke();
    } else if (tool === ToolType.CALLIGRAPHY) {
      ctx.strokeStyle = brushColor;
      const thickness = brushSize;
      const angle = Math.PI / 4;
      ctx.lineWidth = 1;
      for (let i = -thickness/2; i < thickness/2; i++) {
        ctx.lineTo(coords.x + i * Math.cos(angle), coords.y + i * Math.sin(angle));
      }
      ctx.stroke();
    } else {
      ctx.strokeStyle = tool === ToolType.ERASER ? 'rgba(255,255,255,1)' : brushColor;
      ctx.lineTo(coords.x, coords.y);
      ctx.stroke();
    }
  };

  const stop = () => { 
    if (isDrawing) { setIsDrawing(false); saveState(); }
    setDragMode('none');
  };

  const getCombined = () => {
    if (!canvasRef.current || !drawingCanvasRef.current) return '';
    const final = document.createElement('canvas');
    final.width = canvasRef.current.width;
    final.height = canvasRef.current.height;
    const ctx = final.getContext('2d')!;
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, final.width, final.height);
    ctx.drawImage(drawingCanvasRef.current, 0, 0);
    ctx.globalCompositeOperation = 'multiply';
    ctx.drawImage(canvasRef.current, 0, 0);
    return final.toDataURL('image/png');
  };

  const handleZoom = (delta: number) => {
    setScale(prev => Math.min(8, Math.max(0.5, prev + delta)));
  };

  const resetView = () => {
    setScale(1);
    setOffset({ x: 0, y: 0 });
  };

  useEffect(() => {
    (window as any).clearCanvas = clearDrawing;
    (window as any).getCombinedImage = getCombined;
    (window as any).undo = undo;
    (window as any).redo = redo;
    (window as any).applyCrop = applyCrop;
  }, [clearDrawing, undo, redo, applyCrop, backgroundImage, brushColor, brushSize, tool]);

  return (
    <div className="relative w-full h-full bg-white rounded-xl shadow-inner overflow-hidden border-2 border-slate-200 group">
      {/* Transformation Container */}
      <div 
        className="absolute inset-0 transition-transform duration-200 ease-out origin-top-left"
        style={{ transform: `translate(${offset.x}px, ${offset.y}px) scale(${scale})` }}
      >
        <canvas
          ref={drawingCanvasRef}
          onMouseDown={start}
          onMouseMove={draw}
          onMouseUp={stop}
          onMouseLeave={stop}
          onTouchStart={start}
          onTouchMove={draw}
          onTouchEnd={stop}
          className={`absolute inset-0 touch-none ${tool === ToolType.PAN ? 'cursor-grab active:cursor-grabbing' : (tool === ToolType.CROP ? 'cursor-default' : 'cursor-crosshair')}`}
        />
        <canvas ref={canvasRef} className="absolute inset-0 pointer-events-none mix-blend-multiply" />
      </div>

      {/* Zoom Overlay */}
      <div className="absolute bottom-6 right-6 flex flex-col gap-2 p-1 bg-white/80 backdrop-blur-md rounded-2xl border border-slate-200 shadow-xl opacity-0 group-hover:opacity-100 transition-opacity">
        <button onClick={() => handleZoom(0.25)} className="p-3 hover:bg-white text-slate-600 rounded-xl transition-all" title="Enlarge View"><ZoomIn className="w-5 h-5" /></button>
        <div className="h-[1px] bg-slate-100 mx-2" />
        <div className="text-[10px] font-black text-slate-400 text-center py-1">{Math.round(scale * 100)}%</div>
        <div className="h-[1px] bg-slate-100 mx-2" />
        <button onClick={() => handleZoom(-0.25)} className="p-3 hover:bg-white text-slate-600 rounded-xl transition-all" title="Zoom Out"><ZoomOut className="w-5 h-5" /></button>
        <button onClick={resetView} className="p-3 hover:bg-white text-indigo-600 rounded-xl transition-all" title="Fit to Screen"><Maximize className="w-5 h-5" /></button>
      </div>

      {tool === ToolType.CROP && (
        <div className="absolute inset-0 pointer-events-none">
          {/* Note: Crop doesn't zoom with the image for UX simplicity */}
          <div className="absolute border-2 border-white shadow-[0_0_0_1px_rgba(0,0,0,0.5)] pointer-events-auto" style={{ left: cropRect.x, top: cropRect.y, width: cropRect.w, height: cropRect.h }}>
             {/* Crop handles implementation simplified for brevity */}
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { 
  Plus, 
  Upload, 
  Printer, 
  RotateCcw, 
  Eraser, 
  Paintbrush, 
  Sparkles, 
  Download,
  Camera,
  Loader2,
  Trash2,
  Wand2,
  Image as ImageIcon,
  Undo,
  Redo,
  PaintBucket,
  Crop,
  Check,
  ChevronRight,
  ShieldCheck,
  Settings2,
  Maximize2,
  Type,
  PenTool,
  Wind,
  Highlighter,
  Hand,
  Trophy
} from 'lucide-react';
import { ColorPicker } from './components/ColorPicker';
import { Editor } from './components/Editor';
import { CameraModal } from './components/CameraModal';
import { convertToLineArt, editWithAI, upscaleToStudioMaster, ColoringStyle, ImageResolution } from './services/geminiService';
import { ToolType } from './types';

declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    aistudio: AIStudio;
  }
}

const AI_SUGGESTIONS = [
  "Add some cute flowers",
  "Make it a space adventure",
  "Add a friendly dragon",
  "Add a birthday cake",
  "Make the person a superhero"
];

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [brushColor, setBrushColor] = useState('#FF0000');
  const [brushSize, setBrushSize] = useState(10);
  const [activeTool, setActiveTool] = useState<ToolType>(ToolType.BRUSH);
  const [aiPrompt, setAiPrompt] = useState('');
  const [showCamera, setShowCamera] = useState(false);
  const [canUndo, setCanUndo] = useState(false);
  const [canRedo, setCanRedo] = useState(false);

  const [isProMode, setIsProMode] = useState(false);
  const [resolution, setResolution] = useState<ImageResolution>('1K');

  const fileInputRef = useRef<HTMLInputElement>(null);

  const checkProPermissions = async () => {
    try {
      const hasKey = await window.aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await window.aistudio.openSelectKey();
      }
      return true;
    } catch (e) {
      console.error("Key selection failed", e);
      return false;
    }
  };

  const toggleProMode = async () => {
    if (!isProMode) {
      const success = await checkProPermissions();
      if (success) setIsProMode(true);
    } else {
      setIsProMode(false);
      setResolution('1K');
    }
  };

  const handleResolutionChange = async (res: ImageResolution) => {
    if (res !== '1K' && !isProMode) {
      const success = await checkProPermissions();
      if (success) {
        setIsProMode(true);
        setResolution(res);
      }
    } else {
      setResolution(res);
    }
  };

  const processImage = async (base64: string, style: ColoringStyle = 'standard') => {
    setIsProcessing(true);
    try {
      const lineArt = await convertToLineArt(base64, style, resolution, isProMode);
      setImage(lineArt);
    } catch (error: any) {
      console.error("Processing failed", error);
      alert("Processing error. Ensure the image is clear and you have pro access if 4K is selected.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleMasterUpscale = async () => {
    const data = (window as any).getCombinedImage?.();
    if (!data) return;

    setIsProcessing(true);
    try {
      const mastered = await upscaleToStudioMaster(data);
      setImage(mastered);
      setResolution('4K');
      setIsProMode(true);
    } catch (error) {
      console.error("Master upscale failed", error);
      alert("Upscaling failed. Ensure you have a valid Studio Pro session.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result as string;
      await processImage(base64);
    };
    reader.readAsDataURL(file);
  };

  const handleAIEdit = async () => {
    if (!image || !aiPrompt) return;
    setIsProcessing(true);
    try {
