                { id: ToolType.SPRAY, icon: Wind, label: 'Spray' },
                { id: ToolType.CALLIGRAPHY, icon: PenTool, label: 'Chisel' },
                { id: ToolType.RAINBOW, icon: Sparkles, label: 'Rainbow' },
                { id: ToolType.BUCKET, icon: PaintBucket, label: 'Fill' },
