                </button>
              ))}
            </div>
          </section>

          <section className="mt-auto">
            {image && (
              <button 
                onClick={handleMasterUpscale}
                className="w-full mb-4 group relative flex items-center justify-center gap-3 p-4 bg-gradient-to-r from-indigo-600 to-purple-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg hover:scale-[1.02] active:scale-95 transition-all overflow-hidden"
              >
                <div className="absolute inset-0 bg-white/20 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-700 skew-x-12" />
                <Trophy className="w-4 h-4 text-yellow-300" />
                Master 4K Reconstruction
