              <button onClick={toggleLock} className={`p-1 rounded ${aspectRatioLocked ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-200 text-slate-500'}`}>
                {aspectRatioLocked ? <Link className="w-3 h-3" /> : <Link2Off className="w-3 h-3" />}
