              <button disabled={!image || isProcessing || !aiPrompt} onClick={handleAIEdit} className="mt-3 w-full bg-indigo-600 text-white p-2.5 rounded-xl text-xs font-bold flex items-center justify-center gap-2 disabled:opacity-30 hover:bg-indigo-700 transition-all">
                {isProcessing ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Sparkles className="w-3.5 h-3.5" />} 
                Transform Page
              </button>
