          </section>
        </aside>

        <section className="flex-1 flex flex-col p-8 relative overflow-hidden bg-slate-100/50">
          <div className="flex-1 relative">
            {isProcessing && (
              <div className="absolute inset-0 z-[100] flex items-center justify-center bg-white/60 backdrop-blur-md rounded-3xl">
                <div className="bg-white p-12 rounded-[2.5rem] shadow-2xl flex flex-col items-center gap-8 border border-slate-100 max-w-sm text-center">
                  <div className="relative">
                    <div className="w-24 h-24 border-[6px] border-slate-50 border-t-indigo-600 rounded-full animate-spin" />
                    <Sparkles className="w-10 h-10 text-indigo-500 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 animate-pulse" />
                  </div>
                  <div>
                    <h4 className="text-2xl font-black text-slate-800 mb-2">
                      {outputFormat === 'vector' ? 'Tracing Vector Map...' : 'Rendering Canvas...'}
