                <button onClick={() => (window as any).redo?.()} disabled={!canRedo} className={`p-3 rounded-2xl transition-all ${canRedo ? 'text-indigo-600 bg-indigo-50 hover:bg-indigo-100 shadow-sm' : 'text-slate-200'}`} title="Redo Strokes"><Redo className="w-5 h-5" /></button>
