};

export default App;

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { ToolType } from '../types';
import { ZoomIn, ZoomOut, Maximize, Hand, MoveDiagonal2, RotateCcw } from 'lucide-react';

interface EditorProps {
  backgroundImage: string | null;
  brushColor: string;
  brushSize: number;
  tool: ToolType;
  onHistoryChange?: (canUndo: boolean, canRedo: boolean) => void;
  onCropComplete?: (newLineArt: string) => void;
  canvasWidth?: number;
  canvasHeight?: number;
}

const MAX_HISTORY = 50;
const HANDLE_SIZE = 12;

function hexToRgb(hex: string) {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16),
    g: parseInt(result[2], 16),
    b: parseInt(result[3], 16)
  } : { r: 0, g: 0, b: 0 };
}

export const Editor: React.FC<EditorProps> = ({ 
  backgroundImage, 
  brushColor, 
  brushSize, 
  tool, 
  onHistoryChange, 
  onCropComplete,
  canvasWidth,
  canvasHeight
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null); 
  const drawingCanvasRef = useRef<HTMLCanvasElement>(null); 
  const containerRef = useRef<HTMLDivElement>(null);
  const [isDrawing, setIsDrawing] = useState(false);
  const [isPanning, setIsPanning] = useState(false);
  const rainbowHueRef = useRef(0);

  // View State (Enlargement/Navigation)
  const [scale, setScale] = useState(1);
  const [offset, setOffset] = useState({ x: 0, y: 0 });

  // Crop States
  const [cropRect, setCropRect] = useState({ x: 50, y: 50, w: 300, h: 300 });
  const [dragMode, setDragMode] = useState<'none' | 'move' | number>('none');
  const [startDragCoords, setStartDragCoords] = useState({ x: 0, y: 0 });
  const [initialOffset, setInitialOffset] = useState({ x: 0, y: 0 });
  const [initialCropRect, setInitialCropRect] = useState({ x: 50, y: 50, w: 300, h: 300 });

  const historyRef = useRef<ImageData[]>([]);
  const historyIndexRef = useRef<number>(-1);

  const updateHistoryStatus = useCallback(() => {
    if (onHistoryChange) {
      onHistoryChange(
        historyIndexRef.current > 0,
        historyIndexRef.current < historyRef.current.length - 1
      );
    }
  }, [onHistoryChange]);

  const saveState = useCallback(() => {
    const canvas = drawingCanvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (canvas && ctx) {
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      if (historyIndexRef.current < historyRef.current.length - 1) {
        historyRef.current = historyRef.current.slice(0, historyIndexRef.current + 1);
      }
      historyRef.current.push(imageData);
      if (historyRef.current.length > MAX_HISTORY) {
        historyRef.current.shift();
      } else {
        historyIndexRef.current++;
      }
      updateHistoryStatus();
    }
  }, [updateHistoryStatus]);

  const undo = useCallback(() => {
    if (historyIndexRef.current > 0) {
      historyIndexRef.current--;
      const canvas = drawingCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (canvas && ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.putImageData(historyRef.current[historyIndexRef.current], 0, 0);
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  const redo = useCallback(() => {
    if (historyIndexRef.current < historyRef.current.length - 1) {
      historyIndexRef.current++;
      const canvas = drawingCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (canvas && ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.putImageData(historyRef.current[historyIndexRef.current], 0, 0);
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  const clearDrawing = useCallback(() => {
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.clearRect(0, 0, drawingCanvasRef.current!.width, drawingCanvasRef.current!.height);
      saveState();
    }
  }, [saveState]);

  useEffect(() => {
    if (drawingCanvasRef.current && historyRef.current.length === 0) {
      const ctx = drawingCanvasRef.current.getContext('2d');
      if (ctx) {
        const empty = ctx.getImageData(0, 0, drawingCanvasRef.current.width, drawingCanvasRef.current.height);
        historyRef.current = [empty];
        historyIndexRef.current = 0;
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  const resize = useCallback(() => {
    const parent = containerRef.current;
    if (!parent || !canvasRef.current || !drawingCanvasRef.current) return;

    const containerW = parent.clientWidth;
    const containerH = parent.clientHeight;

    const targetW = canvasWidth || containerW;
    const targetH = canvasHeight || containerH;

    const temp = document.createElement('canvas');
    temp.width = drawingCanvasRef.current.width;
    temp.height = drawingCanvasRef.current.height;
    temp.getContext('2d')?.drawImage(drawingCanvasRef.current, 0, 0);

    canvasRef.current.width = targetW;
    canvasRef.current.height = targetH;
    drawingCanvasRef.current.width = targetW;
    drawingCanvasRef.current.height = targetH;

    const ctx = drawingCanvasRef.current.getContext('2d');
    if (ctx) {
      ctx.drawImage(temp, 0, 0, temp.width, temp.height, 0, 0, targetW, targetH);
    }

    if (backgroundImage) {
      const bgCtx = canvasRef.current.getContext('2d');
      if (bgCtx) {
        const img = new Image();
        img.onload = () => {
          bgCtx.clearRect(0, 0, targetW, targetH);
          const scaleFactor = Math.min(targetW / img.width, targetH / img.height);
          const x = (targetW / 2) - (img.width / 2) * scaleFactor;
          const y = (targetH / 2) - (img.height / 2) * scaleFactor;
          bgCtx.drawImage(img, x, y, img.width * scaleFactor, img.height * scaleFactor);
        };
        img.src = backgroundImage;
      }
    }

    setCropRect({ x: targetW * 0.1, y: targetH * 0.1, w: targetW * 0.8, h: targetH * 0.8 });

    const scaleToFit = Math.min(containerW / targetW, containerH / targetH) * 0.9;
    setScale(scaleToFit);
    setOffset({
      x: (containerW - targetW * scaleToFit) / 2,
      y: (containerH - targetH * scaleToFit) / 2
    });
  }, [backgroundImage, canvasWidth, canvasHeight]);

  useEffect(() => {
    window.addEventListener('resize', resize);
    resize();
    return () => window.removeEventListener('resize', resize);
  }, [resize]);

  const getCoords = (e: React.MouseEvent | React.TouchEvent) => {
    const canvas = drawingCanvasRef.current;
    if (!canvas) return { x: 0, y: 0 };
    const rect = containerRef.current?.getBoundingClientRect();
    if (!rect) return { x: 0, y: 0 };

    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    const x = (clientX - rect.left - offset.x) / scale;
    const y = (clientY - rect.top - offset.y) / scale;

    return { x, y };
  };

  const applyCrop = useCallback(() => {
    if (!canvasRef.current || !drawingCanvasRef.current) return;
    const { x, y, w, h } = cropRect;
    if (w <= 5 || h <= 5) return;

    const lineArtCrop = document.createElement('canvas');
    lineArtCrop.width = w;
    lineArtCrop.height = h;
    lineArtCrop.getContext('2d')?.drawImage(canvasRef.current, x, y, w, h, 0, 0, w, h);
    const newLineArt = lineArtCrop.toDataURL('image/png');

    const drawingCrop = document.createElement('canvas');
    drawingCrop.width = w;
    drawingCrop.height = h;
    drawingCrop.getContext('2d')?.drawImage(drawingCanvasRef.current, x, y, w, h, 0, 0, w, h);

    if (onCropComplete) {
      onCropComplete(newLineArt);
      const dCtx = drawingCanvasRef.current.getContext('2d');
      if (dCtx) {
        dCtx.clearRect(0, 0, drawingCanvasRef.current.width, drawingCanvasRef.current.height);
        dCtx.drawImage(drawingCrop, 0, 0, w, h, 0, 0, drawingCanvasRef.current.width, drawingCanvasRef.current.height);
        saveState();
      }
    }
  }, [cropRect, onCropComplete, saveState]);

  const handleBucketFill = (startX: number, startY: number) => {
    const canvas = drawingCanvasRef.current;
    const bgCanvas = canvasRef.current;
    if (!canvas || !bgCanvas) return;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    const { width, height } = canvas;
    const tempCanvas = document.createElement('canvas');
    tempCanvas.width = width;
    tempCanvas.height = height;
    const tCtx = tempCanvas.getContext('2d', { willReadFrequently: true })!;
    tCtx.fillStyle = '#ffffff';
    tCtx.fillRect(0, 0, width, height);
    tCtx.drawImage(bgCanvas, 0, 0);
    tCtx.drawImage(canvas, 0, 0);

    const imgData = tCtx.getImageData(0, 0, width, height);
    const pixels = imgData.data;
    const x = Math.round(startX);
    const y = Math.round(startY);
    const pos = (y * width + x) * 4;
    const [tR, tG, tB] = [pixels[pos], pixels[pos+1], pixels[pos+2]];
    const fill = hexToRgb(brushColor);

    if (Math.abs(tR - fill.r) < 10 && Math.abs(tG - fill.g) < 10 && Math.abs(tB - fill.b) < 10) return;

    const stack = [[x, y]];
    const seen = new Uint8Array(width * height);
    const fillPixels = new Uint8Array(width * height);
    const threshold = 60;

    while (stack.length) {
      const [cx, cy] = stack.pop()!;
      if (cx < 0 || cx >= width || cy < 0 || cy >= height) continue;
      const idx = cy * width + cx;
      if (seen[idx]) continue;
      seen[idx] = 1;

      const p = idx * 4;
      if (Math.abs(pixels[p] - tR) < threshold && Math.abs(pixels[p+1] - tG) < threshold && Math.abs(pixels[p+2] - tB) < threshold) {
        fillPixels[idx] = 1;
        stack.push([cx + 1, cy], [cx - 1, cy], [cx, cy + 1], [cx, cy - 1]);
      }
    }

    const res = ctx.createImageData(width, height);
    for (let i = 0; i < width * height; i++) {
      if (fillPixels[i]) {
        const p = i * 4;
        res.data[p] = fill.r;
        res.data[p+1] = fill.g;
        res.data[p+2] = fill.b;
        res.data[p+3] = 255;
      }
    }
    const scratch = document.createElement('canvas');
    scratch.width = width;
    scratch.height = height;
    scratch.getContext('2d')?.putImageData(res, 0, 0);
    ctx.globalCompositeOperation = 'source-over';
    ctx.drawImage(scratch, 0, 0);
    saveState();
  };

  const getHandleAt = (px: number, py: number) => {
    const { x, y, w, h } = cropRect;
    const handles = [
      { x: x, y: y }, { x: x + w, y: y }, { x: x + w, y: y + h }, { x: x, y: y + h },
      { x: x + w / 2, y: y }, { x: x + w, y: y + h / 2 }, { x: x + w / 2, y: y + h }, { x: x, y: y + h / 2 }
    ];
    for (let i = 0; i < handles.length; i++) {
      if (Math.abs(px - handles[i].x) < HANDLE_SIZE && Math.abs(py - handles[i].y) < HANDLE_SIZE) return i;
    }
    return -1;
  };

  const start = (e: React.MouseEvent | React.TouchEvent) => {
    const coords = getCoords(e);
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    if (tool === ToolType.PAN) {
      setIsPanning(true);
      setStartDragCoords({ x: clientX, y: clientY });
      setInitialOffset({ ...offset });
      return;
    }

    if (tool === ToolType.CROP) {
      const handleIdx = getHandleAt(coords.x, coords.y);
      if (handleIdx !== -1) setDragMode(handleIdx);
      else if (coords.x >= cropRect.x && coords.x <= cropRect.x + cropRect.w && coords.y >= cropRect.y && coords.y <= cropRect.y + cropRect.h) setDragMode('move');
      else return;
      setStartDragCoords({ x: coords.x, y: coords.y });
      setInitialCropRect({ ...cropRect });
      return;
    }

    if (tool === ToolType.BUCKET) return handleBucketFill(coords.x, coords.y);

    setIsDrawing(true);
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.beginPath();
      ctx.moveTo(coords.x, coords.y);
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.globalCompositeOperation = tool === ToolType.ERASER ? 'destination-out' : 'source-over';
      ctx.globalAlpha = tool === ToolType.HIGHLIGHTER ? 0.35 : 1.0;
      ctx.lineWidth = brushSize;
      if (tool === ToolType.CALLIGRAPHY) ctx.lineCap = 'butt';
    }
  };

  const draw = (e: React.MouseEvent | React.TouchEvent) => {
    const coords = getCoords(e);
    const clientX = 'touches' in e ? (e as React.TouchEvent).touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? (e as React.TouchEvent).touches[0].clientY : (e as React.MouseEvent).clientY;

    if (tool === ToolType.PAN && isPanning) {
      const dx = clientX - startDragCoords.x;
      const dy = clientY - startDragCoords.y;
      setOffset({ 
        x: initialOffset.x + dx, 
        y: initialOffset.y + dy 
      });
      return;
    }

    if (tool === ToolType.CROP && dragMode !== 'none') {
      const dx = coords.x - startDragCoords.x;
      const dy = coords.y - startDragCoords.y;
      const newRect = { ...initialCropRect };
      if (dragMode === 'move') { newRect.x += dx; newRect.y += dy; }
      else {
        switch (dragMode) {
          case 0: newRect.x += dx; newRect.y += dy; newRect.w -= dx; newRect.h -= dy; break;
          case 1: newRect.y += dy; newRect.w += dx; newRect.h -= dy; break;
          case 2: newRect.w += dx; newRect.h += dy; break;
          case 3: newRect.x += dx; newRect.w -= dx; newRect.h += dy; break;
          case 4: newRect.y += dy; newRect.h -= dy; break;
          case 5: newRect.w += dx; break;
          case 6: newRect.h += dy; break;
          case 7: newRect.x += dx; newRect.w -= dx; break;
        }
      }
      if (newRect.w < 10) newRect.w = 10;
      if (newRect.h < 10) newRect.h = 10;
      setCropRect(newRect);
      return;
    }

    if (!isDrawing || tool === ToolType.BUCKET) return;
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (!ctx) return;

    if (tool === ToolType.SPRAY) {
      ctx.fillStyle = brushColor;
      const density = 20 + brushSize / 2;
      for (let i = 0; i < density; i++) {
        const angle = Math.random() * Math.PI * 2;
        const dist = Math.random() * brushSize;
        const px = coords.x + Math.cos(angle) * dist;
        const py = coords.y + Math.sin(angle) * dist;
        ctx.fillRect(px, py, 1.2, 1.2);
      }
    } else if (tool === ToolType.RAINBOW) {
      rainbowHueRef.current = (rainbowHueRef.current + 3) % 360;
      ctx.strokeStyle = `hsl(${rainbowHueRef.current}, 100%, 50%)`;
      ctx.lineTo(coords.x, coords.y);
      ctx.stroke();
    } else if (tool === ToolType.CALLIGRAPHY) {
      ctx.strokeStyle = brushColor;
      const thickness = brushSize;
      const angle = Math.PI / 4;
      ctx.lineWidth = 1;
      for (let i = -thickness/2; i < thickness/2; i++) {
        ctx.lineTo(coords.x + i * Math.cos(angle), coords.y + i * Math.sin(angle));
      }
      ctx.stroke();
    } else {
      ctx.strokeStyle = tool === ToolType.ERASER ? 'rgba(255,255,255,1)' : brushColor;
      ctx.lineTo(coords.x, coords.y);
      ctx.stroke();
    }
  };

  const stop = () => { 
    if (isDrawing) { setIsDrawing(false); saveState(); }
    setIsPanning(false);
    setDragMode('none');
  };

  // Helper to handle zooming at a specific point
  const applyZoom = useCallback((zoomFactor: number, focusX: number, focusY: number) => {
    const newScale = Math.min(10, Math.max(0.05, scale * zoomFactor));
    const actualFactor = newScale / scale;

    setOffset(prev => ({
      x: focusX - (focusX - prev.x) * actualFactor,
      y: focusY - (focusY - prev.y) * actualFactor
    }));
    setScale(newScale);
  }, [scale]);

  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    const zoomIntensity = 0.001; // Slower, smoother wheel zoom
    const wheel = -e.deltaY;
    const zoomFactor = Math.exp(wheel * zoomIntensity);

    const container = containerRef.current;
    if (!container) return;
    const rect = container.getBoundingClientRect();

    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;

    applyZoom(zoomFactor, mouseX, mouseY);
  };

  const handleZoomDiscrete = (type: 'in' | 'out') => {
    const container = containerRef.current;
    if (!container) return;
    const rect = container.getBoundingClientRect();

    // Zoom center point is the middle of the container
    const centerX = rect.width / 2;
    const centerY = rect.height / 2;

    const factor = type === 'in' ? 1.1 : 0.9; // 10% steps
    applyZoom(factor, centerX, centerY);
  };

  const resetView = () => resize();

  const getCombined = () => {
    if (!canvasRef.current || !drawingCanvasRef.current) return '';
    const final = document.createElement('canvas');
    final.width = canvasRef.current.width;
    final.height = canvasRef.current.height;
    const ctx = final.getContext('2d')!;
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, final.width, final.height);
    ctx.drawImage(drawingCanvasRef.current, 0, 0);
    ctx.globalCompositeOperation = 'multiply';
    ctx.drawImage(canvasRef.current, 0, 0);
    return final.toDataURL('image/png');
  };

  useEffect(() => {
    (window as any).clearCanvas = clearDrawing;
    (window as any).getCombinedImage = getCombined;
    (window as any).undo = undo;
    (window as any).redo = redo;
    (window as any).applyCrop = applyCrop;
  }, [clearDrawing, undo, redo, applyCrop, backgroundImage, brushColor, brushSize, tool]);

  return (
    <div 
      ref={containerRef}
      className="relative w-full h-full bg-slate-200 rounded-3xl shadow-inner overflow-hidden border-4 border-white group"
      onWheel={handleWheel}
    >
      <div className="absolute inset-0 bg-[radial-gradient(#CBD5E1_1px,transparent_1px)] [background-size:20px_20px] opacity-30" />

      <div 
        className="absolute origin-top-left"
        style={{ 
          transform: `translate(${offset.x}px, ${offset.y}px) scale(${scale})`,
          width: canvasWidth,
          height: canvasHeight
        }}
      >
        <div className="absolute inset-0 shadow-2xl bg-white ring-1 ring-slate-300" />
        <canvas
          ref={drawingCanvasRef}
          onMouseDown={start}
          onMouseMove={draw}
          onMouseUp={stop}
          onMouseLeave={stop}
          onTouchStart={start}
          onTouchMove={draw}
          onTouchEnd={stop}
          className={`absolute inset-0 touch-none ${tool === ToolType.PAN ? (isPanning ? 'cursor-grabbing' : 'cursor-grab') : (tool === ToolType.CROP ? 'cursor-default' : 'cursor-crosshair')}`}
        />
        <canvas ref={canvasRef} className="absolute inset-0 pointer-events-none mix-blend-multiply" />
      </div>

      <div className="absolute top-6 left-6 flex flex-col gap-2 pointer-events-none">
         <div className="px-4 py-2 bg-black/80 backdrop-blur-md text-white text-[10px] font-black rounded-full shadow-lg border border-white/10 uppercase tracking-widest flex items-center gap-2">
            <MoveDiagonal2 className="w-3 h-3" />
            {canvasWidth} x {canvasHeight} | {Math.round(scale * 100)}%
         </div>
      </div>

      <div className="absolute bottom-6 right-6 flex flex-col gap-2 p-1.5 bg-white/90 backdrop-blur-xl rounded-[2rem] border border-slate-200 shadow-2xl opacity-0 group-hover:opacity-100 transition-all scale-90 group-hover:scale-100">
        <button onClick={() => handleZoomDiscrete('in')} className="p-4 hover:bg-white text-slate-600 rounded-full transition-all hover:shadow-sm" title="Zoom In (+10%)"><ZoomIn className="w-5 h-5" /></button>
        <div className="h-[1px] bg-slate-100 mx-3" />
        <button onClick={() => handleZoomDiscrete('out')} className="p-4 hover:bg-white text-slate-600 rounded-full transition-all hover:shadow-sm" title="Zoom Out (-10%)"><ZoomOut className="w-5 h-5" /></button>
        <div className="h-[1px] bg-slate-100 mx-3" />
        <button onClick={resetView} className="p-4 hover:bg-indigo-600 hover:text-white text-indigo-600 rounded-full transition-all hover:shadow-md" title="Reset Zoom / Fit to Screen"><RotateCcw className="w-5 h-5" /></button>
      </div>

      {tool === ToolType.CROP && (
        <div className="absolute inset-0 pointer-events-none">
          <div className="absolute border-2 border-white shadow-[0_0_0_1px_rgba(0,0,0,0.5)] pointer-events-auto" style={{ left: cropRect.x, top: cropRect.y, width: cropRect.w, height: cropRect.h }}>
          </div>
        </div>
      )}

      {tool === ToolType.PAN && !isPanning && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none bg-black/50 backdrop-blur-sm text-white px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3">
          <Hand className="w-4 h-4 animate-bounce" /> Drag to explore canvas
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Save, Trash2, Plus, Bookmark, PenTool, Highlighter, Wind, Sparkles, PaintBucket, Eraser, Hand, Crop } from 'lucide-react';
import { ToolType } from '../types';

interface StylePreset {
  id: string;
  name: string;
  color: string;
  size: number;
  tool: ToolType;
}

interface StylePresetsProps {
  currentColor: string;
  currentSize: number;
  currentTool: ToolType;
  onApplyPreset: (color: string, size: number, tool: ToolType) => void;
}

const TOOL_ICONS: Record<ToolType, any> = {
  [ToolType.BRUSH]: PenTool,
  [ToolType.HIGHLIGHTER]: Highlighter,
  [ToolType.SPRAY]: Wind,
  [ToolType.CALLIGRAPHY]: PenTool,
  [ToolType.RAINBOW]: Sparkles,
  [ToolType.BUCKET]: PaintBucket,
  [ToolType.ERASER]: Eraser,
  [ToolType.PAN]: Hand,
  [ToolType.CROP]: Crop,
};

export const StylePresets: React.FC<StylePresetsProps> = ({
  currentColor,
  currentSize,
  currentTool,
  onApplyPreset,
}) => {
  const [presets, setPresets] = useState<StylePreset[]>([]);
  const [newPresetName, setNewPresetName] = useState('');
  const [isAdding, setIsAdding] = useState(false);

  // Load presets from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('chromasketch_presets');
    if (saved) {
      try {
        setPresets(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load presets", e);
      }
    }
  }, []);

  // Save presets to localStorage
  useEffect(() => {
    localStorage.setItem('chromasketch_presets', JSON.stringify(presets));
  }, [presets]);

  const handleSavePreset = () => {
    if (!newPresetName.trim()) return;

    const newPreset: StylePreset = {
      id: Date.now().toString(),
      name: newPresetName.trim(),
      color: currentColor,
      size: currentSize,
      tool: currentTool,
    };

    setPresets([newPreset, ...presets]);
    setNewPresetName('');
    setIsAdding(false);
  };

  const handleDeletePreset = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setPresets(presets.filter(p => p.id !== id));
  };

  return (
    <div className="flex flex-col gap-4">
      <div className="flex items-center justify-between">
        <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Style Library</h3>
        <button 
          onClick={() => setIsAdding(!isAdding)}
          className={`p-1.5 rounded-lg transition-all ${isAdding ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'}`}
        >
          {isAdding ? <Bookmark className="w-3 h-3" /> : <Plus className="w-3.5 h-3.5" />}
        </button>
      </div>

      {isAdding && (
        <div className="bg-slate-50 p-3 rounded-xl border border-slate-200 animate-in fade-in slide-in-from-top-2">
          <input
            type="text"
            placeholder="Preset name..."
            value={newPresetName}
            onChange={(e) => setNewPresetName(e.target.value)}
            className="w-full text-xs p-2 rounded-lg bg-white border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 mb-2"
            autoFocus
            onKeyDown={(e) => e.key === 'Enter' && handleSavePreset()}
          />
          <div className="flex gap-2">
            <button 
              onClick={handleSavePreset}
              className="flex-1 bg-indigo-600 text-white py-1.5 rounded-lg text-[10px] font-black uppercase tracking-wider flex items-center justify-center gap-1.5"
            >
              <Save className="w-3 h-3" /> Save Current
            </button>
            <button 
              onClick={() => setIsAdding(false)}
              className="px-3 py-1.5 bg-slate-200 text-slate-600 rounded-lg text-[10px] font-black uppercase tracking-wider"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 gap-2 max-h-[160px] overflow-y-auto pr-1 custom-scrollbar">
        {presets.length === 0 && !isAdding && (
          <div className="text-[10px] text-slate-400 italic text-center py-4 bg-slate-50/50 rounded-xl border border-dashed border-slate-200">
            No saved styles yet
          </div>
        )}
        {presets.map((preset) => {
          const ToolIcon = TOOL_ICONS[preset.tool] || PenTool;
          return (
            <button
              key={preset.id}
              onClick={() => onApplyPreset(preset.color, preset.size, preset.tool)}
              className="group flex items-center gap-3 p-2 bg-white border border-slate-100 rounded-xl hover:border-indigo-300 hover:shadow-sm transition-all text-left"
            >
              <div className="relative">
                <div 
                  className="w-8 h-8 rounded-lg shadow-inner border border-slate-100"
                  style={{ backgroundColor: preset.color }}
                />
                <div className="absolute -bottom-1 -right-1 bg-white p-0.5 rounded shadow-sm border border-slate-100">
                  <ToolIcon className="w-2.5 h-2.5 text-slate-600" />
                </div>
              </div>
              <div className="flex-1 min-w-0">
                <div className="text-[10px] font-black text-slate-700 uppercase truncate">{preset.name}</div>
                <div className="text-[9px] text-slate-400 font-bold">{preset.size}px • {preset.tool.toLowerCase()}</div>
              </div>
              <button 
                onClick={(e) => handleDeletePreset(preset.id, e)}
                className="opacity-0 group-hover:opacity-100 p-1.5 text-slate-300 hover:text-red-500 transition-all"
              >
                <Trash2 className="w-3 h-3" />
              </button>
            </button>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { 
  Plus, 
  Upload, 
  Printer, 
  RotateCcw, 
  Eraser, 
  Paintbrush, 
  Sparkles, 
  Download,
  Camera,
  Loader2,
  Trash2,
  Wand2,
  Image as ImageIcon,
  Undo,
  Redo,
  PaintBucket,
  Crop,
  Check,
  ChevronRight,
  ShieldCheck,
  Settings2,
  Maximize2,
  Type,
  PenTool,
  Wind,
  Highlighter,
  Hand,
  Trophy,
  Shapes,
  Image as RasterIcon,
  Link,
  Link2Off,
  MoveDiagonal2
} from 'lucide-react';
import { ColorPicker } from './components/ColorPicker';
import { Editor } from './components/Editor';
import { CameraModal } from './components/CameraModal';
import { StylePresets } from './components/StylePresets';
import { convertToLineArt, editWithAI, upscaleToStudioMaster, ColoringStyle, ImageResolution, OutputFormat } from './services/geminiService';
import { ToolType } from './types';

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [brushColor, setBrushColor] = useState('#FF0000');
  const [brushSize, setBrushSize] = useState(10);
  const [activeTool, setActiveTool] = useState<ToolType>(ToolType.BRUSH);
  const [aiPrompt, setAiPrompt] = useState('');
  const [showCamera, setShowCamera] = useState(false);
  const [canUndo, setCanUndo] = useState(false);
  const [canRedo, setCanRedo] = useState(false);

  const [isProMode, setIsProMode] = useState(false);
  const [resolution, setResolution] = useState<ImageResolution>('1K');
  const [outputFormat, setOutputFormat] = useState<OutputFormat>('raster');

  // Canvas Dimension State
  const [canvasWidth, setCanvasWidth] = useState<number>(1024);
  const [canvasHeight, setCanvasHeight] = useState<number>(1024);
  const [aspectRatioLocked, setAspectRatioLocked] = useState(true);
  const [ratio, setRatio] = useState(1);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    setRatio(canvasWidth / canvasHeight);
  }, []);

  const handleWidthChange = (val: number) => {
    setCanvasWidth(val);
    if (aspectRatioLocked) {
      setCanvasHeight(Math.round(val / ratio));
    }
  };

  const handleHeightChange = (val: number) => {
    setCanvasHeight(val);
    if (aspectRatioLocked) {
      setCanvasWidth(Math.round(val * ratio));
    }
  };

  const toggleLock = () => {
    if (!aspectRatioLocked) {
      setRatio(canvasWidth / canvasHeight);
    }
    setAspectRatioLocked(!aspectRatioLocked);
  };

  const checkProPermissions = async () => {
    try {
      // Cast window to any to access aistudio which is injected by the environment
      const hasKey = await (window as any).aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await (window as any).aistudio.openSelectKey();
      }
      return true;
    } catch (e) {
      console.error("Key selection failed", e);
      return false;
    }
  };

  const toggleProMode = async () => {
    if (!isProMode) {
      const success = await checkProPermissions();
      if (success) setIsProMode(true);
    } else {
      setIsProMode(false);
      setResolution('1K');
      setOutputFormat('raster');
    }
  };

  const handleFormatChange = async (fmt: OutputFormat) => {
    if (fmt === 'vector' && !isProMode) {
      const success = await checkProPermissions();
      if (success) {
        setIsProMode(true);
        setOutputFormat(fmt);
      }
    } else {
      setOutputFormat(fmt);
    }
  };

  const handleResolutionChange = async (res: ImageResolution) => {
    if (res !== '1K' && !isProMode) {
      const success = await checkProPermissions();
      if (success) {
        setIsProMode(true);
        setResolution(res);
      }
    } else {
      setResolution(res);
    }
  };

  const processImage = async (base64: string, style: ColoringStyle = 'standard') => {
    // Extra validation for high resolutions
    if ((resolution === '2K' || resolution === '4K') && !isProMode) {
       const success = await checkProPermissions();
       if (!success) return;
       setIsProMode(true);
    }

    setIsProcessing(true);
    try {
      const lineArt = await convertToLineArt(base64, style, resolution, outputFormat, isProMode);
      setImage(lineArt);
    } catch (error: any) {
      console.error("Processing failed", error);
      alert("Processing error. Ensure the image is clear and you have pro access if Vector/2K/4K is selected.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleMasterUpscale = async () => {
    const data = (window as any).getCombinedImage?.();
    if (!data) return;

    setIsProcessing(true);
    try {
      const mastered = await upscaleToStudioMaster(data);
      setImage(mastered);
      setResolution('4K');
      setIsProMode(true);
      setOutputFormat('raster');
    } catch (error) {
      console.error("Master upscale failed", error);
      alert("Upscaling failed. Ensure you have a valid Studio Pro session.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result as string;
      await processImage(base64);
    };
    reader.readAsDataURL(file);
  };

  const handleAIEdit = async () => {
    if (!image || !aiPrompt) return;
    setIsProcessing(true);
    try {
      const edited = await editWithAI(image, aiPrompt, isProMode);
      setImage(edited);
      setAiPrompt('');
    } catch (error) {
      alert("AI was unable to process that request.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handlePrint = () => {
    const combined = (window as any).getCombinedImage?.();
    if (!combined) return;
    const printWindow = window.open('', '_blank');
    if (printWindow) {
      printWindow.document.write(`<html><body style="margin:0;display:flex;justify-content:center;align-items:center;height:100vh;"><img src="${combined}" style="max-width:100%;max-height:100%;object-fit:contain;" /><script>window.onload=()=>window.print();</script></body></html>`);
      printWindow.document.close();
    }
  };

  const handleDownload = (onlyLineArt = false) => {
    const data = onlyLineArt ? (window as any).getLineArtOnly?.() : (window as any).getCombinedImage?.();
    if (!data) return;
    const extension = data.includes('svg+xml') ? 'svg' : 'png';
    const linkObj = document.createElement('a');
    linkObj.href = data;
    linkObj.download = `chromasketch-${outputFormat}-${resolution}-${Date.now()}.${extension}`;
    linkObj.click();
  };

  const handleCropComplete = (newImageData: string) => {
    setImage(newImageData);
    setActiveTool(ToolType.BRUSH);
  };

  const applyStylePreset = (color: string, size: number, tool: ToolType) => {
    setBrushColor(color);
    setBrushSize(size);
    setActiveTool(tool);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-900 overflow-hidden font-sans">
      {showCamera && (
        <CameraModal 
          onCapture={(base64, style) => { setShowCamera(false); processImage(base64, style); }} 
          onClose={() => setShowCamera(false)} 
        />
      )}

      <header className="bg-white border-b border-slate-200 px-6 py-4 flex justify-between items-center shrink-0 shadow-sm z-20">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2.5 rounded-2xl shadow-lg shadow-indigo-100">
              <Sparkles className="text-white w-6 h-6" />
            </div>
            <div>
              <h1 className="text-xl font-extrabold tracking-tight text-slate-800">ChromaSketch AI</h1>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Digital Arts Studio</p>
            </div>
          </div>

          <div className="hidden lg:flex items-center gap-2 bg-slate-50 p-1.5 rounded-2xl border border-slate-200">
            <button 
              onClick={toggleProMode}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl transition-all font-black text-xs uppercase tracking-wider ${isProMode ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-white'}`}
            >
              <ShieldCheck className={`w-4 h-4 ${isProMode ? 'animate-pulse' : ''}`} />
              Studio Pro
            </button>

            <div className="w-[1px] h-4 bg-slate-200 mx-1" />

            <div className="flex bg-slate-100 p-0.5 rounded-xl">
              <button
                onClick={() => handleFormatChange('raster')}
                className={`px-3 py-1.5 rounded-lg flex items-center gap-2 text-[10px] font-black transition-all ${outputFormat === 'raster' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}
              >
                <RasterIcon className="w-3 h-3" /> PNG
              </button>
              <button
                onClick={() => handleFormatChange('vector')}
                className={`px-3 py-1.5 rounded-lg flex items-center gap-2 text-[10px] font-black transition-all ${outputFormat === 'vector' ? 'bg-indigo-600 text-white shadow-sm' : 'text-slate-400'}`}
              >
                <Shapes className="w-3 h-3" /> SVG
              </button>
            </div>

            {outputFormat === 'raster' && (
              <>
                <div className="w-[1px] h-4 bg-slate-200 mx-1" />
                {(['1K', '2K', '4K'] as ImageResolution[]).map(res => (
                  <button
                    key={res}
                    onClick={() => handleResolutionChange(res)}
                    className={`px-3 py-2 rounded-xl text-[10px] font-black transition-all ${resolution === res ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    {res}
                  </button>
                ))}
              </>
            )}
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button onClick={() => setShowCamera(true)} className="flex items-center gap-2 px-4 py-2 hover:bg-slate-50 text-slate-600 rounded-lg transition-all font-semibold"><Camera className="w-4 h-4" /> Camera</button>
          <button onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 px-4 py-2 bg-white text-indigo-600 rounded-lg shadow-sm hover:shadow-md transition-all font-bold border border-indigo-50"><Upload className="w-4 h-4" /> Upload</button>
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <aside className="w-80 bg-white border-r border-slate-200 p-6 flex flex-col gap-6 shrink-0 overflow-y-auto shadow-sm z-10 custom-scrollbar">
          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 text-center border-b pb-2 border-slate-50">Studio Palette</h3>
            <ColorPicker currentColor={brushColor} onChange={setBrushColor} />
          </section>

          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Line Weight</h3>
            <div className="flex items-center gap-3">
              <input type="range" min="1" max="50" value={brushSize} onChange={(e) => setBrushSize(parseInt(e.target.value))} className="flex-1 h-1.5 bg-slate-100 rounded-lg appearance-none cursor-pointer accent-indigo-600" />
              <span className="text-[10px] font-bold text-indigo-600 w-8 text-right">{brushSize}px</span>
            </div>
          </section>

          <section className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 flex justify-between items-center">
              Canvas Dimensions
              <button onClick={toggleLock} className={`p-1 rounded ${aspectRatioLocked ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-200 text-slate-500'}`}>
                {aspectRatioLocked ? <Link className="w-3 h-3" /> : <Link2Off className="w-3 h-3" />}
              </button>
            </h3>
            <div className="flex flex-col gap-3">
              <div className="flex items-center gap-2">
                <span className="text-[10px] font-bold text-slate-400 w-4">W</span>
                <input 
                  type="number" 
                  value={canvasWidth} 
                  onChange={(e) => handleWidthChange(parseInt(e.target.value) || 0)}
                  className="flex-1 bg-white border border-slate-200 rounded-lg px-3 py-1.5 text-xs font-mono"
                />
              </div>
              <div className="flex items-center gap-2">
                <span className="text-[10px] font-bold text-slate-400 w-4">H</span>
                <input 
                  type="number" 
                  value={canvasHeight} 
                  onChange={(e) => handleHeightChange(parseInt(e.target.value) || 0)}
                  className="flex-1 bg-white border border-slate-200 rounded-lg px-3 py-1.5 text-xs font-mono"
                />
              </div>
            </div>
          </section>

          <section>
            <StylePresets 
              currentColor={brushColor}
              currentSize={brushSize}
              currentTool={activeTool}
              onApplyPreset={applyStylePreset}
            />
          </section>

          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Precision Tools</h3>
            <div className="grid grid-cols-2 gap-2">
              {[
                { id: ToolType.BRUSH, icon: Paintbrush, label: 'Brush' },
                { id: ToolType.PAN, icon: Hand, label: 'Pan/View' },
