            {isProcessing && (
              <div className="absolute inset-0 z-[100] flex items-center justify-center bg-white/60 backdrop-blur-md rounded-3xl">
                <div className="bg-white p-12 rounded-[2.5rem] shadow-2xl flex flex-col items-center gap-8 border border-slate-100 max-w-sm text-center">
                  <div className="relative">
                    <div className="w-24 h-24 border-[6px] border-slate-50 border-t-indigo-600 rounded-full animate-spin" />
                    <Sparkles className="w-10 h-10 text-indigo-500 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 animate-pulse" />
                  </div>
                  <div>
                    <h4 className="text-2xl font-black text-slate-800 mb-2">
                      {outputFormat === 'vector' ? 'Tracing Vector Map...' : 'Rendering Canvas...'}
                    </h4>
                    <p className="text-slate-400 font-medium">Gemini 3 Pro is {outputFormat === 'vector' ? 'generating mathematical paths' : 'refining your artwork'} for {resolution} output.</p>
                  </div>
                </div>
              </div>
            )}

            {!image ? (
              <div className="h-full border-4 border-dashed border-slate-200 rounded-[2.5rem] flex flex-col items-center justify-center bg-white gap-8 text-center px-16 group transition-all hover:border-indigo-100 hover:bg-slate-50/50">
                <div className="w-32 h-32 bg-indigo-50 text-indigo-600 rounded-[2.5rem] flex items-center justify-center transform group-hover:rotate-6 transition-transform shadow-xl">
                  <ImageIcon className="w-16 h-16" />
                </div>
                <div>
                  <h2 className="text-4xl font-black text-slate-800 mb-4 tracking-tight">Pro Illustration Studio</h2>
                  <p className="text-slate-400 max-w-md font-medium leading-relaxed">Infinitely scalable vector art from your photos. Perfect for professional coloring books and large-scale printing.</p>
                </div>
                <div className="flex gap-4">
                  <button onClick={() => setShowCamera(true)} className="bg-indigo-600 text-white px-10 py-4 rounded-2xl font-black text-lg hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 flex items-center gap-3 transform hover:-translate-y-1 active:scale-95"><Camera className="w-6 h-6" /> Camera</button>
                  <button onClick={() => fileInputRef.current?.click()} className="bg-white text-indigo-600 border-2 border-indigo-600 px-10 py-4 rounded-2xl font-black text-lg hover:bg-indigo-50 transition-all flex items-center gap-3 transform hover:-translate-y-1 active:scale-95"><Upload className="w-6 h-6" /> Upload</button>
                </div>
              </div>
            ) : (
              <Editor 
                backgroundImage={image} 
                brushColor={brushColor} 
                brushSize={brushSize} 
                tool={activeTool}
                onHistoryChange={(u, r) => { setCanUndo(u); setCanRedo(r); }}
                onCropComplete={handleCropComplete}
                canvasWidth={canvasWidth}
                canvasHeight={canvasHeight}
              />
            )}
          </div>

          {image && (
            <div className="mt-8 flex justify-between items-center bg-white p-4 rounded-3xl border border-slate-200 shadow-xl z-20">
              <div className="flex gap-2">
                <button onClick={() => (window as any).undo?.()} disabled={!canUndo} className={`p-3 rounded-2xl transition-all ${canUndo ? 'text-indigo-600 bg-indigo-50 hover:bg-indigo-100 shadow-sm' : 'text-slate-200'}`} title="Undo Strokes"><Undo className="w-5 h-5" /></button>
                <button onClick={() => (window as any).redo?.()} disabled={!canRedo} className={`p-3 rounded-2xl transition-all ${canRedo ? 'text-indigo-600 bg-indigo-50 hover:bg-indigo-100 shadow-sm' : 'text-slate-200'}`} title="Redo Strokes"><Redo className="w-5 h-5" /></button>
                <div className="w-[1px] h-8 bg-slate-100 mx-1 self-center" />
                <button onClick={() => (window as any).clearCanvas?.()} className="p-3 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-2xl transition-all flex items-center gap-2" title="Reset Colors"><RotateCcw className="w-4 h-4" /><span className="text-[10px] font-black uppercase">Clear</span></button>
              </div>
              <div className="flex gap-4">
                <button onClick={() => handleDownload(false)} className="px-8 py-3 bg-slate-50 text-slate-600 border border-slate-200 rounded-2xl font-black text-sm hover:bg-white transition-all flex items-center gap-2">
                  <Download className="w-4 h-4" /> Save {outputFormat.toUpperCase()}
                </button>
                <button onClick={handlePrint} className="flex items-center gap-3 px-10 py-3 bg-indigo-600 text-white font-black text-sm rounded-2xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 active:scale-95"><Printer className="w-5 h-5" /> Print Project</button>
              </div>
            </div>
          )}
        </section>
      </main>

      <footer className="bg-white border-t border-slate-100 px-8 py-3 text-[10px] text-slate-300 font-bold uppercase tracking-widest flex justify-between shrink-0">
        <div className="flex gap-4 items-center">
          <span>© 2025 ChromaSketch Studio</span>
          {isProMode && <span className="text-indigo-500 flex items-center gap-1"><ShieldCheck className="w-3 h-3" /> Professional Vector Engine Active</span>}
        </div>
        <div className="flex gap-8 items-center">
          <span>Output: {outputFormat === 'vector' ? 'Scalable SVG' : `Raster ${resolution}`}</span>
          <span className="text-slate-200">|</span>
          <span>Zoom: Pan Supported (800% Precision)</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { 
  Plus, 
  Upload, 
  Printer, 
  RotateCcw, 
  Eraser, 
  Paintbrush, 
  Sparkles, 
  Download,
  Camera,
  Loader2,
  Trash2,
  Wand2,
  Image as ImageIcon,
  Undo,
  Redo,
  PaintBucket,
  Crop,
  Check,
  ChevronRight,
  ShieldCheck,
  Settings2,
  Maximize2,
  Type,
  PenTool,
  Wind,
  Highlighter,
  Hand,
  Trophy,
  Shapes,
  Image as RasterIcon,
  Link,
  Link2Off,
  MoveDiagonal2,
  Zap
} from 'lucide-react';
import { ColorPicker } from './components/ColorPicker';
import { Editor } from './components/Editor';
import { CameraModal } from './components/CameraModal';
import { StylePresets } from './components/StylePresets';
import { convertToLineArt, editWithAI, upscaleToStudioMaster, ColoringStyle, ImageResolution, OutputFormat } from './services/geminiService';
import { ToolType } from './types';

const BRUSH_PRESETS = [
  { label: 'XS', size: 2 },
  { label: 'S', size: 5 },
  { label: 'M', size: 10 },
  { label: 'L', size: 25 },
  { label: 'XL', size: 50 },
];

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [brushColor, setBrushColor] = useState('#FF0000');
  const [brushSize, setBrushSize] = useState(10);
  const [pressureEnabled, setPressureEnabled] = useState(false);
  const [activeTool, setActiveTool] = useState<ToolType>(ToolType.BRUSH);
  const [aiPrompt, setAiPrompt] = useState('');
  const [showCamera, setShowCamera] = useState(false);
  const [canUndo, setCanUndo] = useState(false);
  const [canRedo, setCanRedo] = useState(false);

  const [isProMode, setIsProMode] = useState(false);
  const [resolution, setResolution] = useState<ImageResolution>('1K');
  const [outputFormat, setOutputFormat] = useState<OutputFormat>('raster');

  // Canvas Dimension State
  const [canvasWidth, setCanvasWidth] = useState<number>(1024);
  const [canvasHeight, setCanvasHeight] = useState<number>(1024);
  const [aspectRatioLocked, setAspectRatioLocked] = useState(true);
  const [ratio, setRatio] = useState(1);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    setRatio(canvasWidth / canvasHeight);
  }, []);

  const handleWidthChange = (val: number) => {
    setCanvasWidth(val);
    if (aspectRatioLocked) {
      setCanvasHeight(Math.round(val / ratio));
    }
  };

  const handleHeightChange = (val: number) => {
    setCanvasHeight(val);
    if (aspectRatioLocked) {
      setCanvasWidth(Math.round(val * ratio));
    }
  };

  const toggleLock = () => {
    if (!aspectRatioLocked) {
      setRatio(canvasWidth / canvasHeight);
    }
    setAspectRatioLocked(!aspectRatioLocked);
  };

  const checkProPermissions = async () => {
    try {
      const hasKey = await (window as any).aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await (window as any).aistudio.openSelectKey();
      }
      return true;
    } catch (e) {
      console.error("Key selection failed", e);
      return false;
    }
  };

  const toggleProMode = async () => {
    if (!isProMode) {
      const success = await checkProPermissions();
      if (success) setIsProMode(true);
    } else {
      setIsProMode(false);
      setResolution('1K');
      setOutputFormat('raster');
    }
  };

  const handleFormatChange = async (fmt: OutputFormat) => {
    if (fmt === 'vector' && !isProMode) {
      const success = await checkProPermissions();
      if (success) {
        setIsProMode(true);
        setOutputFormat(fmt);
      }
    } else {
      setOutputFormat(fmt);
    }
  };

  const handleResolutionChange = async (res: ImageResolution) => {
    if (res !== '1K' && !isProMode) {
      const success = await checkProPermissions();
      if (success) {
        setIsProMode(true);
        setResolution(res);
      }
    } else {
      setResolution(res);
    }
  };

  const processImage = async (base64: string, style: ColoringStyle = 'standard') => {
    if ((resolution === '2K' || resolution === '4K') && !isProMode) {
       const success = await checkProPermissions();
       if (!success) return;
       setIsProMode(true);
    }

    setIsProcessing(true);
    try {
      const lineArt = await convertToLineArt(base64, style, resolution, outputFormat, isProMode);
      setImage(lineArt);
    } catch (error: any) {
      console.error("Processing failed", error);
      alert("Processing error. Ensure the image is clear.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleMasterUpscale = async () => {
    const data = (window as any).getCombinedImage?.();
    if (!data) return;

    setIsProcessing(true);
    try {
      const mastered = await upscaleToStudioMaster(data);
      setImage(mastered);
      setResolution('4K');
      setIsProMode(true);
      setOutputFormat('raster');
    } catch (error) {
      console.error("Master upscale failed", error);
      alert("Upscaling failed.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result as string;
      await processImage(base64);
    };
    reader.readAsDataURL(file);
  };

  const handleAIEdit = async () => {
    if (!image || !aiPrompt) return;
    setIsProcessing(true);
    try {
      const edited = await editWithAI(image, aiPrompt, isProMode);
      setImage(edited);
      setAiPrompt('');
    } catch (error) {
      alert("AI was unable to process that request.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handlePrint = () => {
    const combined = (window as any).getCombinedImage?.();
    if (!combined) return;
    const printWindow = window.open('', '_blank');
    if (printWindow) {
      printWindow.document.write(`<html><body style="margin:0;display:flex;justify-content:center;align-items:center;height:100vh;"><img src="${combined}" style="max-width:100%;max-height:100%;object-fit:contain;" /><script>window.onload=()=>window.print();</script></body></html>`);
      printWindow.document.close();
    }
  };

  const handleDownload = (onlyLineArt = false) => {
    const data = onlyLineArt ? (window as any).getLineArtOnly?.() : (window as any).getCombinedImage?.();
    if (!data) return;
    const extension = data.includes('svg+xml') ? 'svg' : 'png';
    const linkObj = document.createElement('a');
    linkObj.href = data;
    linkObj.download = `chromasketch-${outputFormat}-${resolution}-${Date.now()}.${extension}`;
    linkObj.click();
  };

  const handleCropComplete = (newImageData: string) => {
    setImage(newImageData);
    setActiveTool(ToolType.BRUSH);
  };

  const applyStylePreset = (color: string, size: number, tool: ToolType) => {
    setBrushColor(color);
    setBrushSize(size);
    setActiveTool(tool);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-900 overflow-hidden font-sans">
      {showCamera && (
        <CameraModal 
          onCapture={(base64, style) => { setShowCamera(false); processImage(base64, style); }} 
          onClose={() => setShowCamera(false)} 
        />
      )}

      <header className="bg-white border-b border-slate-200 px-6 py-4 flex justify-between items-center shrink-0 shadow-sm z-20">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2.5 rounded-2xl shadow-lg shadow-indigo-100">
              <Sparkles className="text-white w-6 h-6" />
            </div>
            <div>
              <h1 className="text-xl font-extrabold tracking-tight text-slate-800">ChromaSketch AI</h1>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Digital Arts Studio</p>
            </div>
          </div>

          <div className="hidden lg:flex items-center gap-2 bg-slate-50 p-1.5 rounded-2xl border border-slate-200">
            <button 
              onClick={toggleProMode}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl transition-all font-black text-xs uppercase tracking-wider ${isProMode ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-white'}`}
            >
              <ShieldCheck className={`w-4 h-4 ${isProMode ? 'animate-pulse' : ''}`} />
              Studio Pro
            </button>

            <div className="w-[1px] h-4 bg-slate-200 mx-1" />

            <div className="flex bg-slate-100 p-0.5 rounded-xl">
              <button
                onClick={() => handleFormatChange('raster')}
                className={`px-3 py-1.5 rounded-lg flex items-center gap-2 text-[10px] font-black transition-all ${outputFormat === 'raster' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}
              >
                <RasterIcon className="w-3 h-3" /> PNG
              </button>
              <button
                onClick={() => handleFormatChange('vector')}
                className={`px-3 py-1.5 rounded-lg flex items-center gap-2 text-[10px] font-black transition-all ${outputFormat === 'vector' ? 'bg-indigo-600 text-white shadow-sm' : 'text-slate-400'}`}
              >
                <Shapes className="w-3 h-3" /> SVG
              </button>
            </div>

            {outputFormat === 'raster' && (
              <>
                <div className="w-[1px] h-4 bg-slate-200 mx-1" />
                {(['1K', '2K', '4K'] as ImageResolution[]).map(res => (
                  <button
                    key={res}
                    onClick={() => handleResolutionChange(res)}
                    className={`px-3 py-2 rounded-xl text-[10px] font-black transition-all ${resolution === res ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    {res}
                  </button>
                ))}
              </>
            )}
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button onClick={() => setShowCamera(true)} className="flex items-center gap-2 px-4 py-2 hover:bg-slate-50 text-slate-600 rounded-lg transition-all font-semibold"><Camera className="w-4 h-4" /> Camera</button>
          <button onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 px-4 py-2 bg-white text-indigo-600 rounded-lg shadow-sm hover:shadow-md transition-all font-bold border border-indigo-50"><Upload className="w-4 h-4" /> Upload</button>
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <aside className="w-80 bg-white border-r border-slate-200 p-6 flex flex-col gap-6 shrink-0 overflow-y-auto shadow-sm z-10 custom-scrollbar">
          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 text-center border-b pb-2 border-slate-50">Studio Palette</h3>
            <ColorPicker currentColor={brushColor} onChange={setBrushColor} />
          </section>

          <section className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Line Weight</h3>
              <div className="flex items-center gap-1.5">
                <input 
                  type="number" 
                  min="1" 
                  max="100" 
                  value={brushSize} 
                  onChange={(e) => setBrushSize(Math.min(100, Math.max(1, parseInt(e.target.value) || 1)))}
                  className="w-12 bg-white border border-slate-200 rounded px-1.5 py-0.5 text-[10px] font-black text-indigo-600 text-center focus:ring-1 focus:ring-indigo-400 outline-none"
                />
                <span className="text-[8px] font-black text-slate-400 uppercase">px</span>
              </div>
            </div>

            <input 
              type="range" 
              min="1" 
              max="100" 
              step="1"
              value={brushSize} 
              onChange={(e) => setBrushSize(parseInt(e.target.value))} 
              className="w-full h-1.5 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600 mb-4" 
            />

            <div className="flex justify-between gap-1.5 mb-4">
              {BRUSH_PRESETS.map((preset) => (
                <button
                  key={preset.label}
                  onClick={() => setBrushSize(preset.size)}
                  className={`flex-1 py-1.5 rounded-lg text-[9px] font-black transition-all ${
                    brushSize === preset.size 
                    ? 'bg-indigo-600 text-white shadow-md' 
                    : 'bg-white text-slate-400 hover:text-slate-600 border border-slate-100'
                  }`}
                >
                  {preset.label}
                </button>
              ))}
            </div>

            <button 
              onClick={() => setPressureEnabled(!pressureEnabled)}
              className={`w-full flex items-center justify-between p-2 rounded-xl border transition-all ${pressureEnabled ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg' : 'bg-white border-slate-100 text-slate-500 hover:bg-slate-50'}`}
            >
              <div className="flex items-center gap-2">
                <Zap className={`w-3.5 h-3.5 ${pressureEnabled ? 'fill-yellow-300 text-yellow-300' : 'text-slate-300'}`} />
                <span className="text-[10px] font-black uppercase tracking-wider">Pressure Sensitivity</span>
              </div>
              <div className={`w-8 h-4 rounded-full relative transition-colors ${pressureEnabled ? 'bg-indigo-400' : 'bg-slate-200'}`}>
                <div className={`absolute top-0.5 w-3 h-3 bg-white rounded-full transition-all shadow-sm ${pressureEnabled ? 'left-4.5' : 'left-0.5'}`} />
              </div>
            </button>
          </section>

          <section className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 flex justify-between items-center">
              Canvas Dimensions
              <button onClick={toggleLock} className={`p-1 rounded ${aspectRatioLocked ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-200 text-slate-500'}`}>
                {aspectRatioLocked ? <Link className="w-3 h-3" /> : <Link2Off className="w-3 h-3" />}
              </button>
            </h3>
            <div className="flex flex-col gap-3">
              <div className="flex items-center gap-2">
                <span className="text-[10px] font-bold text-slate-400 w-4">W</span>
                <input 
                  type="number" 
                  value={canvasWidth} 
                  onChange={(e) => handleWidthChange(parseInt(e.target.value) || 0)}
                  className="flex-1 bg-white border border-slate-200 rounded-lg px-3 py-1.5 text-xs font-mono"
                />
              </div>
              <div className="flex items-center gap-2">
                <span className="text-[10px] font-bold text-slate-400 w-4">H</span>
                <input 
                  type="number" 
                  value={canvasHeight} 
                  onChange={(e) => handleHeightChange(parseInt(e.target.value) || 0)}
                  className="flex-1 bg-white border border-slate-200 rounded-lg px-3 py-1.5 text-xs font-mono"
                />
              </div>
            </div>
          </section>

          <section>
            <StylePresets 
              currentColor={brushColor}
              currentSize={brushSize}
              currentTool={activeTool}
              onApplyPreset={applyStylePreset}
            />
          </section>

          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Precision Tools</h3>
            <div className="grid grid-cols-2 gap-2">
              {[
                { id: ToolType.BRUSH, icon: Paintbrush, label: 'Brush' },
                { id: ToolType.PAN, icon: Hand, label: 'Pan/View' },
                { id: ToolType.HIGHLIGHTER, icon: Highlighter, label: 'Marker' },
                { id: ToolType.SPRAY, icon: Wind, label: 'Spray' },
                { id: ToolType.CALLIGRAPHY, icon: PenTool, label: 'Chisel' },
                { id: ToolType.RAINBOW, icon: Sparkles, label: 'Rainbow' },
                { id: ToolType.BUCKET, icon: PaintBucket, label: 'Fill' },
                { id: ToolType.ERASER, icon: Eraser, label: 'Eraser' },
                { id: ToolType.CROP, icon: Crop, label: 'Crop' }
              ].map(t => (
                <button 
                  key={t.id} 
                  onClick={() => setActiveTool(t.id)} 
                  className={`flex items-center gap-3 p-3 rounded-xl border-2 transition-all ${activeTool === t.id ? 'border-indigo-600 bg-indigo-50 text-indigo-700 font-bold' : 'border-slate-50 text-slate-500 hover:border-slate-200'}`}
                >
                  <t.icon className="w-4 h-4" />
                  <span className="text-[10px] font-black uppercase">{t.label}</span>
                </button>
              ))}
            </div>
          </section>

          <section className="mt-auto">
            {image && (
              <button 
                onClick={handleMasterUpscale}
                className="w-full mb-4 group relative flex items-center justify-center gap-3 p-4 bg-gradient-to-r from-indigo-600 to-purple-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg hover:scale-[1.02] active:scale-95 transition-all overflow-hidden"
              >
                <div className="absolute inset-0 bg-white/20 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-700 skew-x-12" />
                <Trophy className="w-4 h-4 text-yellow-300" />
                Master 4K Reconstruction
              </button>
            )}
            <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
              <h3 className="text-xs font-bold text-indigo-600 uppercase mb-3 flex items-center gap-2">
                < Wand2 className="w-3 h-3" /> AI Stylist
              </h3>
              <textarea
                placeholder="E.g. Add complex floral motifs..."
                value={aiPrompt}
                onChange={(e) => setAiPrompt(e.target.value)}
                className="w-full text-xs p-3 rounded-xl bg-white border border-slate-200 h-20 resize-none outline-none focus:ring-2 focus:ring-indigo-500 shadow-inner"
              />
              <button disabled={!image || isProcessing || !aiPrompt} onClick={handleAIEdit} className="mt-3 w-full bg-indigo-600 text-white p-2.5 rounded-xl text-xs font-bold flex items-center justify-center gap-2 disabled:opacity-30 hover:bg-indigo-700 transition-all">
                {isProcessing ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Sparkles className="w-3.5 h-3.5" />} 
                Transform Page
              </button>
            </div>
          </section>
        </aside>

        <section className="flex-1 flex flex-col p-8 relative overflow-hidden bg-slate-100/50">
          <div className="flex-1 relative">
            {isProcessing && (
              <div className="absolute inset-0 z-[100] flex items-center justify-center bg-white/60 backdrop-blur-md rounded-3xl">
                <div className="bg-white p-12 rounded-[2.5rem] shadow-2xl flex flex-col items-center gap-8 border border-slate-100 max-w-sm text-center">
                  <div className="relative">
                    <div className="w-24 h-24 border-[6px] border-slate-50 border-t-indigo-600 rounded-full animate-spin" />
                    <Sparkles className="w-10 h-10 text-indigo-500 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 animate-pulse" />
                  </div>
                  <div>
                    <h4 className="text-2xl font-black text-slate-800 mb-2">
                      {outputFormat === 'vector' ? 'Tracing Vector Map...' : 'Rendering Canvas...'}
                    </h4>
                    <p className="text-slate-400 font-medium">Gemini 3 Pro is refining your artwork for {resolution} output.</p>
                  </div>
                </div>
              </div>
            )}

            {!image ? (
              <div className="h-full border-4 border-dashed border-slate-200 rounded-[2.5rem] flex flex-col items-center justify-center bg-white gap-8 text-center px-16 group transition-all hover:border-indigo-100 hover:bg-slate-50/50">
                <div className="w-32 h-32 bg-indigo-50 text-indigo-600 rounded-[2.5rem] flex items-center justify-center transform group-hover:rotate-6 transition-transform shadow-xl">
                  <ImageIcon className="w-16 h-16" />
                </div>
                <div>
                  <h2 className="text-4xl font-black text-slate-800 mb-4 tracking-tight">Pro Illustration Studio</h2>
                  <p className="text-slate-400 max-w-md font-medium leading-relaxed">Infinitely scalable vector art from your photos. Perfect for professional coloring books and large-scale printing.</p>
                </div>
                <div className="flex gap-4">
                  <button onClick={() => setShowCamera(true)} className="bg-indigo-600 text-white px-10 py-4 rounded-2xl font-black text-lg hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 flex items-center gap-3 transform hover:-translate-y-1 active:scale-95"><Camera className="w-6 h-6" /> Camera</button>
                  <button onClick={() => fileInputRef.current?.click()} className="bg-white text-indigo-600 border-2 border-indigo-600 px-10 py-4 rounded-2xl font-black text-lg hover:bg-indigo-50 transition-all flex items-center gap-3 transform hover:-translate-y-1 active:scale-95"><Upload className="w-6 h-6" /> Upload</button>
                </div>
              </div>
            ) : (
              <Editor 
                backgroundImage={image} 
                brushColor={brushColor} 
                brushSize={brushSize} 
                pressureEnabled={pressureEnabled}
                tool={activeTool}
                onHistoryChange={(u, r) => { setCanUndo(u); setCanRedo(r); }}
                onCropComplete={handleCropComplete}
                canvasWidth={canvasWidth}
                canvasHeight={canvasHeight}
              />
            )}
          </div>

          {image && (
            <div className="mt-8 flex justify-between items-center bg-white p-4 rounded-3xl border border-slate-200 shadow-xl z-20">
              <div className="flex gap-2">
                <button onClick={() => (window as any).undo?.()} disabled={!canUndo} className={`p-3 rounded-2xl transition-all ${canUndo ? 'text-indigo-600 bg-indigo-50 hover:bg-indigo-100 shadow-sm' : 'text-slate-200'}`} title="Undo Strokes"><Undo className="w-5 h-5" /></button>
                <button onClick={() => (window as any).redo?.()} disabled={!canRedo} className={`p-3 rounded-2xl transition-all ${canRedo ? 'text-indigo-600 bg-indigo-50 hover:bg-indigo-100 shadow-sm' : 'text-slate-200'}`} title="Redo Strokes"><Redo className="w-5 h-5" /></button>
                <div className="w-[1px] h-8 bg-slate-100 mx-1 self-center" />
                <button onClick={() => (window as any).clearCanvas?.()} className="p-3 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-2xl transition-all flex items-center gap-2" title="Reset Colors"><RotateCcw className="w-4 h-4" /><span className="text-[10px] font-black uppercase">Clear</span></button>
              </div>
              <div className="flex gap-4">
                <button onClick={() => handleDownload(false)} className="px-8 py-3 bg-slate-50 text-slate-600 border border-slate-200 rounded-2xl font-black text-sm hover:bg-white transition-all flex items-center gap-2">
                  <Download className="w-4 h-4" /> Save {outputFormat.toUpperCase()}
                </button>
                <button onClick={handlePrint} className="flex items-center gap-3 px-10 py-3 bg-indigo-600 text-white font-black text-sm rounded-2xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 active:scale-95"><Printer className="w-5 h-5" /> Print Project</button>
              </div>
            </div>
          )}
        </section>
      </main>

      <footer className="bg-white border-t border-slate-100 px-8 py-3 text-[10px] text-slate-300 font-bold uppercase tracking-widest flex justify-between shrink-0">
        <div className="flex gap-4 items-center">
          <span>© 2025 ChromaSketch Studio</span>
          {isProMode && <span className="text-indigo-500 flex items-center gap-1"><ShieldCheck className="w-3 h-3" /> Professional Vector Engine Active</span>}
        </div>
        <div className="flex gap-8 items-center">
          <span>Output: {outputFormat === 'vector' ? 'Scalable SVG' : `Raster ${resolution}`}</span>
          <span className="text-slate-200">|</span>
          <span>Zoom: Pan Supported (800% Precision)</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { ToolType } from '../types';
import { ZoomIn, ZoomOut, Maximize, Hand, MoveDiagonal2, RotateCcw } from 'lucide-react';

interface EditorProps {
  backgroundImage: string | null;
  brushColor: string;
  brushSize: number;
  pressureEnabled?: boolean;
  tool: ToolType;
  onHistoryChange?: (canUndo: boolean, canRedo: boolean) => void;
  onCropComplete?: (newLineArt: string) => void;
  canvasWidth?: number;
  canvasHeight?: number;
}

const MAX_HISTORY = 50;
const HANDLE_SIZE = 12;

function hexToRgb(hex: string) {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16),
    g: parseInt(result[2], 16),
    b: parseInt(result[3], 16)
  } : { r: 0, g: 0, b: 0 };
}

export const Editor: React.FC<EditorProps> = ({ 
  backgroundImage, 
  brushColor, 
  brushSize, 
  pressureEnabled = false,
  tool, 
  onHistoryChange, 
  onCropComplete,
  canvasWidth,
  canvasHeight
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null); 
  const drawingCanvasRef = useRef<HTMLCanvasElement>(null); 
  const containerRef = useRef<HTMLDivElement>(null);

  const [isDrawing, setIsDrawing] = useState(false);
  const [isPanning, setIsPanning] = useState(false);
  const rainbowHueRef = useRef(0);
  const lastCoordsRef = useRef<{x: number, y: number} | null>(null);

  const [view, setView] = useState({ scale: 1, x: 0, y: 0 });

  // Crop States
  const [cropRect, setCropRect] = useState({ x: 50, y: 50, w: 300, h: 300 });
  const [dragMode, setDragMode] = useState<'none' | 'move' | number>('none');
  const [startDragCoords, setStartDragCoords] = useState({ x: 0, y: 0 });
  const [initialView, setInitialView] = useState({ scale: 1, x: 0, y: 0 });
  const [initialCropRect, setInitialCropRect] = useState({ x: 50, y: 50, w: 300, h: 300 });

  const historyRef = useRef<ImageData[]>([]);
  const historyIndexRef = useRef<number>(-1);

  const updateHistoryStatus = useCallback(() => {
    if (onHistoryChange) {
      onHistoryChange(
        historyIndexRef.current > 0,
        historyIndexRef.current < historyRef.current.length - 1
      );
    }
  }, [onHistoryChange]);

  const saveState = useCallback(() => {
    const canvas = drawingCanvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (canvas && ctx) {
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      if (historyIndexRef.current < historyRef.current.length - 1) {
        historyRef.current = historyRef.current.slice(0, historyIndexRef.current + 1);
      }
      historyRef.current.push(imageData);
      if (historyRef.current.length > MAX_HISTORY) {
        historyRef.current.shift();
      } else {
        historyIndexRef.current++;
      }
      updateHistoryStatus();
    }
  }, [updateHistoryStatus]);

  const undo = useCallback(() => {
    if (historyIndexRef.current > 0) {
      historyIndexRef.current--;
      const canvas = drawingCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (canvas && ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.putImageData(historyRef.current[historyIndexRef.current], 0, 0);
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  const redo = useCallback(() => {
    if (historyIndexRef.current < historyRef.current.length - 1) {
      historyIndexRef.current++;
      const canvas = drawingCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (canvas && ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.putImageData(historyRef.current[historyIndexRef.current], 0, 0);
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  const clearDrawing = useCallback(() => {
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.clearRect(0, 0, drawingCanvasRef.current!.width, drawingCanvasRef.current!.height);
      saveState();
    }
  }, [saveState]);

  useEffect(() => {
    if (drawingCanvasRef.current && historyRef.current.length === 0) {
      const ctx = drawingCanvasRef.current.getContext('2d');
      if (ctx) {
        const empty = ctx.getImageData(0, 0, drawingCanvasRef.current.width, drawingCanvasRef.current.height);
        historyRef.current = [empty];
        historyIndexRef.current = 0;
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  const fitToScreen = useCallback(() => {
    const parent = containerRef.current;
    if (!parent || !canvasRef.current || !drawingCanvasRef.current) return;

    const containerW = parent.clientWidth;
    const containerH = parent.clientHeight;
    const targetW = canvasWidth || containerW;
    const targetH = canvasHeight || containerH;

    const scaleToFit = Math.min(containerW / targetW, containerH / targetH) * 0.9;

    setView({
      scale: scaleToFit,
      x: (containerW - targetW * scaleToFit) / 2,
      y: (containerH - targetH * scaleToFit) / 2
    });
  }, [canvasWidth, canvasHeight]);

  const resize = useCallback(() => {
    const parent = containerRef.current;
    if (!parent || !canvasRef.current || !drawingCanvasRef.current) return;

    const containerW = parent.clientWidth;
    const containerH = parent.clientHeight;
    const targetW = canvasWidth || containerW;
    const targetH = canvasHeight || containerH;

    const temp = document.createElement('canvas');
    temp.width = drawingCanvasRef.current.width;
    temp.height = drawingCanvasRef.current.height;
    temp.getContext('2d')?.drawImage(drawingCanvasRef.current, 0, 0);

    canvasRef.current.width = targetW;
    canvasRef.current.height = targetH;
    drawingCanvasRef.current.width = targetW;
    drawingCanvasRef.current.height = targetH;

    const ctx = drawingCanvasRef.current.getContext('2d');
    if (ctx) {
      ctx.drawImage(temp, 0, 0, temp.width, temp.height, 0, 0, targetW, targetH);
    }

    if (backgroundImage) {
      const bgCtx = canvasRef.current.getContext('2d');
      if (bgCtx) {
        const img = new Image();
        img.onload = () => {
          bgCtx.clearRect(0, 0, targetW, targetH);
          const scaleFactor = Math.min(targetW / img.width, targetH / img.height);
          const x = (targetW / 2) - (img.width / 2) * scaleFactor;
          const y = (targetH / 2) - (img.height / 2) * scaleFactor;
          bgCtx.drawImage(img, x, y, img.width * scaleFactor, img.height * scaleFactor);
        };
        img.src = backgroundImage;
      }
    }

    setCropRect({ x: targetW * 0.1, y: targetH * 0.1, w: targetW * 0.8, h: targetH * 0.8 });
    fitToScreen();
  }, [backgroundImage, canvasWidth, canvasHeight, fitToScreen]);

  useEffect(() => {
    window.addEventListener('resize', resize);
    resize();
    return () => window.removeEventListener('resize', resize);
  }, [resize]);

  const getCoords = (e: React.PointerEvent) => {
    const rect = containerRef.current?.getBoundingClientRect();
    if (!rect) return { x: 0, y: 0 };

    const clientX = e.clientX;
    const clientY = e.clientY;

    const x = (clientX - rect.left - view.x) / view.scale;
    const y = (clientY - rect.top - view.y) / view.scale;

    return { x, y };
  };

  const applyCrop = useCallback(() => {
    if (!canvasRef.current || !drawingCanvasRef.current) return;
    const { x, y, w, h } = cropRect;
    if (w <= 5 || h <= 5) return;

    const lineArtCrop = document.createElement('canvas');
    lineArtCrop.width = w;
    lineArtCrop.height = h;
    lineArtCrop.getContext('2d')?.drawImage(canvasRef.current, x, y, w, h, 0, 0, w, h);
    const newLineArt = lineArtCrop.toDataURL('image/png');

    const drawingCrop = document.createElement('canvas');
    drawingCrop.width = w;
    drawingCrop.height = h;
    drawingCrop.getContext('2d')?.drawImage(drawingCanvasRef.current, x, y, w, h, 0, 0, w, h);

    if (onCropComplete) {
      onCropComplete(newLineArt);
      const dCtx = drawingCanvasRef.current.getContext('2d');
      if (dCtx) {
        dCtx.clearRect(0, 0, drawingCanvasRef.current.width, drawingCanvasRef.current.height);
        dCtx.drawImage(drawingCrop, 0, 0, w, h, 0, 0, drawingCanvasRef.current.width, drawingCanvasRef.current.height);
        saveState();
      }
    }
  }, [cropRect, onCropComplete, saveState]);

  const handleBucketFill = (startX: number, startY: number) => {
    const canvas = drawingCanvasRef.current;
    const bgCanvas = canvasRef.current;
    if (!canvas || !bgCanvas) return;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    const { width, height } = canvas;
    const tempCanvas = document.createElement('canvas');
    tempCanvas.width = width;
    tempCanvas.height = height;
    const tCtx = tempCanvas.getContext('2d', { willReadFrequently: true })!;
    tCtx.fillStyle = '#ffffff';
    tCtx.fillRect(0, 0, width, height);
    tCtx.drawImage(bgCanvas, 0, 0);
    tCtx.drawImage(canvas, 0, 0);

    const imgData = tCtx.getImageData(0, 0, width, height);
    const pixels = imgData.data;
    const x = Math.round(startX);
    const y = Math.round(startY);
    const pos = (y * width + x) * 4;
    const [tR, tG, tB] = [pixels[pos], pixels[pos+1], pixels[pos+2]];
    const fill = hexToRgb(brushColor);

    if (Math.abs(tR - fill.r) < 10 && Math.abs(tG - fill.g) < 10 && Math.abs(tB - fill.b) < 10) return;

    const stack = [[x, y]];
    const seen = new Uint8Array(width * height);
    const fillPixels = new Uint8Array(width * height);
    const threshold = 60;

    while (stack.length) {
      const [cx, cy] = stack.pop()!;
      if (cx < 0 || cx >= width || cy < 0 || cy >= height) continue;
      const idx = cy * width + cx;
      if (seen[idx]) continue;
      seen[idx] = 1;

      const p = idx * 4;
      if (Math.abs(pixels[p] - tR) < threshold && Math.abs(pixels[p+1] - tG) < threshold && Math.abs(pixels[p+2] - tB) < threshold) {
        fillPixels[idx] = 1;
        stack.push([cx + 1, cy], [cx - 1, cy], [cx, cy + 1], [cx, cy - 1]);
      }
    }

    const res = ctx.createImageData(width, height);
    for (let i = 0; i < width * height; i++) {
      if (fillPixels[i]) {
        const p = i * 4;
        res.data[p] = fill.r;
        res.data[p+1] = fill.g;
        res.data[p+2] = fill.b;
        res.data[p+3] = 255;
      }
    }
    const scratch = document.createElement('canvas');
    scratch.width = width;
    scratch.height = height;
    scratch.getContext('2d')?.putImageData(res, 0, 0);
    ctx.globalCompositeOperation = 'source-over';
    ctx.drawImage(scratch, 0, 0);
    saveState();
  };

  const getHandleAt = (px: number, py: number) => {
    const { x, y, w, h } = cropRect;
    const handles = [
      { x: x, y: y }, { x: x + w, y: y }, { x: x + w, y: y + h }, { x: x, y: y + h },
      { x: x + w / 2, y: y }, { x: x + w, y: y + h / 2 }, { x: x + w / 2, y: y + h }, { x: x, y: y + h / 2 }
    ];
    for (let i = 0; i < handles.length; i++) {
      if (Math.abs(px - handles[i].x) < HANDLE_SIZE && Math.abs(py - handles[i].y) < HANDLE_SIZE) return i;
    }
    return -1;
  };

  const start = (e: React.PointerEvent) => {
    const coords = getCoords(e);
    const clientX = e.clientX;
    const clientY = e.clientY;

    if (tool === ToolType.PAN) {
      setIsPanning(true);
      setStartDragCoords({ x: clientX, y: clientY });
      setInitialView({ ...view });
      return;
    }

    if (tool === ToolType.CROP) {
      const handleIdx = getHandleAt(coords.x, coords.y);
      if (handleIdx !== -1) setDragMode(handleIdx);
      else if (coords.x >= cropRect.x && coords.x <= cropRect.x + cropRect.w && coords.y >= cropRect.y && coords.y <= cropRect.y + cropRect.h) setDragMode('move');
      else return;
      setStartDragCoords({ x: coords.x, y: coords.y });
      setInitialCropRect({ ...cropRect });
      return;
    }

    if (tool === ToolType.BUCKET) return handleBucketFill(coords.x, coords.y);

    setIsDrawing(true);
    lastCoordsRef.current = coords;
  };

  const draw = (e: React.PointerEvent) => {
    const coords = getCoords(e);
    const clientX = e.clientX;
    const clientY = e.clientY;

    if (tool === ToolType.PAN && isPanning) {
      const dx = clientX - startDragCoords.x;
      const dy = clientY - startDragCoords.y;
      setView(prev => ({
        ...prev,
        x: initialView.x + dx,
        y: initialView.y + dy
      }));
      return;
    }

    if (tool === ToolType.CROP && dragMode !== 'none') {
      const dx = coords.x - startDragCoords.x;
      const dy = coords.y - startDragCoords.y;
      const newRect = { ...initialCropRect };
      if (dragMode === 'move') { newRect.x += dx; newRect.y += dy; }
      else {
        switch (dragMode) {
          case 0: newRect.x += dx; newRect.y += dy; newRect.w -= dx; newRect.h -= dy; break;
          case 1: newRect.y += dy; newRect.w += dx; newRect.h -= dy; break;
          case 2: newRect.w += dx; newRect.h += dy; break;
          case 3: newRect.x += dx; newRect.w -= dx; newRect.h += dy; break;
          case 4: newRect.y += dy; newRect.h -= dy; break;
          case 5: newRect.w += dx; break;
          case 6: newRect.h += dy; break;
          case 7: newRect.x += dx; newRect.w -= dx; break;
        }
      }
      if (newRect.w < 10) newRect.w = 10;
      if (newRect.h < 10) newRect.h = 10;
      setCropRect(newRect);
      return;
    }

    if (!isDrawing || tool === ToolType.BUCKET || !lastCoordsRef.current) return;
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (!ctx) return;

    // Apply Pen Pressure modulation
    // Spec: pressure is 0 to 1. hardware without pressure uses 0.5.
    const pressure = (pressureEnabled && e.pressure > 0) ? e.pressure : 1.0;
    const effectiveSize = pressureEnabled ? brushSize * (0.2 + 0.8 * pressure) : brushSize;
    const effectiveAlpha = pressureEnabled ? (0.3 + 0.7 * pressure) : 1.0;

    ctx.beginPath();
    ctx.moveTo(lastCoordsRef.current.x, lastCoordsRef.current.y);
    ctx.lineTo(coords.x, coords.y);
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.lineWidth = effectiveSize;

    if (tool === ToolType.SPRAY) {
      ctx.fillStyle = brushColor;
      const density = (20 + brushSize / 2) * pressure;
      for (let i = 0; i < density; i++) {
        const angle = Math.random() * Math.PI * 2;
        const dist = Math.random() * effectiveSize;
        const px = coords.x + Math.cos(angle) * dist;
        const py = coords.y + Math.sin(angle) * dist;
        ctx.fillRect(px, py, 1.2, 1.2);
      }
    } else if (tool === ToolType.RAINBOW) {
      rainbowHueRef.current = (rainbowHueRef.current + 3) % 360;
      ctx.strokeStyle = `hsl(${rainbowHueRef.current}, 100%, 50%)`;
      ctx.stroke();
    } else if (tool === ToolType.CALLIGRAPHY) {
      ctx.strokeStyle = brushColor;
      ctx.globalAlpha = effectiveAlpha;
      ctx.lineCap = 'butt';
      ctx.stroke();
      ctx.globalAlpha = 1.0;
    } else {
      ctx.strokeStyle = tool === ToolType.ERASER ? '#FFFFFF' : brushColor;
      ctx.globalCompositeOperation = tool === ToolType.ERASER ? 'destination-out' : 'source-over';
      ctx.globalAlpha = tool === ToolType.HIGHLIGHTER ? 0.35 * effectiveAlpha : effectiveAlpha;
      ctx.stroke();
      ctx.globalAlpha = 1.0;
    }

    lastCoordsRef.current = coords;
  };

  const stop = () => { 
    if (isDrawing) { 
      setIsDrawing(false); 
      saveState(); 
    }
    setIsPanning(false);
    setDragMode('none');
    lastCoordsRef.current = null;
  };

  const applyZoom = useCallback((zoomFactor: number, focusX: number, focusY: number) => {
    setView(prev => {
      const nextScale = Math.min(10, Math.max(0.05, prev.scale * zoomFactor));
      const actualFactor = nextScale / prev.scale;

      return {
        scale: nextScale,
        x: focusX - (focusX - prev.x) * actualFactor,
        y: focusY - (focusY - prev.y) * actualFactor
      };
    });
  }, []);

  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    const zoomIntensity = 0.001; 
    const wheel = -e.deltaY;
    const zoomFactor = Math.exp(wheel * zoomIntensity);

    const container = containerRef.current;
    if (!container) return;
    const rect = container.getBoundingClientRect();

    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;

    applyZoom(zoomFactor, mouseX, mouseY);
  };

  const handleZoomDiscrete = (type: 'in' | 'out') => {
    const container = containerRef.current;
    if (!container) return;
    const rect = container.getBoundingClientRect();
    const centerX = rect.width / 2;
    const centerY = rect.height / 2;
    const factor = type === 'in' ? 1.1 : 0.9; 
    applyZoom(factor, centerX, centerY);
  };

  const resetZoomTo100 = () => {
    const parent = containerRef.current;
    if (!parent) return;
    const containerW = parent.clientWidth;
    const containerH = parent.clientHeight;
    const targetW = canvasWidth || containerW;
    const targetH = canvasHeight || containerH;
    setView({
      scale: 1.0,
      x: (containerW - targetW) / 2,
      y: (containerH - targetH) / 2
    });
  };

  const getCombined = () => {
    if (!canvasRef.current || !drawingCanvasRef.current) return '';
    const final = document.createElement('canvas');
    final.width = canvasRef.current.width;
    final.height = canvasRef.current.height;
    const ctx = final.getContext('2d')!;
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, final.width, final.height);
    ctx.drawImage(drawingCanvasRef.current, 0, 0);
    ctx.globalCompositeOperation = 'multiply';
    ctx.drawImage(canvasRef.current, 0, 0);
    return final.toDataURL('image/png');
  };

  useEffect(() => {
    (window as any).clearCanvas = clearDrawing;
    (window as any).getCombinedImage = getCombined;
    (window as any).undo = undo;
    (window as any).redo = redo;
    (window as any).applyCrop = applyCrop;
  }, [clearDrawing, undo, redo, applyCrop, backgroundImage, brushColor, brushSize, tool]);

  return (
    <div 
      ref={containerRef}
      className="relative w-full h-full bg-slate-200 rounded-3xl shadow-inner overflow-hidden border-4 border-white group"
      onWheel={handleWheel}
    >
      <div className="absolute inset-0 bg-[radial-gradient(#CBD5E1_1px,transparent_1px)] [background-size:20px_20px] opacity-30" />

      <div 
        className="absolute origin-top-left will-change-transform"
        style={{ 
          transform: `translate(${view.x}px, ${view.y}px) scale(${view.scale})`,
          width: canvasWidth,
          height: canvasHeight
        }}
      >
        <div className="absolute inset-0 shadow-2xl bg-white ring-1 ring-slate-300" />
        <canvas
          ref={drawingCanvasRef}
          onPointerDown={start}
          onPointerMove={draw}
          onPointerUp={stop}
          onPointerLeave={stop}
          className={`absolute inset-0 touch-none ${tool === ToolType.PAN ? (isPanning ? 'cursor-grabbing' : 'cursor-grab') : (tool === ToolType.CROP ? 'cursor-default' : 'cursor-crosshair')}`}
        />
        <canvas ref={canvasRef} className="absolute inset-0 pointer-events-none mix-blend-multiply" />
      </div>

      <div className="absolute top-6 left-6 flex flex-col gap-2 pointer-events-none">
         <div className="px-4 py-2 bg-black/80 backdrop-blur-md text-white text-[10px] font-black rounded-full shadow-lg border border-white/10 uppercase tracking-widest flex items-center gap-2">
            <MoveDiagonal2 className="w-3 h-3" />
            {canvasWidth} x {canvasHeight} | {Math.round(view.scale * 100)}%
         </div>
      </div>

      <div className="absolute bottom-6 right-6 flex flex-col gap-2 p-1.5 bg-white/90 backdrop-blur-xl rounded-[2rem] border border-slate-200 shadow-2xl opacity-0 group-hover:opacity-100 transition-all scale-90 group-hover:scale-100">
        <button onClick={() => handleZoomDiscrete('in')} className="p-4 hover:bg-slate-50 text-slate-600 rounded-full transition-all" title="Zoom In (10%)"><ZoomIn className="w-5 h-5" /></button>
        <div className="h-[1px] bg-slate-100 mx-3" />
        <button onClick={() => handleZoomDiscrete('out')} className="p-4 hover:bg-slate-50 text-slate-600 rounded-full transition-all" title="Zoom Out (10%)"><ZoomOut className="w-5 h-5" /></button>
        <div className="h-[1px] bg-slate-100 mx-3" />
        <button onClick={resetZoomTo100} className="p-4 hover:bg-slate-50 text-indigo-600 rounded-full transition-all" title="Reset Zoom (100%)"><RotateCcw className="w-5 h-5" /></button>
        <div className="h-[1px] bg-slate-100 mx-3" />
        <button onClick={fitToScreen} className="p-4 hover:bg-indigo-600 hover:text-white text-slate-400 rounded-full transition-all" title="Fit to Screen"><Maximize className="w-5 h-5" /></button>
      </div>

      {tool === ToolType.CROP && (
        <div className="absolute inset-0 pointer-events-none">
          <div className="absolute border-2 border-white shadow-[0_0_0_1px_rgba(0,0,0,0.5)] pointer-events-auto" style={{ left: cropRect.x, top: cropRect.y, width: cropRect.w, height: cropRect.h }}>
          </div>
        </div>
      )}

      {tool === ToolType.PAN && !isPanning && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none bg-black/50 backdrop-blur-sm text-white px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3">
          <Hand className="w-4 h-4 animate-bounce" /> Drag to explore canvas
        </div>
      )}
    </div>
  );
};

export interface ImageState {
  original: string | null;
  lineArt: string | null;
  history: string[];
}

export interface ColorPreset {
  name: string;
  value: string;
}

export enum ToolType {
  BRUSH = 'BRUSH',
  ERASER = 'ERASER',
  BUCKET = 'BUCKET',
  CROP = 'CROP',
  HIGHLIGHTER = 'HIGHLIGHTER',
  SPRAY = 'SPRAY',
  CALLIGRAPHY = 'CALLIGRAPHY',
  RAINBOW = 'RAINBOW',
  PAN = 'PAN',
  INVERT = 'INVERT'
}

export interface DrawingPoint {
  x: number;
  y: number;
  color: string;
  size: number;
  type: ToolType;
  isDragging: boolean;
}

import React, { useRef, useEffect, useState, useCallback } from 'react';
import { ToolType } from '../types';
import { ZoomIn, ZoomOut, Maximize, Hand, MoveDiagonal2, RotateCcw, Contrast } from 'lucide-react';

interface EditorProps {
  backgroundImage: string | null;
  brushColor: string;
  brushSize: number;
  pressureEnabled?: boolean;
  tool: ToolType;
  onHistoryChange?: (canUndo: boolean, canRedo: boolean) => void;
  onCropComplete?: (newLineArt: string) => void;
  canvasWidth?: number;
  canvasHeight?: number;
}

const MAX_HISTORY = 50;
const HANDLE_SIZE = 12;

function hexToRgb(hex: string) {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16),
    g: parseInt(result[2], 16),
    b: parseInt(result[3], 16)
  } : { r: 0, g: 0, b: 0 };
}

export const Editor: React.FC<EditorProps> = ({ 
  backgroundImage, 
  brushColor, 
  brushSize, 
  pressureEnabled = false,
  tool, 
  onHistoryChange, 
  onCropComplete,
  canvasWidth,
  canvasHeight
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null); 
  const drawingCanvasRef = useRef<HTMLCanvasElement>(null); 
  const containerRef = useRef<HTMLDivElement>(null);

  const [isDrawing, setIsDrawing] = useState(false);
  const [isPanning, setIsPanning] = useState(false);
  const rainbowHueRef = useRef(0);
  const lastCoordsRef = useRef<{x: number, y: number} | null>(null);

  const [view, setView] = useState({ scale: 1, x: 0, y: 0 });

  // Crop States
  const [cropRect, setCropRect] = useState({ x: 50, y: 50, w: 300, h: 300 });
  const [dragMode, setDragMode] = useState<'none' | 'move' | number>('none');
  const [startDragCoords, setStartDragCoords] = useState({ x: 0, y: 0 });
  const [initialView, setInitialView] = useState({ scale: 1, x: 0, y: 0 });
  const [initialCropRect, setInitialCropRect] = useState({ x: 50, y: 50, w: 300, h: 300 });

  const historyRef = useRef<ImageData[]>([]);
  const historyIndexRef = useRef<number>(-1);

  const updateHistoryStatus = useCallback(() => {
    if (onHistoryChange) {
      onHistoryChange(
        historyIndexRef.current > 0,
        historyIndexRef.current < historyRef.current.length - 1
      );
    }
  }, [onHistoryChange]);

  const saveState = useCallback(() => {
    const canvas = drawingCanvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (canvas && ctx) {
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      if (historyIndexRef.current < historyRef.current.length - 1) {
        historyRef.current = historyRef.current.slice(0, historyIndexRef.current + 1);
      }
      historyRef.current.push(imageData);
      if (historyRef.current.length > MAX_HISTORY) {
        historyRef.current.shift();
      } else {
        historyIndexRef.current++;
      }
      updateHistoryStatus();
    }
  }, [updateHistoryStatus]);

  const undo = useCallback(() => {
    if (historyIndexRef.current > 0) {
      historyIndexRef.current--;
      const canvas = drawingCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (canvas && ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.putImageData(historyRef.current[historyIndexRef.current], 0, 0);
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  const redo = useCallback(() => {
    if (historyIndexRef.current < historyRef.current.length - 1) {
      historyIndexRef.current++;
      const canvas = drawingCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (canvas && ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.putImageData(historyRef.current[historyIndexRef.current], 0, 0);
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  const clearDrawing = useCallback(() => {
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.clearRect(0, 0, drawingCanvasRef.current!.width, drawingCanvasRef.current!.height);
      saveState();
    }
  }, [saveState]);

  useEffect(() => {
    if (drawingCanvasRef.current && historyRef.current.length === 0) {
      const ctx = drawingCanvasRef.current.getContext('2d');
      if (ctx) {
        const empty = ctx.getImageData(0, 0, drawingCanvasRef.current.width, drawingCanvasRef.current.height);
        historyRef.current = [empty];
        historyIndexRef.current = 0;
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  const fitToScreen = useCallback(() => {
    const parent = containerRef.current;
    if (!parent || !canvasRef.current || !drawingCanvasRef.current) return;

    const containerW = parent.clientWidth;
    const containerH = parent.clientHeight;
    const targetW = canvasWidth || containerW;
    const targetH = canvasHeight || containerH;

    const scaleToFit = Math.min(containerW / targetW, containerH / targetH) * 0.9;

    setView({
      scale: scaleToFit,
      x: (containerW - targetW * scaleToFit) / 2,
      y: (containerH - targetH * scaleToFit) / 2
    });
  }, [canvasWidth, canvasHeight]);

  const resize = useCallback(() => {
    const parent = containerRef.current;
    if (!parent || !canvasRef.current || !drawingCanvasRef.current) return;

    const containerW = parent.clientWidth;
    const containerH = parent.clientHeight;
    const targetW = canvasWidth || containerW;
    const targetH = canvasHeight || containerH;

    const temp = document.createElement('canvas');
    temp.width = drawingCanvasRef.current.width;
    temp.height = drawingCanvasRef.current.height;
    temp.getContext('2d')?.drawImage(drawingCanvasRef.current, 0, 0);

    canvasRef.current.width = targetW;
    canvasRef.current.height = targetH;
    drawingCanvasRef.current.width = targetW;
    drawingCanvasRef.current.height = targetH;

    const ctx = drawingCanvasRef.current.getContext('2d');
    if (ctx) {
      ctx.drawImage(temp, 0, 0, temp.width, temp.height, 0, 0, targetW, targetH);
    }

    if (backgroundImage) {
      const bgCtx = canvasRef.current.getContext('2d');
      if (bgCtx) {
        const img = new Image();
        img.onload = () => {
          bgCtx.clearRect(0, 0, targetW, targetH);
          const scaleFactor = Math.min(targetW / img.width, targetH / img.height);
          const x = (targetW / 2) - (img.width / 2) * scaleFactor;
          const y = (targetH / 2) - (img.height / 2) * scaleFactor;
          bgCtx.drawImage(img, x, y, img.width * scaleFactor, img.height * scaleFactor);
        };
        img.src = backgroundImage;
      }
    }

    setCropRect({ x: targetW * 0.1, y: targetH * 0.1, w: targetW * 0.8, h: targetH * 0.8 });
    fitToScreen();
  }, [backgroundImage, canvasWidth, canvasHeight, fitToScreen]);

  useEffect(() => {
    window.addEventListener('resize', resize);
    resize();
    return () => window.removeEventListener('resize', resize);
  }, [resize]);

  const getCoords = (e: React.PointerEvent) => {
    const rect = containerRef.current?.getBoundingClientRect();
    if (!rect) return { x: 0, y: 0 };

    const clientX = e.clientX;
    const clientY = e.clientY;

    const x = (clientX - rect.left - view.x) / view.scale;
    const y = (clientY - rect.top - view.y) / view.scale;

    return { x, y };
  };

  const handleInvert = useCallback(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imageData.data;
    for (let i = 0; i < data.length; i += 4) {
      data[i] = 255 - data[i];     // Red
      data[i + 1] = 255 - data[i + 1]; // Green
      data[i + 2] = 255 - data[i + 2]; // Blue
      // Alpha remains unchanged
    }
    ctx.putImageData(imageData, 0, 0);

    if (onCropComplete) {
      onCropComplete(canvas.toDataURL('image/png'));
    }
  }, [onCropComplete]);

  const applyCrop = useCallback(() => {
    if (!canvasRef.current || !drawingCanvasRef.current) return;
    const { x, y, w, h } = cropRect;
    if (w <= 5 || h <= 5) return;

    const lineArtCrop = document.createElement('canvas');
    lineArtCrop.width = w;
    lineArtCrop.height = h;
    lineArtCrop.getContext('2d')?.drawImage(canvasRef.current, x, y, w, h, 0, 0, w, h);
    const newLineArt = lineArtCrop.toDataURL('image/png');

    const drawingCrop = document.createElement('canvas');
    drawingCrop.width = w;
    drawingCrop.height = h;
    drawingCrop.getContext('2d')?.drawImage(drawingCanvasRef.current, x, y, w, h, 0, 0, w, h);

    if (onCropComplete) {
      onCropComplete(newLineArt);
      const dCtx = drawingCanvasRef.current.getContext('2d');
      if (dCtx) {
        dCtx.clearRect(0, 0, drawingCanvasRef.current.width, drawingCanvasRef.current.height);
        dCtx.drawImage(drawingCrop, 0, 0, w, h, 0, 0, drawingCanvasRef.current.width, drawingCanvasRef.current.height);
        saveState();
      }
    }
  }, [cropRect, onCropComplete, saveState]);

  const handleBucketFill = (startX: number, startY: number) => {
    const canvas = drawingCanvasRef.current;
    const bgCanvas = canvasRef.current;
    if (!canvas || !bgCanvas) return;
    const ctx = canvas.getContext('2d', { willReadFrequently: true });
    if (!ctx) return;

    const { width, height } = canvas;
    const tempCanvas = document.createElement('canvas');
    tempCanvas.width = width;
    tempCanvas.height = height;
    const tCtx = tempCanvas.getContext('2d', { willReadFrequently: true })!;
    tCtx.fillStyle = '#ffffff';
    tCtx.fillRect(0, 0, width, height);
    tCtx.drawImage(bgCanvas, 0, 0);
    tCtx.drawImage(canvas, 0, 0);

    const imgData = tCtx.getImageData(0, 0, width, height);
    const pixels = imgData.data;
    const x = Math.round(startX);
    const y = Math.round(startY);
    const pos = (y * width + x) * 4;
    const [tR, tG, tB] = [pixels[pos], pixels[pos+1], pixels[pos+2]];
    const fill = hexToRgb(brushColor);

    if (Math.abs(tR - fill.r) < 10 && Math.abs(tG - fill.g) < 10 && Math.abs(tB - fill.b) < 10) return;

    const stack = [[x, y]];
    const seen = new Uint8Array(width * height);
    const fillPixels = new Uint8Array(width * height);
    const threshold = 60;

    while (stack.length) {
      const [cx, cy] = stack.pop()!;
      if (cx < 0 || cx >= width || cy < 0 || cy >= height) continue;
      const idx = cy * width + cx;
      if (seen[idx]) continue;
      seen[idx] = 1;

      const p = idx * 4;
      if (Math.abs(pixels[p] - tR) < threshold && Math.abs(pixels[p+1] - tG) < threshold && Math.abs(pixels[p+2] - tB) < threshold) {
        fillPixels[idx] = 1;
        stack.push([cx + 1, cy], [cx - 1, cy], [cx, cy + 1], [cx, cy - 1]);
      }
    }

    const res = ctx.createImageData(width, height);
    for (let i = 0; i < width * height; i++) {
      if (fillPixels[i]) {
        const p = i * 4;
        res.data[p] = fill.r;
        res.data[p+1] = fill.g;
        res.data[p+2] = fill.b;
        res.data[p+3] = 255;
      }
    }
    const scratch = document.createElement('canvas');
    scratch.width = width;
    scratch.height = height;
    scratch.getContext('2d')?.putImageData(res, 0, 0);
    ctx.globalCompositeOperation = 'source-over';
    ctx.drawImage(scratch, 0, 0);
    saveState();
  };

  const getHandleAt = (px: number, py: number) => {
    const { x, y, w, h } = cropRect;
    const handles = [
      { x: x, y: y }, { x: x + w, y: y }, { x: x + w, y: y + h }, { x: x, y: y + h },
      { x: x + w / 2, y: y }, { x: x + w, y: y + h / 2 }, { x: x + w / 2, y: y + h }, { x: x, y: y + h / 2 }
    ];
    for (let i = 0; i < handles.length; i++) {
      if (Math.abs(px - handles[i].x) < HANDLE_SIZE && Math.abs(py - handles[i].y) < HANDLE_SIZE) return i;
    }
    return -1;
  };

  const start = (e: React.PointerEvent) => {
    const coords = getCoords(e);
    const clientX = e.clientX;
    const clientY = e.clientY;

    if (tool === ToolType.PAN) {
      setIsPanning(true);
      setStartDragCoords({ x: clientX, y: clientY });
      setInitialView({ ...view });
      return;
    }

    if (tool === ToolType.CROP) {
      const handleIdx = getHandleAt(coords.x, coords.y);
      if (handleIdx !== -1) setDragMode(handleIdx);
      else if (coords.x >= cropRect.x && coords.x <= cropRect.x + cropRect.w && coords.y >= cropRect.y && coords.y <= cropRect.y + cropRect.h) setDragMode('move');
      else return;
      setStartDragCoords({ x: coords.x, y: coords.y });
      setInitialCropRect({ ...cropRect });
      return;
    }

    if (tool === ToolType.BUCKET) return handleBucketFill(coords.x, coords.y);
    if (tool === ToolType.INVERT) return handleInvert();

    setIsDrawing(true);
    lastCoordsRef.current = coords;
  };

  const draw = (e: React.PointerEvent) => {
    const coords = getCoords(e);
    const clientX = e.clientX;
    const clientY = e.clientY;

    if (tool === ToolType.PAN && isPanning) {
      const dx = clientX - startDragCoords.x;
      const dy = clientY - startDragCoords.y;
      setView(prev => ({
        ...prev,
        x: initialView.x + dx,
        y: initialView.y + dy
      }));
      return;
    }

    if (tool === ToolType.CROP && dragMode !== 'none') {
      const dx = coords.x - startDragCoords.x;
      const dy = coords.y - startDragCoords.y;
      const newRect = { ...initialCropRect };
      if (dragMode === 'move') { newRect.x += dx; newRect.y += dy; }
      else {
        switch (dragMode) {
          case 0: newRect.x += dx; newRect.y += dy; newRect.w -= dx; newRect.h -= dy; break;
          case 1: newRect.y += dy; newRect.w += dx; newRect.h -= dy; break;
          case 2: newRect.w += dx; newRect.h += dy; break;
          case 3: newRect.x += dx; newRect.w -= dx; newRect.h += dy; break;
          case 4: newRect.y += dy; newRect.h -= dy; break;
          case 5: newRect.w += dx; break;
          case 6: newRect.h += dy; break;
          case 7: newRect.x += dx; newRect.w -= dx; break;
        }
      }
      if (newRect.w < 10) newRect.w = 10;
      if (newRect.h < 10) newRect.h = 10;
      setCropRect(newRect);
      return;
    }

    if (!isDrawing || tool === ToolType.BUCKET || tool === ToolType.INVERT || !lastCoordsRef.current) return;
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (!ctx) return;

    // Apply Pen Pressure modulation
    const pressure = (pressureEnabled && e.pressure > 0) ? e.pressure : 1.0;
    const effectiveSize = pressureEnabled ? brushSize * (0.2 + 0.8 * pressure) : brushSize;
    const effectiveAlpha = pressureEnabled ? (0.3 + 0.7 * pressure) : 1.0;

    ctx.beginPath();
    ctx.moveTo(lastCoordsRef.current.x, lastCoordsRef.current.y);
    ctx.lineTo(coords.x, coords.y);
    ctx.lineCap = 'round';
    ctx.lineJoin = 'round';
    ctx.lineWidth = effectiveSize;

    if (tool === ToolType.SPRAY) {
      ctx.fillStyle = brushColor;
      const density = (20 + brushSize / 2) * pressure;
      for (let i = 0; i < density; i++) {
        const angle = Math.random() * Math.PI * 2;
        const dist = Math.random() * effectiveSize;
        const px = coords.x + Math.cos(angle) * dist;
        const py = coords.y + Math.sin(angle) * dist;
        ctx.fillRect(px, py, 1.2, 1.2);
      }
    } else if (tool === ToolType.RAINBOW) {
      rainbowHueRef.current = (rainbowHueRef.current + 3) % 360;
      ctx.strokeStyle = `hsl(${rainbowHueRef.current}, 100%, 50%)`;
      ctx.stroke();
    } else if (tool === ToolType.CALLIGRAPHY) {
      ctx.strokeStyle = brushColor;
      ctx.globalAlpha = effectiveAlpha;
      ctx.lineCap = 'butt';
      ctx.stroke();
      ctx.globalAlpha = 1.0;
    } else {
      ctx.strokeStyle = tool === ToolType.ERASER ? '#FFFFFF' : brushColor;
      ctx.globalCompositeOperation = tool === ToolType.ERASER ? 'destination-out' : 'source-over';
      ctx.globalAlpha = tool === ToolType.HIGHLIGHTER ? 0.35 * effectiveAlpha : effectiveAlpha;
      ctx.stroke();
      ctx.globalAlpha = 1.0;
    }

    lastCoordsRef.current = coords;
  };

  const stop = () => { 
    if (isDrawing) { 
      setIsDrawing(false); 
      saveState(); 
    }
    setIsPanning(false);
    setDragMode('none');
    lastCoordsRef.current = null;
  };

  const applyZoom = useCallback((zoomFactor: number, focusX: number, focusY: number) => {
    setView(prev => {
      const nextScale = Math.min(10, Math.max(0.05, prev.scale * zoomFactor));
      const actualFactor = nextScale / prev.scale;

      return {
        scale: nextScale,
        x: focusX - (focusX - prev.x) * actualFactor,
        y: focusY - (focusY - prev.y) * actualFactor
      };
    });
  }, []);

  const handleWheel = (e: React.WheelEvent) => {
    e.preventDefault();
    const zoomIntensity = 0.001; 
    const wheel = -e.deltaY;
    const zoomFactor = Math.exp(wheel * zoomIntensity);

    const container = containerRef.current;
    if (!container) return;
    const rect = container.getBoundingClientRect();

    const mouseX = e.clientX - rect.left;
    const mouseY = e.clientY - rect.top;

    applyZoom(zoomFactor, mouseX, mouseY);
  };

  const handleZoomDiscrete = (type: 'in' | 'out') => {
    const container = containerRef.current;
    if (!container) return;
    const rect = container.getBoundingClientRect();
    const centerX = rect.width / 2;
    const centerY = rect.height / 2;
    const factor = type === 'in' ? 1.1 : 0.9; 
    applyZoom(factor, centerX, centerY);
  };

  const resetZoomTo100 = () => {
    const parent = containerRef.current;
    if (!parent) return;
    const containerW = parent.clientWidth;
    const containerH = parent.clientHeight;
    const targetW = canvasWidth || containerW;
    const targetH = canvasHeight || containerH;
    setView({
      scale: 1.0,
      x: (containerW - targetW) / 2,
      y: (containerH - targetH) / 2
    });
  };

  const getCombined = () => {
    if (!canvasRef.current || !drawingCanvasRef.current) return '';
    const final = document.createElement('canvas');
    final.width = canvasRef.current.width;
    final.height = canvasRef.current.height;
    const ctx = final.getContext('2d')!;
    ctx.fillStyle = '#ffffff';
    ctx.fillRect(0, 0, final.width, final.height);
    ctx.drawImage(drawingCanvasRef.current, 0, 0);
    ctx.globalCompositeOperation = 'multiply';
    ctx.drawImage(canvasRef.current, 0, 0);
    return final.toDataURL('image/png');
  };

  useEffect(() => {
    (window as any).clearCanvas = clearDrawing;
    (window as any).getCombinedImage = getCombined;
    (window as any).undo = undo;
    (window as any).redo = redo;
    (window as any).applyCrop = applyCrop;
    (window as any).invertLineArt = handleInvert;
  }, [clearDrawing, undo, redo, applyCrop, backgroundImage, brushColor, brushSize, tool, handleInvert]);

  return (
    <div 
      ref={containerRef}
      className="relative w-full h-full bg-slate-200 rounded-3xl shadow-inner overflow-hidden border-4 border-white group"
      onWheel={handleWheel}
    >
      <div className="absolute inset-0 bg-[radial-gradient(#CBD5E1_1px,transparent_1px)] [background-size:20px_20px] opacity-30" />

      <div 
        className="absolute origin-top-left will-change-transform"
        style={{ 
          transform: `translate(${view.x}px, ${view.y}px) scale(${view.scale})`,
          width: canvasWidth,
          height: canvasHeight
        }}
      >
        <div className="absolute inset-0 shadow-2xl bg-white ring-1 ring-slate-300" />
        <canvas
          ref={drawingCanvasRef}
          onPointerDown={start}
          onPointerMove={draw}
          onPointerUp={stop}
          onPointerLeave={stop}
          className={`absolute inset-0 touch-none ${tool === ToolType.PAN ? (isPanning ? 'cursor-grabbing' : 'cursor-grab') : (tool === ToolType.CROP ? 'cursor-default' : 'cursor-crosshair')}`}
        />
        <canvas ref={canvasRef} className="absolute inset-0 pointer-events-none mix-blend-multiply" />
      </div>

      <div className="absolute top-6 left-6 flex flex-col gap-2 pointer-events-none">
         <div className="px-4 py-2 bg-black/80 backdrop-blur-md text-white text-[10px] font-black rounded-full shadow-lg border border-white/10 uppercase tracking-widest flex items-center gap-2">
            <MoveDiagonal2 className="w-3 h-3" />
            {canvasWidth} x {canvasHeight} | {Math.round(view.scale * 100)}%
         </div>
      </div>

      <div className="absolute bottom-6 right-6 flex flex-col gap-2 p-1.5 bg-white/90 backdrop-blur-xl rounded-[2rem] border border-slate-200 shadow-2xl opacity-0 group-hover:opacity-100 transition-all scale-90 group-hover:scale-100">
        <button onClick={() => handleZoomDiscrete('in')} className="p-4 hover:bg-slate-50 text-slate-600 rounded-full transition-all" title="Zoom In (10%)"><ZoomIn className="w-5 h-5" /></button>
        <div className="h-[1px] bg-slate-100 mx-3" />
        <button onClick={() => handleZoomDiscrete('out')} className="p-4 hover:bg-slate-50 text-slate-600 rounded-full transition-all" title="Zoom Out (10%)"><ZoomOut className="w-5 h-5" /></button>
        <div className="h-[1px] bg-slate-100 mx-3" />
        <button onClick={resetZoomTo100} className="p-4 hover:bg-slate-50 text-indigo-600 rounded-full transition-all" title="Reset Zoom (100%)"><RotateCcw className="w-5 h-5" /></button>
        <div className="h-[1px] bg-slate-100 mx-3" />
        <button onClick={fitToScreen} className="p-4 hover:bg-indigo-600 hover:text-white text-slate-400 rounded-full transition-all" title="Fit to Screen"><Maximize className="w-5 h-5" /></button>
      </div>

      {tool === ToolType.CROP && (
        <div className="absolute inset-0 pointer-events-none">
          <div className="absolute border-2 border-white shadow-[0_0_0_1px_rgba(0,0,0,0.5)] pointer-events-auto" style={{ left: cropRect.x, top: cropRect.y, width: cropRect.w, height: cropRect.h }}>
          </div>
        </div>
      )}

      {tool === ToolType.PAN && !isPanning && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none bg-black/50 backdrop-blur-sm text-white px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3">
          <Hand className="w-4 h-4 animate-bounce" /> Drag to explore canvas
        </div>
      )}

      {tool === ToolType.INVERT && (
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none bg-black/50 backdrop-blur-sm text-white px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest flex items-center gap-3">
          <Contrast className="w-4 h-4 animate-pulse" /> Click to invert line art
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { 
  Plus, 
  Upload, 
  Printer, 
  RotateCcw, 
  Eraser, 
  Paintbrush, 
  Sparkles, 
  Download,
  Camera,
  Loader2,
  Trash2,
  Wand2,
  Image as ImageIcon,
  Undo,
  Redo,
  PaintBucket,
  Crop,
  Check,
  ChevronRight,
  ShieldCheck,
  Settings2,
  Maximize2,
  Type,
  PenTool,
  Wind,
  Highlighter,
  Hand,
  Trophy,
  Shapes,
  Image as RasterIcon,
  Link,
  Link2Off,
  MoveDiagonal2,
  Zap,
  Contrast
} from 'lucide-react';
import { ColorPicker } from './components/ColorPicker';
import { Editor } from './components/Editor';
import { CameraModal } from './components/CameraModal';
import { StylePresets } from './components/StylePresets';
import { convertToLineArt, editWithAI, upscaleToStudioMaster, ColoringStyle, ImageResolution, OutputFormat } from './services/geminiService';
import { ToolType } from './types';

const BRUSH_PRESETS = [
  { label: 'XS', size: 2 },
  { label: 'S', size: 5 },
  { label: 'M', size: 10 },
  { label: 'L', size: 25 },
  { label: 'XL', size: 50 },
];

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [brushColor, setBrushColor] = useState('#FF0000');
  const [brushSize, setBrushSize] = useState(10);
  const [pressureEnabled, setPressureEnabled] = useState(false);
  const [activeTool, setActiveTool] = useState<ToolType>(ToolType.BRUSH);
  const [aiPrompt, setAiPrompt] = useState('');
  const [showCamera, setShowCamera] = useState(false);
  const [canUndo, setCanUndo] = useState(false);
  const [canRedo, setCanRedo] = useState(false);

  const [isProMode, setIsProMode] = useState(false);
  const [resolution, setResolution] = useState<ImageResolution>('1K');
  const [outputFormat, setOutputFormat] = useState<OutputFormat>('raster');

  // Canvas Dimension State
  const [canvasWidth, setCanvasWidth] = useState<number>(1024);
  const [canvasHeight, setCanvasHeight] = useState<number>(1024);
  const [aspectRatioLocked, setAspectRatioLocked] = useState(true);
  const [ratio, setRatio] = useState(1);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    setRatio(canvasWidth / canvasHeight);
  }, []);

  const handleWidthChange = (val: number) => {
    setCanvasWidth(val);
    if (aspectRatioLocked) {
      setCanvasHeight(Math.round(val / ratio));
    }
  };

  const handleHeightChange = (val: number) => {
    setCanvasHeight(val);
    if (aspectRatioLocked) {
      setCanvasWidth(Math.round(val * ratio));
    }
  };

  const toggleLock = () => {
    if (!aspectRatioLocked) {
      setRatio(canvasWidth / canvasHeight);
    }
    setAspectRatioLocked(!aspectRatioLocked);
  };

  const checkProPermissions = async () => {
    try {
      const hasKey = await (window as any).aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await (window as any).aistudio.openSelectKey();
      }
      return true;
    } catch (e) {
      console.error("Key selection failed", e);
      return false;
    }
  };

  const toggleProMode = async () => {
    if (!isProMode) {
      const success = await checkProPermissions();
      if (success) setIsProMode(true);
    } else {
      setIsProMode(false);
      setResolution('1K');
      setOutputFormat('raster');
    }
  };

  const handleFormatChange = async (fmt: OutputFormat) => {
    if (fmt === 'vector' && !isProMode) {
      const success = await checkProPermissions();
      if (success) {
        setIsProMode(true);
        setOutputFormat(fmt);
      }
    } else {
      setOutputFormat(fmt);
    }
  };

  const handleResolutionChange = async (res: ImageResolution) => {
    if (res !== '1K' && !isProMode) {
      const success = await checkProPermissions();
      if (success) {
        setIsProMode(true);
        setResolution(res);
      }
    } else {
      setResolution(res);
    }
  };

  const processImage = async (base64: string, style: ColoringStyle = 'standard') => {
    if ((resolution === '2K' || resolution === '4K') && !isProMode) {
       const success = await checkProPermissions();
       if (!success) return;
       setIsProMode(true);
    }

    setIsProcessing(true);
    try {
      const lineArt = await convertToLineArt(base64, style, resolution, outputFormat, isProMode);
      setImage(lineArt);
    } catch (error: any) {
      console.error("Processing failed", error);
      alert("Processing error. Ensure the image is clear.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleMasterUpscale = async () => {
    const data = (window as any).getCombinedImage?.();
    if (!data) return;

    setIsProcessing(true);
    try {
      const mastered = await upscaleToStudioMaster(data);
      setImage(mastered);
      setResolution('4K');
      setIsProMode(true);
      setOutputFormat('raster');
    } catch (error) {
      console.error("Master upscale failed", error);
      alert("Upscaling failed.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result as string;
      await processImage(base64);
    };
    reader.readAsDataURL(file);
  };

  const handleAIEdit = async () => {
    if (!image || !aiPrompt) return;
    setIsProcessing(true);
    try {
      const edited = await editWithAI(image, aiPrompt, isProMode);
      setImage(edited);
      setAiPrompt('');
    } catch (error) {
      alert("AI was unable to process that request.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handlePrint = () => {
    const combined = (window as any).getCombinedImage?.();
    if (!combined) return;
    const printWindow = window.open('', '_blank');
    if (printWindow) {
      printWindow.document.write(`<html><body style="margin:0;display:flex;justify-content:center;align-items:center;height:100vh;"><img src="${combined}" style="max-width:100%;max-height:100%;object-fit:contain;" /><script>window.onload=()=>window.print();</script></body></html>`);
      printWindow.document.close();
    }
  };

  const handleDownload = (onlyLineArt = false) => {
    const data = onlyLineArt ? (window as any).getLineArtOnly?.() : (window as any).getCombinedImage?.();
    if (!data) return;
    const extension = data.includes('svg+xml') ? 'svg' : 'png';
    const linkObj = document.createElement('a');
    linkObj.href = data;
    linkObj.download = `chromasketch-${outputFormat}-${resolution}-${Date.now()}.${extension}`;
    linkObj.click();
  };

  const handleCropComplete = (newImageData: string) => {
    setImage(newImageData);
    setActiveTool(ToolType.BRUSH);
  };

  const applyStylePreset = (color: string, size: number, tool: ToolType) => {
    setBrushColor(color);
    setBrushSize(size);
    setActiveTool(tool);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-900 overflow-hidden font-sans">
      {showCamera && (
        <CameraModal 
          onCapture={(base64, style) => { setShowCamera(false); processImage(base64, style); }} 
          onClose={() => setShowCamera(false)} 
        />
      )}

      <header className="bg-white border-b border-slate-200 px-6 py-4 flex justify-between items-center shrink-0 shadow-sm z-20">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2.5 rounded-2xl shadow-lg shadow-indigo-100">
              <Sparkles className="text-white w-6 h-6" />
            </div>
            <div>
              <h1 className="text-xl font-extrabold tracking-tight text-slate-800">ChromaSketch AI</h1>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Digital Arts Studio</p>
            </div>
          </div>

          <div className="hidden lg:flex items-center gap-2 bg-slate-50 p-1.5 rounded-2xl border border-slate-200">
            <button 
              onClick={toggleProMode}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl transition-all font-black text-xs uppercase tracking-wider ${isProMode ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-white'}`}
            >
              <ShieldCheck className={`w-4 h-4 ${isProMode ? 'animate-pulse' : ''}`} />
              Studio Pro
            </button>

            <div className="w-[1px] h-4 bg-slate-200 mx-1" />

            <div className="flex bg-slate-100 p-0.5 rounded-xl">
              <button
                onClick={() => handleFormatChange('raster')}
                className={`px-3 py-1.5 rounded-lg flex items-center gap-2 text-[10px] font-black transition-all ${outputFormat === 'raster' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}
              >
                <RasterIcon className="w-3 h-3" /> PNG
              </button>
              <button
                onClick={() => handleFormatChange('vector')}
                className={`px-3 py-1.5 rounded-lg flex items-center gap-2 text-[10px] font-black transition-all ${outputFormat === 'vector' ? 'bg-indigo-600 text-white shadow-sm' : 'text-slate-400'}`}
              >
                <Shapes className="w-3 h-3" /> SVG
              </button>
            </div>

            {outputFormat === 'raster' && (
              <>
                <div className="w-[1px] h-4 bg-slate-200 mx-1" />
                {(['1K', '2K', '4K'] as ImageResolution[]).map(res => (
                  <button
                    key={res}
                    onClick={() => handleResolutionChange(res)}
                    className={`px-3 py-2 rounded-xl text-[10px] font-black transition-all ${resolution === res ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    {res}
                  </button>
                ))}
              </>
            )}
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button onClick={() => setShowCamera(true)} className="flex items-center gap-2 px-4 py-2 hover:bg-slate-50 text-slate-600 rounded-lg transition-all font-semibold"><Camera className="w-4 h-4" /> Camera</button>
          <button onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 px-4 py-2 bg-white text-indigo-600 rounded-lg shadow-sm hover:shadow-md transition-all font-bold border border-indigo-50"><Upload className="w-4 h-4" /> Upload</button>
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <aside className="w-80 bg-white border-r border-slate-200 p-6 flex flex-col gap-6 shrink-0 overflow-y-auto shadow-sm z-10 custom-scrollbar">
          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 text-center border-b pb-2 border-slate-50">Studio Palette</h3>
            <ColorPicker currentColor={brushColor} onChange={setBrushColor} />
          </section>

          <section className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Line Weight</h3>
              <div className="flex items-center gap-1.5">
                <input 
                  type="number" 
                  min="1" 
                  max="100" 
                  value={brushSize} 
                  onChange={(e) => setBrushSize(Math.min(100, Math.max(1, parseInt(e.target.value) || 1)))}
                  className="w-12 bg-white border border-slate-200 rounded px-1.5 py-0.5 text-[10px] font-black text-indigo-600 text-center focus:ring-1 focus:ring-indigo-400 outline-none"
                />
                <span className="text-[8px] font-black text-slate-400 uppercase">px</span>
              </div>
            </div>

            <input 
              type="range" 
              min="1" 
              max="100" 
              step="1"
              value={brushSize} 
              onChange={(e) => setBrushSize(parseInt(e.target.value))} 
              className="w-full h-1.5 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600 mb-4" 
            />

            <div className="flex justify-between gap-1.5 mb-4">
              {BRUSH_PRESETS.map((preset) => (
                <button
                  key={preset.label}
                  onClick={() => setBrushSize(preset.size)}
                  className={`flex-1 py-1.5 rounded-lg text-[9px] font-black transition-all ${
                    brushSize === preset.size 
                    ? 'bg-indigo-600 text-white shadow-md' 
                    : 'bg-white text-slate-400 hover:text-slate-600 border border-slate-100'
                  }`}
                >
                  {preset.label}
                </button>
              ))}
            </div>

            <button 
              onClick={() => setPressureEnabled(!pressureEnabled)}
              className={`w-full flex items-center justify-between p-2 rounded-xl border transition-all ${pressureEnabled ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg' : 'bg-white border-slate-100 text-slate-500 hover:bg-slate-50'}`}
            >
              <div className="flex items-center gap-2">
                <Zap className={`w-3.5 h-3.5 ${pressureEnabled ? 'fill-yellow-300 text-yellow-300' : 'text-slate-300'}`} />
                <span className="text-[10px] font-black uppercase tracking-wider">Pressure Sensitivity</span>
              </div>
              <div className={`w-8 h-4 rounded-full relative transition-colors ${pressureEnabled ? 'bg-indigo-400' : 'bg-slate-200'}`}>
                <div className={`absolute top-0.5 w-3 h-3 bg-white rounded-full transition-all shadow-sm ${pressureEnabled ? 'left-4.5' : 'left-0.5'}`} />
              </div>
            </button>
          </section>

          <section className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 flex justify-between items-center">
              Canvas Dimensions
              <button onClick={toggleLock} className={`p-1 rounded ${aspectRatioLocked ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-200 text-slate-500'}`}>
                {aspectRatioLocked ? <Link className="w-3 h-3" /> : <Link2Off className="w-3 h-3" />}
              </button>
            </h3>
            <div className="flex flex-col gap-3">
              <div className="flex items-center gap-2">
                <span className="text-[10px] font-bold text-slate-400 w-4">W</span>
                <input 
                  type="number" 
                  value={canvasWidth} 
                  onChange={(e) => handleWidthChange(parseInt(e.target.value) || 0)}
                  className="flex-1 bg-white border border-slate-200 rounded-lg px-3 py-1.5 text-xs font-mono"
                />
              </div>
              <div className="flex items-center gap-2">
                <span className="text-[10px] font-bold text-slate-400 w-4">H</span>
                <input 
                  type="number" 
                  value={canvasHeight} 
                  onChange={(e) => handleHeightChange(parseInt(e.target.value) || 0)}
                  className="flex-1 bg-white border border-slate-200 rounded-lg px-3 py-1.5 text-xs font-mono"
                />
              </div>
            </div>
          </section>

          <section>
            <StylePresets 
              currentColor={brushColor}
              currentSize={brushSize}
              currentTool={activeTool}
              onApplyPreset={applyStylePreset}
            />
          </section>

          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">Precision Tools</h3>
            <div className="grid grid-cols-2 gap-2">
              {[
                { id: ToolType.BRUSH, icon: Paintbrush, label: 'Brush' },
                { id: ToolType.PAN, icon: Hand, label: 'Pan/View' },
                { id: ToolType.HIGHLIGHTER, icon: Highlighter, label: 'Marker' },
                { id: ToolType.SPRAY, icon: Wind, label: 'Spray' },
                { id: ToolType.CALLIGRAPHY, icon: PenTool, label: 'Chisel' },
                { id: ToolType.RAINBOW, icon: Sparkles, label: 'Rainbow' },
                { id: ToolType.BUCKET, icon: PaintBucket, label: 'Fill' },
                { id: ToolType.ERASER, icon: Eraser, label: 'Eraser' },
                { id: ToolType.CROP, icon: Crop, label: 'Crop' },
                { id: ToolType.INVERT, icon: Contrast, label: 'Invert' }
              ].map(t => (
                <button 
                  key={t.id} 
                  onClick={() => setActiveTool(t.id)} 
                  className={`flex items-center gap-3 p-3 rounded-xl border-2 transition-all ${activeTool === t.id ? 'border-indigo-600 bg-indigo-50 text-indigo-700 font-bold' : 'border-slate-50 text-slate-500 hover:border-slate-200'}`}
                >
                  <t.icon className="w-4 h-4" />
                  <span className="text-[10px] font-black uppercase">{t.label}</span>
                </button>
              ))}
            </div>
          </section>

          <section className="mt-auto">
            {image && (
              <button 
                onClick={handleMasterUpscale}
                className="w-full mb-4 group relative flex items-center justify-center gap-3 p-4 bg-gradient-to-r from-indigo-600 to-purple-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg hover:scale-[1.02] active:scale-95 transition-all overflow-hidden"
              >
                <div className="absolute inset-0 bg-white/20 translate-x-[-100%] group-hover:translate-x-[100%] transition-transform duration-700 skew-x-12" />
                <Trophy className="w-4 h-4 text-yellow-300" />
                Master 4K Reconstruction
              </button>
            )}
            <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
              <h3 className="text-xs font-bold text-indigo-600 uppercase mb-3 flex items-center gap-2">
                < Wand2 className="w-3 h-3" /> AI Stylist
              </h3>
              <textarea
                placeholder="E.g. Add complex floral motifs..."
                value={aiPrompt}
                onChange={(e) => setAiPrompt(e.target.value)}
                className="w-full text-xs p-3 rounded-xl bg-white border border-slate-200 h-20 resize-none outline-none focus:ring-2 focus:ring-indigo-500 shadow-inner"
              />
              <button disabled={!image || isProcessing || !aiPrompt} onClick={handleAIEdit} className="mt-3 w-full bg-indigo-600 text-white p-2.5 rounded-xl text-xs font-bold flex items-center justify-center gap-2 disabled:opacity-30 hover:bg-indigo-700 transition-all">
                {isProcessing ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : <Sparkles className="w-3.5 h-3.5" />} 
                Transform Page
              </button>
            </div>
          </section>
        </aside>

        <section className="flex-1 flex flex-col p-8 relative overflow-hidden bg-slate-100/50">
          <div className="flex-1 relative">
            {isProcessing && (
              <div className="absolute inset-0 z-[100] flex items-center justify-center bg-white/60 backdrop-blur-md rounded-3xl">
                <div className="bg-white p-12 rounded-[2.5rem] shadow-2xl flex flex-col items-center gap-8 border border-slate-100 max-w-sm text-center">
                  <div className="relative">
                    <div className="w-24 h-24 border-[6px] border-slate-50 border-t-indigo-600 rounded-full animate-spin" />
                    <Sparkles className="w-10 h-10 text-indigo-500 absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 animate-pulse" />
                  </div>
                  <div>
                    <h4 className="text-2xl font-black text-slate-800 mb-2">
                      {outputFormat === 'vector' ? 'Tracing Vector Map...' : 'Rendering Canvas...'}
                    </h4>
                    <p className="text-slate-400 font-medium">Gemini 3 Pro is refining your artwork for {resolution} output.</p>
                  </div>
                </div>
              </div>
            )}

            {!image ? (
              <div className="h-full border-4 border-dashed border-slate-200 rounded-[2.5rem] flex flex-col items-center justify-center bg-white gap-8 text-center px-16 group transition-all hover:border-indigo-100 hover:bg-slate-50/50">
                <div className="w-32 h-32 bg-indigo-50 text-indigo-600 rounded-[2.5rem] flex items-center justify-center transform group-hover:rotate-6 transition-transform shadow-xl">
                  <ImageIcon className="w-16 h-16" />
                </div>
                <div>
                  <h2 className="text-4xl font-black text-slate-800 mb-4 tracking-tight">Pro Illustration Studio</h2>
                  <p className="text-slate-400 max-w-md font-medium leading-relaxed">Infinitely scalable vector art from your photos. Perfect for professional coloring books and large-scale printing.</p>
                </div>
                <div className="flex gap-4">
                  <button onClick={() => setShowCamera(true)} className="bg-indigo-600 text-white px-10 py-4 rounded-2xl font-black text-lg hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 flex items-center gap-3 transform hover:-translate-y-1 active:scale-95"><Camera className="w-6 h-6" /> Camera</button>
                  <button onClick={() => fileInputRef.current?.click()} className="bg-white text-indigo-600 border-2 border-indigo-600 px-10 py-4 rounded-2xl font-black text-lg hover:bg-indigo-50 transition-all flex items-center gap-3 transform hover:-translate-y-1 active:scale-95"><Upload className="w-6 h-6" /> Upload</button>
                </div>
              </div>
            ) : (
              <Editor 
                backgroundImage={image} 
                brushColor={brushColor} 
                brushSize={brushSize} 
                pressureEnabled={pressureEnabled}
                tool={activeTool}
                onHistoryChange={(u, r) => { setCanUndo(u); setCanRedo(r); }}
                onCropComplete={handleCropComplete}
                canvasWidth={canvasWidth}
                canvasHeight={canvasHeight}
              />
            )}
          </div>

          {image && (
            <div className="mt-8 flex justify-between items-center bg-white p-4 rounded-3xl border border-slate-200 shadow-xl z-20">
              <div className="flex gap-2">
                <button onClick={() => (window as any).undo?.()} disabled={!canUndo} className={`p-3 rounded-2xl transition-all ${canUndo ? 'text-indigo-600 bg-indigo-50 hover:bg-indigo-100 shadow-sm' : 'text-slate-200'}`} title="Undo Strokes"><Undo className="w-5 h-5" /></button>
                <button onClick={() => (window as any).redo?.()} disabled={!canRedo} className={`p-3 rounded-2xl transition-all ${canRedo ? 'text-indigo-600 bg-indigo-50 hover:bg-indigo-100 shadow-sm' : 'text-slate-200'}`} title="Redo Strokes"><Redo className="w-5 h-5" /></button>
                <div className="w-[1px] h-8 bg-slate-100 mx-1 self-center" />
                <button onClick={() => (window as any).clearCanvas?.()} className="p-3 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-2xl transition-all flex items-center gap-2" title="Reset Colors"><RotateCcw className="w-4 h-4" /><span className="text-[10px] font-black uppercase">Clear</span></button>
              </div>
              <div className="flex gap-4">
                <button onClick={() => handleDownload(false)} className="px-8 py-3 bg-slate-50 text-slate-600 border border-slate-200 rounded-2xl font-black text-sm hover:bg-white transition-all flex items-center gap-2">
                  <Download className="w-4 h-4" /> Save {outputFormat.toUpperCase()}
                </button>
                <button onClick={handlePrint} className="flex items-center gap-3 px-10 py-3 bg-indigo-600 text-white font-black text-sm rounded-2xl hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 active:scale-95"><Printer className="w-5 h-5" /> Print Project</button>
              </div>
            </div>
          )}
        </section>
      </main>

      <footer className="bg-white border-t border-slate-100 px-8 py-3 text-[10px] text-slate-300 font-bold uppercase tracking-widest flex justify-between shrink-0">
        <div className="flex gap-4 items-center">
          <span>© 2025 ChromaSketch Studio</span>
          {isProMode && <span className="text-indigo-500 flex items-center gap-1"><ShieldCheck className="w-3 h-3" /> Professional Vector Engine Active</span>}
        </div>
        <div className="flex gap-8 items-center">
          <span>Output: {outputFormat === 'vector' ? 'Scalable SVG' : `Raster ${resolution}`}</span>
          <span className="text-slate-200">|</span>
          <span>Zoom: Pan Supported (800% Precision)</span>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Save, Trash2, Plus, Bookmark, PenTool, Highlighter, Wind, Sparkles, PaintBucket, Eraser, Hand, Crop, Contrast } from 'lucide-react';
import { ToolType } from '../types';

interface StylePreset {
  id: string;
  name: string;
  color: string;
  size: number;
  tool: ToolType;
}

interface StylePresetsProps {
  currentColor: string;
  currentSize: number;
  currentTool: ToolType;
  onApplyPreset: (color: string, size: number, tool: ToolType) => void;
}

const TOOL_ICONS: Record<ToolType, any> = {
  [ToolType.BRUSH]: PenTool,
  [ToolType.HIGHLIGHTER]: Highlighter,
  [ToolType.SPRAY]: Wind,
  [ToolType.CALLIGRAPHY]: PenTool,
  [ToolType.RAINBOW]: Sparkles,
  [ToolType.BUCKET]: PaintBucket,
  [ToolType.ERASER]: Eraser,
  [ToolType.PAN]: Hand,
  [ToolType.CROP]: Crop,
  [ToolType.INVERT]: Contrast,
};

export const StylePresets: React.FC<StylePresetsProps> = ({
  currentColor,
  currentSize,
  currentTool,
  onApplyPreset,
}) => {
  const [presets, setPresets] = useState<StylePreset[]>([]);
  const [newPresetName, setNewPresetName] = useState('');
  const [isAdding, setIsAdding] = useState(false);

  // Load presets from localStorage
  useEffect(() => {
    const saved = localStorage.getItem('chromasketch_presets');
    if (saved) {
      try {
        setPresets(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load presets", e);
      }
    }
  }, []);

  // Save presets to localStorage
  useEffect(() => {
    localStorage.setItem('chromasketch_presets', JSON.stringify(presets));
  }, [presets]);

  const handleSavePreset = () => {
    if (!newPresetName.trim()) return;

    const newPreset: StylePreset = {
      id: Date.now().toString(),
      name: newPresetName.trim(),
      color: currentColor,
      size: currentSize,
      tool: currentTool,
    };

    setPresets([newPreset, ...presets]);
    setNewPresetName('');
    setIsAdding(false);
  };

  const handleDeletePreset = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    setPresets(presets.filter(p => p.id !== id));
  };

  return (
    <div className="flex flex-col gap-4">
      <div className="flex items-center justify-between">
        <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Style Library</h3>
        <button 
          onClick={() => setIsAdding(!isAdding)}
          className={`p-1.5 rounded-lg transition-all ${isAdding ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-500 hover:bg-slate-200'}`}
        >
          {isAdding ? <Bookmark className="w-3 h-3" /> : <Plus className="w-3.5 h-3.5" />}
        </button>
      </div>

      {isAdding && (
        <div className="bg-slate-50 p-3 rounded-xl border border-slate-200 animate-in fade-in slide-in-from-top-2">
          <input
            type="text"
            placeholder="Preset name..."
            value={newPresetName}
            onChange={(e) => setNewPresetName(e.target.value)}
            className="w-full text-xs p-2 rounded-lg bg-white border border-slate-200 outline-none focus:ring-2 focus:ring-indigo-500 mb-2"
            autoFocus
            onKeyDown={(e) => e.key === 'Enter' && handleSavePreset()}
          />
          <div className="flex gap-2">
            <button 
              onClick={handleSavePreset}
              className="flex-1 bg-indigo-600 text-white py-1.5 rounded-lg text-[10px] font-black uppercase tracking-wider flex items-center justify-center gap-1.5"
            >
              <Save className="w-3 h-3" /> Save Current
            </button>
            <button 
              onClick={() => setIsAdding(false)}
              className="px-3 py-1.5 bg-slate-200 text-slate-600 rounded-lg text-[10px] font-black uppercase tracking-wider"
            >
              Cancel
            </button>
          </div>
        </div>
      )}

      <div className="grid grid-cols-1 gap-2 max-h-[160px] overflow-y-auto pr-1 custom-scrollbar">
        {presets.length === 0 && !isAdding && (
          <div className="text-[10px] text-slate-400 italic text-center py-4 bg-slate-50/50 rounded-xl border border-dashed border-slate-200">
            No saved styles yet
          </div>
        )}
        {presets.map((preset) => {
          const ToolIcon = TOOL_ICONS[preset.tool] || PenTool;
          return (
            <button
              key={preset.id}
              onClick={() => onApplyPreset(preset.color, preset.size, preset.tool)}
              className="group flex items-center gap-3 p-2 bg-white border border-slate-100 rounded-xl hover:border-indigo-300 hover:shadow-sm transition-all text-left"
            >
              <div className="relative">
                <div 
                  className="w-8 h-8 rounded-lg shadow-inner border border-slate-100"
                  style={{ backgroundColor: preset.color }}
                />
                <div className="absolute -bottom-1 -right-1 bg-white p-0.5 rounded shadow-sm border border-slate-100">
                  <ToolIcon className="w-2.5 h-2.5 text-slate-600" />
                </div>
              </div>
              <div className="flex-1 min-w-0">
                <div className="text-[10px] font-black text-slate-700 uppercase truncate">{preset.name}</div>
                <div className="text-[9px] text-slate-400 font-bold">{preset.size}px • {preset.tool.toLowerCase()}</div>
              </div>
              <button 
                onClick={(e) => handleDeletePreset(preset.id, e)}
                className="opacity-0 group-hover:opacity-100 p-1.5 text-slate-300 hover:text-red-500 transition-all"
              >
                <Trash2 className="w-3 h-3" />
              </button>
            </button>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { 
  Plus, 
  Upload, 
  Printer, 
  RotateCcw, 
  Eraser, 
  Paintbrush, 
  Sparkles, 
  Download,
  Camera,
  Loader2,
  Trash2,
  Wand2,
  Image as ImageIcon,
  Undo,
  Redo,
  PaintBucket,
  Crop,
  Check,
  ChevronRight,
  ShieldCheck,
  Settings2,
  Maximize2,
  Type,
  PenTool,
  Wind,
  Highlighter,
  Hand,
  Trophy,
  Shapes,
  Image as RasterIcon,
  Link,
  Link2Off,
  MoveDiagonal2,
  Zap,
  Contrast,
  Minus
} from 'lucide-react';
import { ColorPicker } from './components/ColorPicker';
import { Editor } from './components/Editor';
import { CameraModal } from './components/CameraModal';
import { StylePresets } from './components/StylePresets';
import { convertToLineArt, editWithAI, upscaleToStudioMaster, ColoringStyle, ImageResolution, OutputFormat } from './services/geminiService';
import { ToolType } from './types';

const BRUSH_PRESETS = [
  { label: 'Fine', size: 1 },
  { label: 'Thin', size: 4 },
  { label: 'Mid', size: 12 },
  { label: 'Bold', size: 32 },
  { label: 'Max', size: 80 },
];

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [brushColor, setBrushColor] = useState('#FF0000');
  const [brushSize, setBrushSize] = useState(10);
  const [pressureEnabled, setPressureEnabled] = useState(false);
  const [activeTool, setActiveTool] = useState<ToolType>(ToolType.BRUSH);
  const [aiPrompt, setAiPrompt] = useState('');
  const [showCamera, setShowCamera] = useState(false);
  const [canUndo, setCanUndo] = useState(false);
  const [canRedo, setCanRedo] = useState(false);

  const [isProMode, setIsProMode] = useState(false);
  const [resolution, setResolution] = useState<ImageResolution>('1K');
  const [outputFormat, setOutputFormat] = useState<OutputFormat>('raster');

  // Canvas Dimension State
  const [canvasWidth, setCanvasWidth] = useState<number>(1024);
  const [canvasHeight, setCanvasHeight] = useState<number>(1024);
  const [aspectRatioLocked, setAspectRatioLocked] = useState(true);
  const [ratio, setRatio] = useState(1);

  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    setRatio(canvasWidth / canvasHeight);
  }, []);

  const handleWidthChange = (val: number) => {
    setCanvasWidth(val);
    if (aspectRatioLocked) {
      setCanvasHeight(Math.round(val / ratio));
    }
  };

  const handleHeightChange = (val: number) => {
    setCanvasHeight(val);
    if (aspectRatioLocked) {
      setCanvasWidth(Math.round(val * ratio));
    }
  };

  const toggleLock = () => {
    if (!aspectRatioLocked) {
      setRatio(canvasWidth / canvasHeight);
    }
    setAspectRatioLocked(!aspectRatioLocked);
  };

  const checkProPermissions = async () => {
    try {
      const hasKey = await (window as any).aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await (window as any).aistudio.openSelectKey();
      }
      return true;
    } catch (e) {
      console.error("Key selection failed", e);
      return false;
    }
  };

  const toggleProMode = async () => {
    if (!isProMode) {
      const success = await checkProPermissions();
      if (success) setIsProMode(true);
    } else {
      setIsProMode(false);
      setResolution('1K');
      setOutputFormat('raster');
    }
  };

  const handleFormatChange = async (fmt: OutputFormat) => {
    if (fmt === 'vector' && !isProMode) {
      const success = await checkProPermissions();
      if (success) {
        setIsProMode(true);
        setOutputFormat(fmt);
      }
    } else {
      setOutputFormat(fmt);
    }
  };

  const handleResolutionChange = async (res: ImageResolution) => {
    if (res !== '1K' && !isProMode) {
      const success = await checkProPermissions();
      if (success) {
        setIsProMode(true);
        setResolution(res);
      }
    } else {
      setResolution(res);
    }
  };

  const processImage = async (base64: string, style: ColoringStyle = 'standard') => {
    if ((resolution === '2K' || resolution === '4K') && !isProMode) {
       const success = await checkProPermissions();
       if (!success) return;
       setIsProMode(true);
    }

    setIsProcessing(true);
    try {
      const lineArt = await convertToLineArt(base64, style, resolution, outputFormat, isProMode);
      setImage(lineArt);
    } catch (error: any) {
      console.error("Processing failed", error);
      alert("Processing error. Ensure the image is clear.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleMasterUpscale = async () => {
    const data = (window as any).getCombinedImage?.();
    if (!data) return;

    setIsProcessing(true);
    try {
      const mastered = await upscaleToStudioMaster(data);
      setImage(mastered);
      setResolution('4K');
      setIsProMode(true);
      setOutputFormat('raster');
    } catch (error) {
      console.error("Master upscale failed", error);
      alert("Upscaling failed.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = async (event) => {
      const base64 = event.target?.result as string;
      await processImage(base64);
    };
    reader.readAsDataURL(file);
  };

  const handleAIEdit = async () => {
    if (!image || !aiPrompt) return;
    setIsProcessing(true);
    try {
      const edited = await editWithAI(image, aiPrompt, isProMode);
      setImage(edited);
      setAiPrompt('');
    } catch (error) {
      alert("AI was unable to process that request.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handlePrint = () => {
    const combined = (window as any).getCombinedImage?.();
    if (!combined) return;
    const printWindow = window.open('', '_blank');
    if (printWindow) {
      printWindow.document.write(`<html><body style="margin:0;display:flex;justify-content:center;align-items:center;height:100vh;"><img src="${combined}" style="max-width:100%;max-height:100%;object-fit:contain;" /><script>window.onload=()=>window.print();</script></body></html>`);
      printWindow.document.close();
    }
  };

  const handleDownload = (onlyLineArt = false) => {
    const data = onlyLineArt ? (window as any).getLineArtOnly?.() : (window as any).getCombinedImage?.();
    if (!data) return;
    const extension = data.includes('svg+xml') ? 'svg' : 'png';
    const linkObj = document.createElement('a');
    linkObj.href = data;
    linkObj.download = `chromasketch-${outputFormat}-${resolution}-${Date.now()}.${extension}`;
    linkObj.click();
  };

  const handleCropComplete = (newImageData: string) => {
    setImage(newImageData);
    setActiveTool(ToolType.BRUSH);
  };

  const applyStylePreset = (color: string, size: number, tool: ToolType) => {
    setBrushColor(color);
    setBrushSize(size);
    setActiveTool(tool);
  };

  return (
    <div className="flex flex-col h-screen bg-slate-50 text-slate-900 overflow-hidden font-sans">
      {showCamera && (
        <CameraModal 
          onCapture={(base64, style) => { setShowCamera(false); processImage(base64, style); }} 
          onClose={() => setShowCamera(false)} 
        />
      )}

      <header className="bg-white border-b border-slate-200 px-6 py-4 flex justify-between items-center shrink-0 shadow-sm z-20">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2.5 rounded-2xl shadow-lg shadow-indigo-100">
              <Sparkles className="text-white w-6 h-6" />
            </div>
            <div>
              <h1 className="text-xl font-extrabold tracking-tight text-slate-800">ChromaSketch AI</h1>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Digital Arts Studio</p>
            </div>
          </div>

          <div className="hidden lg:flex items-center gap-2 bg-slate-50 p-1.5 rounded-2xl border border-slate-200">
            <button 
              onClick={toggleProMode}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl transition-all font-black text-xs uppercase tracking-wider ${isProMode ? 'bg-indigo-600 text-white shadow-lg' : 'text-slate-500 hover:bg-white'}`}
            >
              <ShieldCheck className={`w-4 h-4 ${isProMode ? 'animate-pulse' : ''}`} />
              Studio Pro
            </button>

            <div className="w-[1px] h-4 bg-slate-200 mx-1" />

            <div className="flex bg-slate-100 p-0.5 rounded-xl">
              <button
                onClick={() => handleFormatChange('raster')}
                className={`px-3 py-1.5 rounded-lg flex items-center gap-2 text-[10px] font-black transition-all ${outputFormat === 'raster' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}
              >
                <RasterIcon className="w-3 h-3" /> PNG
              </button>
              <button
                onClick={() => handleFormatChange('vector')}
                className={`px-3 py-1.5 rounded-lg flex items-center gap-2 text-[10px] font-black transition-all ${outputFormat === 'vector' ? 'bg-indigo-600 text-white shadow-sm' : 'text-slate-400'}`}
              >
                <Shapes className="w-3 h-3" /> SVG
              </button>
            </div>

            {outputFormat === 'raster' && (
              <>
                <div className="w-[1px] h-4 bg-slate-200 mx-1" />
                {(['1K', '2K', '4K'] as ImageResolution[]).map(res => (
                  <button
                    key={res}
                    onClick={() => handleResolutionChange(res)}
                    className={`px-3 py-2 rounded-xl text-[10px] font-black transition-all ${resolution === res ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'}`}
                  >
                    {res}
                  </button>
                ))}
              </>
            )}
          </div>
        </div>

        <div className="flex items-center gap-3">
          <button onClick={() => setShowCamera(true)} className="flex items-center gap-2 px-4 py-2 hover:bg-slate-50 text-slate-600 rounded-lg transition-all font-semibold"><Camera className="w-4 h-4" /> Camera</button>
          <button onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 px-4 py-2 bg-white text-indigo-600 rounded-lg shadow-sm hover:shadow-md transition-all font-bold border border-indigo-50"><Upload className="w-4 h-4" /> Upload</button>
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={handleFileUpload} />
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden">
        <aside className="w-80 bg-white border-r border-slate-200 p-6 flex flex-col gap-6 shrink-0 overflow-y-auto shadow-sm z-10 custom-scrollbar">
          <section>
            <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4 text-center border-b pb-2 border-slate-50">Studio Palette</h3>
            <ColorPicker currentColor={brushColor} onChange={setBrushColor} />
          </section>

          <section className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-xs font-bold text-slate-400 uppercase tracking-widest">Line Weight</h3>
              <div className="flex items-center gap-1 bg-white border border-slate-200 rounded-lg p-0.5 shadow-sm">
                <button 
                  onClick={() => setBrushSize(Math.max(1, brushSize - 1))}
                  className="p-1 hover:bg-slate-100 text-slate-400 rounded transition-colors"
                >
                  <Minus className="w-3 h-3" />
                </button>
                <input 
                  type="number" 
                  min="1" 
                  max="100" 
                  value={brushSize} 
                  onChange={(e) => setBrushSize(Math.min(100, Math.max(1, parseInt(e.target.value) || 1)))}
                  className="w-10 bg-transparent text-[11px] font-black text-indigo-600 text-center outline-none"
                />
                <button 
                  onClick={() => setBrushSize(Math.min(100, brushSize + 1))}
                  className="p-1 hover:bg-slate-100 text-slate-400 rounded transition-colors"
                >
                  <Plus className="w-3 h-3" />
                </button>
              </div>
            </div>

            {/* Visual Brush Preview */}
            <div className="flex items-center justify-center h-16 bg-white/50 rounded-xl mb-4 border border-slate-200/50 relative overflow-hidden">
               <div 
                 className="rounded-full shadow-sm transition-all duration-200"
                 style={{ 
                   width: `${brushSize}px`, 
                   height: `${brushSize}px`, 
                   backgroundColor: brushColor,
                   opacity: pressureEnabled ? 0.7 : 1,
                   maxWidth: '60px',
                   maxHeight: '60px'
                 }}
               />
               <span className="absolute bottom-1 right-2 text-[8px] font-black text-slate-300 uppercase">Preview</span>
            </div>

            <input 
              type="range" 
              min="1" 
              max="100" 
              step="1"
              value={brushSize} 
              onChange={(e) => setBrushSize(parseInt(e.target.value))} 
              className="w-full h-1.5 bg-slate-200 rounded-lg appearance-none cursor-pointer accent-indigo-600 mb-4" 
            />

            <div className="flex justify-between gap-1 mb-4">
              {BRUSH_PRESETS.map((preset) => (
                <button
                  key={preset.label}
                  onClick={() => setBrushSize(preset.size)}
                  className={`flex-1 py-1.5 rounded-lg text-[9px] font-black transition-all ${
                    brushSize === preset.size 
                    ? 'bg-indigo-600 text-white shadow-md' 
                    : 'bg-white text-slate-400 hover:text-slate-600 border border-slate-100'
                  }`}
                >
                  {preset.label}
                </button>
              ))}
