import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

export type ColoringStyle = 'standard' | 'bold' | 'detailed' | 'cute' | 'vintage' | 'sketchy' | 'comic' | 'popart' | 'zentangle' | 'stencil' | 'minimalist' | 'blueprint';
export type ImageResolution = '1K' | '2K' | '4K';
export type OutputFormat = 'raster' | 'vector';

const STYLE_PROMPTS: Record<ColoringStyle, string> = {
  standard: "Transform this image into a clean, high-contrast black and white coloring book page. Use only solid black lines for outlines and ensure the background is pure white with no shading, gradients, or textures.",
  bold: "Transform this image into a bold sticker-style coloring page. Use very thick, solid black outlines and extremely simplified shapes. Remove all small details. Perfect for young children.",
  detailed: "Transform this image into an intricate, highly detailed fine-line coloring page. Capture complex textures and patterns using only thin black lines. Suitable for adult coloring books.",
  cute: "Transform this image into a cute, bubbly cartoon coloring page. Exaggerate features like eyes to make them bigger and rounder. Use soft but clear black outlines and a simplified, playful style.",
  vintage: "Transform this image into a vintage-style coloring page. Use slightly textured, organic black lines that mimic 19th-century woodcuts, antique engravings, or classic storybook illustrations. Add subtle cross-hatching and etched details, but keep it clear for coloring. Pure black ink on white background.",
  sketchy: "Transform this image into an expressive, artistic sketchy pencil-drawing style coloring page. Use multiple overlapping thin black lines, rough strokes, and varied line weights to create a hand-drawn, energetic look. Maintain clear white space for coloring.",
  comic: "Transform this image into a dramatic comic book coloring page. Use deep black shadows (chiaroscuro style), bold dynamic outlines, and stylized action details. Ensure it remains a white-background coloring page with pure black ink for a professional graphic novel look.",
  popart: "Transform this image into a retro Pop Art coloring page. Use bold black outlines and incorporate halftone dot patterns (ben-day dots) for shading. Keep the style graphic and iconic, similar to 1960s comic art, but optimized for coloring.",
  zentangle: "Transform this image into a complex Zentangle coloring page. Fill the large shapes and background areas with intricate repetitive patterns like swirls, dots, scales, and geometric shapes. Ensure all patterns are made of clean black lines on a white background.",
  stencil: "Transform this image into a high-contrast stencil art style. Use bold, connected black shapes and clear gaps. Designed for spray paint masking but perfect for high-impact coloring. Solid black on white.",
  minimalist: "Transform this image into an ultra-clean minimalist line drawing. Use the absolute minimum number of paths to represent the subject. Focus on elegant, continuous curves and essential structural outlines. No noise.",
  blueprint: "Transform this image into a technical blueprint illustration. Use crisp, uniform black lines with occasional structural measurement markers or cross-section details. Very architectural and precise."
};

/**
 * Converts an image to line art (Raster or Vector).
 */
export const convertToLineArt = async (
  base64Image: string, 
  style: ColoringStyle = 'standard',
  resolution: ImageResolution = '1K',
  format: OutputFormat = 'raster',
  usePro: boolean = false
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const mimeType = base64Image.split(';')[0].split(':')[1];
  const base64Data = base64Image.split(',')[1];

  const stylePrompt = STYLE_PROMPTS[style] || STYLE_PROMPTS.standard;

  if (format === 'vector') {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: [
        {
          parts: [
            { inlineData: { mimeType, data: base64Data } },
            { text: `${stylePrompt} STUDIO VECTOR MASTER: Analyze the structural outlines of this photo with extreme precision. Generate a professional-grade SVG file. Use ONLY <path> elements with solid black strokes (#000000) and absolutely NO fill. Ensure paths are simplified for smooth coloring but retain all characteristic details. Output ONLY the raw SVG code starting with <svg> and ending with </svg>. No markdown formatting.` }
          ]
        }
      ],
      config: {
        thinkingConfig: { thinkingBudget: 8000 }
      }
    });

    const svgCode = response.text?.trim() || '';
    const cleanSvg = svgCode.replace(/^```svg\n?/, '').replace(/\n?```$/, '').trim();
    return `data:image/svg+xml;base64,${btoa(cleanSvg)}`;
  }

  const isHighRes = resolution === '2K' || resolution === '4K';
  const modelName = (usePro || isHighRes) ? 'gemini-3-pro-image-preview' : 'gemini-2.5-flash-image';

  const qualityInstruction = ` 
    MASTER RESOLUTION PROTOCOL: Output must reach professional illustration standards. 
    1. Lines: Razor-sharp, perfectly opaque #000000 ink with zero anti-aliasing artifacts or "fuzzy" edges.
    2. Fidelity: Reconstruct complex geometry and subtle details lost in the original source. 
    3. Purity: Background must be absolute #FFFFFF (pure white). Remove all digital noise, compression blocks, or stray pixels. 
    4. Printing: Optimize for large-format 300 DPI professional printing. The line work must remain cohesive and bold even when enlarged to 4K resolution.
  `;

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: modelName,
    contents: {
      parts: [
        { inlineData: { mimeType, data: base64Data } },
        { text: stylePrompt + qualityInstruction + " The result MUST be pure black and white line art. Treat this as a professional master illustration for an adult coloring book." },
      ],
    },
    config: modelName === 'gemini-3-pro-image-preview' ? {
      imageConfig: {
        aspectRatio: "1:1",
        imageSize: resolution
      }
    } : undefined
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Failed to generate line art");
};

/**
 * Specifically master/upscale the current work using Pro 4K model
 */
export const upscaleToStudioMaster = async (base64Artwork: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const mimeType = base64Artwork.split(';')[0].split(':')[1];
  const base64Data = base64Artwork.split(',')[1];

  const response: GenerateContentResponse = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: {
      parts: [
        { inlineData: { mimeType, data: base64Data } },
        { text: "ULTRA-HD 4K STUDIO MASTERING: Perform a complete super-resolution reconstruction of this artwork. 1. Re-render all lines as vector-smooth curves at 4096x4096px resolution. 2. Remove every single pixel of noise or compression artifact. 3. Ensure every colored area is filled with perfectly uniform, high-density pigment simulation. 4. The output must be indistinguishable from a high-end physical lithograph. Pure #000000 ink on pure #FFFFFF paper substrate." },
      ],
    },
    config: {
      imageConfig: {
        aspectRatio: "1:1",
        imageSize: "4K"
      }
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) {
      return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Failed to master image in 4K");
};

export const editWithAI = async (base64Image: string, prompt: string, usePro: boolean = false): Promise<string> => {
