export const CameraModal: React.FC<CameraModalProps> = ({ onCapture, onClose, format }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);

  const isVector = format === 'vector';

  useEffect(() => {
    let stream: MediaStream | null = null;

    const startCamera = async () => {
      try {
        setIsLoading(true);
        stream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } }, 
          audio: false 
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
        setIsLoading(false);
      } catch (err) {
        console.error("Camera access error:", err);
        setError("Could not access camera. Please check permissions.");
        setIsLoading(false);
      }
    };

    if (!capturedImage) {
      startCamera();
    }

    return () => {
      if (stream) {
        stream.getTracks().forEach(track => track.stop());
      }
    };
  }, [capturedImage]);

  const handleSnap = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const context = canvas.getContext('2d');

      if (context) {
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        context.drawImage(video, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/jpeg');
        setCapturedImage(base64);
      }
    }
  };

  const handleSelectStyle = (style: ColoringStyle) => {
    if (capturedImage) {
      onCapture(capturedImage, style);
    }
  };

  // Grouping logic for the sidebar
  const categories: ('Vector Pro' | 'Technical' | 'Artistic')[] = isVector 
    ? ['Vector Pro', 'Technical', 'Artistic'] 
    : ['Artistic', 'Technical'];

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/95 backdrop-blur-md p-4 sm:p-8">
      <div className="relative w-full max-w-5xl bg-slate-900 rounded-[2.5rem] overflow-hidden shadow-2xl border border-white/10 flex flex-col md:flex-row h-full max-h-[850px]">

        {/* Main Content Area */}
        <div className="flex-1 relative bg-black flex flex-col min-h-0 border-r border-white/5">
          {/* Header */}
          <div className="absolute top-0 left-0 right-0 p-6 flex justify-between items-center z-20 bg-gradient-to-b from-black/80 to-transparent">
            <h2 className="text-white font-black text-xl flex items-center gap-3">
              {capturedImage ? <Sparkles className="w-6 h-6 text-yellow-400" /> : <Camera className="w-6 h-6" />}
              {capturedImage ? (isVector ? 'Pro Vector Synthesis' : 'Choose Your AI Upgrade') : 'Capture New Photo'}
            </h2>
            <button 
              onClick={onClose}
              className="p-3 bg-white/10 hover:bg-white/20 text-white rounded-full transition-all backdrop-blur-md border border-white/10"
            >
              <X className="w-6 h-6" />
            </button>
          </div>

          <div className="flex-1 flex items-center justify-center relative overflow-hidden">
            {isLoading && !capturedImage && (
              <div className="flex flex-col items-center gap-4">
                <div className="relative">
                  <div className="w-16 h-16 border-4 border-white/10 border-t-indigo-500 rounded-full animate-spin" />
                  <Camera className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-6 h-6 text-white/20" />
                </div>
                <p className="text-slate-400 text-sm font-bold tracking-widest uppercase text-center">Calibrating Studio Lens...</p>
              </div>
            )}

            {error && (
              <div className="p-8 text-center max-w-sm">
                <p className="text-red-400 font-black text-lg mb-4">{error}</p>
                <button 
                  onClick={onClose}
                  className="px-8 py-3 bg-white text-black font-black rounded-2xl hover:bg-slate-100 transition-all"
                >
                  Go Back
                </button>
              </div>
            )}

            {!capturedImage ? (
              <video 
                ref={videoRef} 
                autoPlay 
                playsInline 
                className={`w-full h-full object-cover ${isLoading || error ? 'hidden' : 'block'}`}
              />
            ) : (
              <div className="relative w-full h-full group">
                <img 
                  src={capturedImage} 
                  className="w-full h-full object-cover animate-in fade-in zoom-in duration-500"
                  alt="Captured"
                />
                <div className="absolute inset-0 bg-indigo-600/10 mix-blend-overlay pointer-events-none" />
              </div>
            )}
            <canvas ref={canvasRef} className="hidden" />
          </div>

          {!capturedImage && !error && !isLoading && (
            <div className="p-10 flex justify-center items-center bg-gradient-to-t from-black/80 to-transparent absolute bottom-0 left-0 right-0">
              <button
                onClick={handleSnap}
                className="group relative flex items-center justify-center w-24 h-24 rounded-full border-4 border-white transition-all transform active:scale-90 hover:scale-105 shadow-[0_0_30px_rgba(255,255,255,0.3)]"
              >
                <div className="w-18 h-18 bg-white rounded-full transition-all group-hover:bg-indigo-50 flex items-center justify-center shadow-xl">
                    <Camera className="w-8 h-8 text-slate-900" />
                </div>
              </button>
            </div>
          )}
        </div>

        {/* Upgrade Sidebar */}
        {capturedImage && (
          <aside className="w-full md:w-96 bg-slate-900 p-6 flex flex-col gap-6 overflow-y-auto custom-scrollbar">
            <div className="mb-2">
              <div className="flex items-center justify-between">
                <h3 className="text-white font-black text-2xl tracking-tight">{isVector ? 'Vector Engine' : 'Stylize'}</h3>
                {isVector && (
                   <div className="flex items-center gap-1.5 px-3 py-1 bg-indigo-600/20 border border-indigo-500/30 rounded-full">
                      <Shapes className="w-3 h-3 text-indigo-400" />
                      <span className="text-[10px] font-black text-indigo-300 uppercase tracking-tighter">Pro SVG Mode</span>
                   </div>
                )}
              </div>
              <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mt-1">
                {isVector ? 'Select Sub-Pixel Logic' : 'Premium AI Outlines'}
              </p>
            </div>

            <div className="flex flex-col gap-8 flex-1">
              {categories.map((cat) => {
                const filtered = UPGRADES.filter(u => u.category === cat);
                if (filtered.length === 0) return null;

                return (
                  <div key={cat} className="space-y-3">
                    <div className="flex items-center gap-2 mb-4">
                      <div className={`w-1.5 h-1.5 rounded-full ${cat === 'Vector Pro' ? 'bg-indigo-500 shadow-[0_0_8px_rgba(99,102,241,0.8)]' : 'bg-slate-700'}`} />
                      <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">{cat}</h4>
                    </div>

                    <div className="grid gap-2.5">
                      {filtered.map((upgrade) => {
                        const isFavored = isVector && upgrade.isVectorFavored;
                        return (
                          <button
                            key={upgrade.id}
                            onClick={() => handleSelectStyle(upgrade.id)}
                            className={`group relative flex items-center gap-4 p-3.5 rounded-3xl transition-all text-left ${
                              isFavored 
                              ? 'bg-indigo-600/10 border border-indigo-500 shadow-[0_0_15px_rgba(79,70,229,0.15)]' 
                              : 'bg-white/5 border border-white/5 hover:bg-white/10 hover:border-white/10'
                            }`}
                          >
                            {upgrade.isNew && (
                              <span className="absolute -top-1 -right-1 bg-indigo-600 text-white text-[8px] font-black px-2 py-0.5 rounded-full shadow-lg z-10 animate-pulse uppercase tracking-tighter">
                                New
                              </span>
                            )}
                            <div className={`p-2.5 rounded-2xl ${upgrade.color} text-white shadow-lg shadow-black/20 group-hover:scale-110 transition-transform flex-shrink-0`}>
                              <upgrade.icon className="w-5 h-5" />
                            </div>
                            <div className="min-w-0 flex-1">
                              <h4 className="text-white font-black text-[11px] uppercase tracking-wide truncate">
                                {upgrade.label}
                              </h4>
                              <p className="text-slate-500 text-[9px] font-bold mt-0.5 truncate">{upgrade.description}</p>
                            </div>
                          </button>
                        );
                      })}
                    </div>
                  </div>
                );
              })}
            </div>

            <button
              onClick={() => setCapturedImage(null)}
              className="mt-6 flex items-center justify-center gap-3 p-4 rounded-2xl text-slate-500 font-bold hover:text-white hover:bg-white/5 transition-all text-[11px] uppercase tracking-widest border border-white/5"
            >
              <RefreshCw className="w-4 h-4" />
              Retake Photo
            </button>
          </aside>
        )}
      </div>
    </div>
  );
};

