import React, { useRef, useEffect, useState, useCallback } from 'react';
import { ToolType } from '../types';
import { ZoomIn, ZoomOut, Maximize, Image as ImageIcon, Layers, Undo, Redo, RotateCcw } from 'lucide-react';

interface EditorProps {
  backgroundImage: string | null;
  originalImage?: string | null;
  brushColor: string;
  brushSize: number;
  brushHardness?: number;
  brushSpacing?: number;
  brushFlow?: number;
  brushSmoothing?: number;
  pressureEnabled?: boolean;
  tool: ToolType;
  onHistoryChange?: (canUndo: boolean, canRedo: boolean) => void;
  canvasWidth?: number;
  canvasHeight?: number;
}

const MAX_HISTORY = 40;

function hexToRgb(hex: string) {
  const result = /^#?([a-f\d]{2})([a-f\d]{2})([a-f\d]{2})$/i.exec(hex);
  return result ? {
    r: parseInt(result[1], 16),
    g: parseInt(result[2], 16),
    b: parseInt(result[3], 16)
  } : { r: 0, g: 0, b: 0 };
}

export const Editor: React.FC<EditorProps> = ({ 
  backgroundImage, 
  originalImage,
  brushColor, 
  brushSize, 
  brushHardness = 100,
  brushSpacing = 10,
  brushFlow = 100,
  brushSmoothing = 30,
  pressureEnabled = false,
  tool, 
  onHistoryChange, 
  canvasWidth,
  canvasHeight
}) => {
  const canvasRef = useRef<HTMLCanvasElement>(null); 
  const drawingCanvasRef = useRef<HTMLCanvasElement>(null); 
  const containerRef = useRef<HTMLDivElement>(null);

  const [isDrawing, setIsDrawing] = useState(false);
  const [isPanning, setIsPanning] = useState(false);
  const [lineOpacity, setLineOpacity] = useState(100);
  const [showReference, setShowReference] = useState(false);
  const [substrate, setSubstrate] = useState<'none' | 'paper' | 'canvas'>('paper');
  const [view, setView] = useState({ scale: 1, x: 0, y: 0 });

  const lastCoordsRef = useRef<{x: number, y: number} | null>(null);
  const smoothedCoordsRef = useRef<{x: number, y: number} | null>(null);
  const distanceAccumulatorRef = useRef(0);

  const [startDragCoords, setStartDragCoords] = useState({ x: 0, y: 0 });
  const [initialView, setInitialView] = useState({ scale: 1, x: 0, y: 0 });

  const historyRef = useRef<ImageData[]>([]);
  const historyIndexRef = useRef<number>(-1);

  const updateHistoryStatus = useCallback(() => {
    if (onHistoryChange) {
      onHistoryChange(
        historyIndexRef.current > 0,
        historyIndexRef.current < historyRef.current.length - 1
      );
    }
  }, [onHistoryChange]);

  const saveState = useCallback(() => {
    const canvas = drawingCanvasRef.current;
    const ctx = canvas?.getContext('2d');
    if (canvas && ctx) {
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      if (historyIndexRef.current < historyRef.current.length - 1) {
        historyRef.current = historyRef.current.slice(0, historyIndexRef.current + 1);
      }
      historyRef.current.push(imageData);
      if (historyRef.current.length > MAX_HISTORY) {
        historyRef.current.shift();
      } else {
        historyIndexRef.current++;
      }
      updateHistoryStatus();
    }
  }, [updateHistoryStatus]);

  const undo = useCallback(() => {
    if (historyIndexRef.current > 0) {
      historyIndexRef.current--;
      const canvas = drawingCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (canvas && ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.putImageData(historyRef.current[historyIndexRef.current], 0, 0);
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  const redo = useCallback(() => {
    if (historyIndexRef.current < historyRef.current.length - 1) {
      historyIndexRef.current++;
      const canvas = drawingCanvasRef.current;
      const ctx = canvas?.getContext('2d');
      if (canvas && ctx) {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.putImageData(historyRef.current[historyIndexRef.current], 0, 0);
        updateHistoryStatus();
      }
    }
  }, [updateHistoryStatus]);

  const clearDrawing = useCallback(() => {
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (ctx) {
      ctx.clearRect(0, 0, drawingCanvasRef.current!.width, drawingCanvasRef.current!.height);
      saveState();
    }
  }, [saveState]);

  const fitToScreen = useCallback(() => {
    const parent = containerRef.current;
    if (!parent || !canvasRef.current || !drawingCanvasRef.current) return;
    const containerW = parent.clientWidth;
    const containerH = parent.clientHeight;
    const targetW = canvasWidth || containerW;
    const targetH = canvasHeight || containerH;
    const scaleToFit = Math.min(containerW / targetW, containerH / targetH) * 0.95;
    setView({
      scale: scaleToFit,
      x: (containerW - targetW * scaleToFit) / 2,
      y: (containerH - targetH * scaleToFit) / 2
    });
  }, [canvasWidth, canvasHeight]);

  const resize = useCallback(() => {
    const parent = containerRef.current;
    if (!parent || !canvasRef.current || !drawingCanvasRef.current) return;

    const targetW = canvasWidth || parent.clientWidth;
    const targetH = canvasHeight || parent.clientHeight;

    canvasRef.current.width = targetW;
    canvasRef.current.height = targetH;
    drawingCanvasRef.current.width = targetW;
    drawingCanvasRef.current.height = targetH;

    if (backgroundImage) {
      const bgCtx = canvasRef.current.getContext('2d');
      if (bgCtx) {
        const img = new Image();
        img.onload = () => {
          bgCtx.clearRect(0, 0, targetW, targetH);
          const scaleFactor = Math.min(targetW / img.width, targetH / img.height);
          const x = (targetW / 2) - (img.width / 2) * scaleFactor;
          const y = (targetH / 2) - (img.height / 2) * scaleFactor;
          bgCtx.drawImage(img, x, y, img.width * scaleFactor, img.height * scaleFactor);
        };
        img.src = backgroundImage;
      }
    }
    fitToScreen();
  }, [backgroundImage, canvasWidth, canvasHeight, fitToScreen]);

  useEffect(() => {
    window.addEventListener('resize', resize);
    resize();
    return () => window.removeEventListener('resize', resize);
  }, [resize]);

  const getCoords = (e: React.PointerEvent) => {
    const rect = containerRef.current?.getBoundingClientRect();
    if (!rect) return { x: 0, y: 0 };
    return {
      x: (e.clientX - rect.left - view.x) / view.scale,
      y: (e.clientY - rect.top - view.y) / view.scale
    };
  };

  const drawStamp = (ctx: CanvasRenderingContext2D, x: number, y: number, size: number, color: string, hardness: number, flow: number) => {
    const radius = size / 2;
    if (radius <= 0) return;
    const rgb = hexToRgb(color);
    const gradient = ctx.createRadialGradient(x, y, 0, x, y, radius);
    const alpha = flow / 100;
    const hardStop = Math.max(0, Math.min(0.99, hardness / 100));

    gradient.addColorStop(0, `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, ${alpha})`);
    gradient.addColorStop(hardStop, `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, ${alpha})`);
    gradient.addColorStop(1, `rgba(${rgb.r}, ${rgb.g}, ${rgb.b}, 0)`);

    ctx.fillStyle = gradient;
    ctx.fillRect(x - radius, y - radius, size, size);
  };

  const start = (e: React.PointerEvent) => {
    const coords = getCoords(e);
    if (tool === ToolType.PAN) {
      setIsPanning(true);
      setStartDragCoords({ x: e.clientX, y: e.clientY });
      setInitialView({ ...view });
      return;
    }
    setIsDrawing(true);
    lastCoordsRef.current = coords;
    smoothedCoordsRef.current = coords;
    distanceAccumulatorRef.current = 0;

    if (tool === ToolType.BRUSH) {
      const ctx = drawingCanvasRef.current?.getContext('2d');
      if (ctx) {
        const pressure = (pressureEnabled && e.pressure > 0) ? e.pressure : 1.0;
        const size = pressureEnabled ? brushSize * (0.3 + 0.7 * pressure) : brushSize;
        ctx.globalCompositeOperation = 'source-over';
        drawStamp(ctx, coords.x, coords.y, size, brushColor, brushHardness, brushFlow);
      }
    }
  };

  const draw = (e: React.PointerEvent) => {
    const rawCoords = getCoords(e);
    if (tool === ToolType.PAN && isPanning) {
      const dx = e.clientX - startDragCoords.x;
      const dy = e.clientY - startDragCoords.y;
      setView({ ...initialView, x: initialView.x + dx, y: initialView.y + dy });
      return;
    }
    if (!isDrawing || !lastCoordsRef.current || !smoothedCoordsRef.current) return;
    const ctx = drawingCanvasRef.current?.getContext('2d');
    if (!ctx) return;

    const factor = Math.max(0.01, 1 - (brushSmoothing / 100));
    const coords = {
      x: smoothedCoordsRef.current.x + (rawCoords.x - smoothedCoordsRef.current.x) * factor,
      y: smoothedCoordsRef.current.y + (rawCoords.y - smoothedCoordsRef.current.y) * factor
    };
    smoothedCoordsRef.current = coords;

    const pressure = (pressureEnabled && e.pressure > 0) ? e.pressure : 1.0;
    const size = pressureEnabled ? brushSize * (0.3 + 0.7 * pressure) : brushSize;

    if (tool === ToolType.BRUSH) {
      const dx = coords.x - lastCoordsRef.current.x;
      const dy = coords.y - lastCoordsRef.current.y;
      const dist = Math.hypot(dx, dy);
      const angle = Math.atan2(dy, dx);

      const spacingValue = Math.max(0.5, (brushSpacing / 100) * brushSize);
      distanceAccumulatorRef.current += dist;

      if (distanceAccumulatorRef.current >= spacingValue) {
        const steps = Math.floor(distanceAccumulatorRef.current / spacingValue);
        for (let i = 1; i <= steps; i++) {
          const stepDist = (i * spacingValue) - (distanceAccumulatorRef.current - dist);
          const px = lastCoordsRef.current.x + Math.cos(angle) * stepDist;
          const py = lastCoordsRef.current.y + Math.sin(angle) * stepDist;
          ctx.globalCompositeOperation = 'source-over';
          drawStamp(ctx, px, py, size, brushColor, brushHardness, brushFlow);
        }
        distanceAccumulatorRef.current %= spacingValue;
        lastCoordsRef.current = coords;
      }
    } else {
      ctx.beginPath();
      ctx.moveTo(lastCoordsRef.current.x, lastCoordsRef.current.y);
      ctx.lineTo(coords.x, coords.y);
      ctx.lineCap = 'round';
      ctx.lineJoin = 'round';
      ctx.lineWidth = size;
      ctx.strokeStyle = tool === ToolType.ERASER ? '#FFFFFF' : brushColor;
      ctx.globalCompositeOperation = tool === ToolType.ERASER ? 'destination-out' : 'source-over';
      ctx.globalAlpha = tool === ToolType.HIGHLIGHTER ? 0.3 : 1.0;
      ctx.stroke();
      lastCoordsRef.current = coords;
    }
  };

  const stop = () => { 
    if (isDrawing) { setIsDrawing(false); saveState(); }
    setIsPanning(false);
  };

  const handleZoom = (factor: number) => {
    setView(v => ({ ...v, scale: Math.max(0.1, Math.min(10, v.scale * factor)) }));
  };

  useEffect(() => {
    (window as any).undo = undo;
    (window as any).redo = redo;
    (window as any).clearCanvas = clearDrawing;
    (window as any).getCombinedImage = () => {
      const final = document.createElement('canvas');
      final.width = canvasRef.current!.width;
      final.height = canvasRef.current!.height;
      const ctx = final.getContext('2d')!;
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, final.width, final.height);
      ctx.drawImage(drawingCanvasRef.current!, 0, 0);
      ctx.globalCompositeOperation = 'multiply';
      ctx.drawImage(canvasRef.current!, 0, 0);
      return final.toDataURL('image/png');
    };
  }, [undo, redo, clearDrawing]);

  return (
    <div ref={containerRef} className="relative w-full h-full bg-slate-950/20 rounded-[1.5rem] md:rounded-[2rem] overflow-hidden group">
      <div 
        className={`absolute inset-0 transition-opacity ${substrate === 'paper' ? 'paper-grain' : (substrate === 'canvas' ? 'canvas-texture' : '')}`}
        style={{ backgroundColor: '#ffffff' }}
      />

      <div 
        className="absolute origin-top-left transition-transform duration-75"
        style={{ transform: `translate(${view.x}px, ${view.y}px) scale(${view.scale})` }}
      >
        <canvas ref={drawingCanvasRef} onPointerDown={start} onPointerMove={draw} onPointerUp={stop} onPointerLeave={stop} className="absolute inset-0 touch-none z-10" />
        <canvas ref={canvasRef} style={{ opacity: lineOpacity / 100 }} className="absolute inset-0 pointer-events-none mix-blend-multiply z-20" />
      </div>

      {/* Floating Layer/Ref Overlays */}
      <div className="absolute top-3 right-3 md:top-4 md:right-4 flex items-center gap-2 z-30">
        <div className="flex bg-slate-900/90 backdrop-blur-md border border-white/10 rounded-xl p-0.5 md:p-1 shadow-lg">
          <button onClick={() => setShowReference(!showReference)} className={`p-2 rounded-lg transition-all ${showReference ? 'bg-indigo-600 text-white' : 'text-slate-400 hover:text-white'}`}>
            <ImageIcon className="w-4 h-4" />
          </button>
          <button onClick={() => setSubstrate(s => s === 'paper' ? 'canvas' : (s === 'canvas' ? 'none' : 'paper'))} className="p-2 text-slate-400 hover:text-white rounded-lg">
            <Layers className="w-4 h-4" />
          </button>
        </div>
      </div>

      {showReference && originalImage && (
        <div className="absolute bottom-20 md:bottom-24 left-4 md:left-6 w-32 h-32 md:w-40 md:h-40 bg-slate-900 border-2 border-white/20 rounded-xl shadow-2xl overflow-hidden z-40 animate-in zoom-in-95">
           <img src={originalImage} className="w-full h-full object-cover" />
           <div className="absolute bottom-1 bg-black/60 px-2 py-0.5 rounded text-[6px] md:text-[7px] font-black uppercase text-white left-1/2 -translate-x-1/2">Ref</div>
        </div>
      )}

      {/* Zoom / Opacity HUD - Simplified for mobile */}
      <div className="absolute bottom-4 md:bottom-6 left-1/2 -translate-x-1/2 flex items-center gap-3 md:gap-5 bg-slate-900/95 backdrop-blur-xl border border-white/10 px-4 md:px-6 py-2 md:py-2.5 rounded-2xl shadow-2xl z-30 scale-90 sm:scale-100">
        <button onClick={() => handleZoom(0.8)} className="p-1.5 text-slate-400 hover:text-white"><ZoomOut className="w-4 h-4" /></button>
        <span className="text-[9px] font-black text-indigo-400 w-8 text-center">{Math.round(view.scale * 100)}%</span>
        <button onClick={() => handleZoom(1.2)} className="p-1.5 text-slate-400 hover:text-white"><ZoomIn className="w-4 h-4" /></button>
        <div className="w-px h-5 bg-white/10 mx-1" />
        <button onClick={fitToScreen} className="p-1.5 text-slate-400 hover:text-white"><Maximize className="w-4 h-4" /></button>
        <div className="hidden xs:flex w-px h-5 bg-white/10 mx-1" />
        <div className="hidden xs:flex flex-col items-center gap-0.5">
          <input type="range" min="0" max="100" value={lineOpacity} onChange={(e) => setLineOpacity(parseInt(e.target.value))} className="w-16 md:w-20 h-0.5 accent-indigo-500" />
          <span className="text-[7px] font-black text-slate-500 uppercase tracking-widest">Fade</span>
        </div>
      </div>
    </div>
  );
};

