export const CameraModal: React.FC<CameraModalProps> = ({ onCapture, onClose, format }) => {
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const [error, setError] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [capturedImage, setCapturedImage] = useState<string | null>(null);

  const isVector = format === 'vector';

  useEffect(() => {
    let stream: MediaStream | null = null;
    const startCamera = async () => {
      try {
        setIsLoading(true);
        stream = await navigator.mediaDevices.getUserMedia({ 
          video: { facingMode: 'environment', width: { ideal: 1280 }, height: { ideal: 720 } }, 
          audio: false 
        });
        if (videoRef.current) {
          videoRef.current.srcObject = stream;
        }
        setIsLoading(false);
      } catch (err) {
        setError("Camera access denied.");
        setIsLoading(false);
      }
    };
    if (!capturedImage) startCamera();
    return () => stream?.getTracks().forEach(track => track.stop());
  }, [capturedImage]);

  const handleSnap = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      const context = canvas.getContext('2d');
      if (context) {
        canvas.width = video.videoWidth;
        canvas.height = video.videoHeight;
        context.drawImage(video, 0, 0, canvas.width, canvas.height);
        setCapturedImage(canvas.toDataURL('image/jpeg'));
      }
    }
  };

  const categories: ('Vector Pro' | 'Technical' | 'Artistic')[] = isVector 
    ? ['Vector Pro', 'Technical', 'Artistic'] 
    : ['Artistic', 'Technical'];

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/95 backdrop-blur-md p-2 sm:p-4">
      <div className="relative w-full max-w-5xl bg-slate-900 rounded-3xl overflow-hidden shadow-2xl border border-white/10 flex flex-col md:flex-row h-full max-h-[90vh] md:max-h-[850px]">

        <div className="flex-1 relative bg-black flex flex-col min-h-[40vh] md:min-h-0 border-b md:border-b-0 md:border-r border-white/5">
          <div className="absolute top-0 left-0 right-0 p-4 md:p-6 flex justify-between items-center z-20 bg-gradient-to-b from-black/80 to-transparent">
            <h2 className="text-white font-black text-sm md:text-xl flex items-center gap-2 md:gap-3">
              {capturedImage ? <Sparkles className="w-5 h-5 md:w-6 md:h-6 text-yellow-400" /> : <Camera className="w-5 h-5 md:w-6 md:h-6" />}
              {capturedImage ? 'AI Synthesis' : 'Capture'}
            </h2>
            <button onClick={onClose} className="p-2 md:p-3 bg-white/10 hover:bg-white/20 text-white rounded-full transition-all border border-white/10">
              <X className="w-5 h-5 md:w-6 md:h-6" />
            </button>
          </div>

          <div className="flex-1 flex items-center justify-center relative overflow-hidden">
            {isLoading && !capturedImage && (
              <div className="flex flex-col items-center gap-4">
                <div className="w-12 h-12 border-4 border-white/10 border-t-indigo-500 rounded-full animate-spin" />
                <p className="text-slate-400 text-[10px] font-black tracking-widest uppercase">Lens Active...</p>
              </div>
            )}

            {error && <div className="p-8 text-center text-red-400 font-black">{error}</div>}

            {!capturedImage ? (
              <video ref={videoRef} autoPlay playsInline className={`w-full h-full object-cover ${isLoading || error ? 'hidden' : 'block'}`} />
            ) : (
              <img src={capturedImage} className="w-full h-full object-cover animate-in fade-in zoom-in-95 duration-500" alt="Captured" />
            )}
            <canvas ref={canvasRef} className="hidden" />
          </div>

          {!capturedImage && !error && !isLoading && (
            <div className="p-6 md:p-10 flex justify-center items-center bg-gradient-to-t from-black/80 to-transparent absolute bottom-0 left-0 right-0">
              <button
                onClick={handleSnap}
                className="group w-16 h-16 md:w-20 md:h-20 rounded-full border-4 border-white flex items-center justify-center transition-all transform active:scale-90 hover:scale-105 shadow-xl"
              >
                <div className="w-12 h-12 md:w-16 md:h-16 bg-white rounded-full flex items-center justify-center">
                    <Camera className="w-6 h-6 md:w-8 md:h-8 text-slate-900" />
                </div>
              </button>
            </div>
          )}
        </div>

        {capturedImage && (
          <aside className="w-full md:w-96 bg-slate-900 p-4 md:p-6 flex flex-col gap-4 md:gap-6 overflow-y-auto custom-scrollbar">
            <div className="flex items-center justify-between">
              <div>
                <h3 className="text-white font-black text-lg md:text-2xl tracking-tight">Style Page</h3>
                <p className="text-slate-500 text-[9px] font-black uppercase tracking-widest">Select AI Logic</p>
              </div>
              <button onClick={() => setCapturedImage(null)} className="p-2 text-slate-400 hover:text-white transition-colors">
                <RefreshCw className="w-5 h-5" />
              </button>
            </div>

            <div className="flex flex-col gap-6 flex-1 pb-4">
              {categories.map((cat) => {
                const filtered = UPGRADES.filter(u => u.category === cat);
                if (filtered.length === 0) return null;
                return (
                  <div key={cat} className="space-y-3">
                    <h4 className="text-[9px] font-black text-slate-500 uppercase tracking-widest">{cat}</h4>
                    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-1 gap-2">
                      {filtered.map((upgrade) => (
                        <button
                          key={upgrade.id}
                          onClick={() => onCapture(capturedImage, upgrade.id)}
                          className={`flex items-center gap-3 p-3 rounded-2xl transition-all text-left bg-white/5 border border-white/5 hover:bg-white/10 hover:border-indigo-500/30 group`}
                        >
                          <div className={`p-2 rounded-xl ${upgrade.color} text-white shadow-lg flex-shrink-0 group-hover:scale-110 transition-transform`}>
                            <upgrade.icon className="w-4 h-4" />
                          </div>
                          <div className="min-w-0 flex-1">
                            <h4 className="text-white font-black text-[10px] uppercase tracking-wide truncate">{upgrade.label}</h4>
                            <p className="text-slate-500 text-[8px] truncate">{upgrade.description}</p>
                          </div>
                        </button>
                      ))}
                    </div>
                  </div>
                );
              })}
            </div>
          </aside>
        )}
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { 
  Plus, Upload, Printer, RotateCcw, Eraser, Paintbrush, Sparkles, Download,
  Camera, Loader2, Trash2, Wand2, Image as ImageIcon, Undo, Redo, PaintBucket,
  ShieldCheck, Settings2, Wind, Highlighter, Hand, MoveDiagonal2, Minus, 
  Crown, Palette, Target, Droplet, Sliders, Zap, Menu, X, Info
} from 'lucide-react';
import { ColorPicker } from './components/ColorPicker';
import { Editor } from './components/Editor';
import { CameraModal } from './components/CameraModal';
import { StylePresets } from './components/StylePresets';
import { convertToLineArt, editWithAI, upscaleToStudioMaster, ColoringStyle, ImageResolution, OutputFormat } from './services/geminiService';
import { ToolType } from './types';

const BRUSH_PRESETS = [
  { label: 'Detail', size: 1 },
  { label: 'Fine', size: 4 },
  { label: 'Normal', size: 12 },
  { label: 'Bold', size: 32 },
  { label: 'Max', size: 80 },
];

const App: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [brushColor, setBrushColor] = useState('#4f46e5');
  const [brushSize, setBrushSize] = useState(12);
  const [brushHardness, setBrushHardness] = useState(90);
  const [brushSpacing, setBrushSpacing] = useState(15);
  const [brushFlow, setBrushFlow] = useState(100);
  const [brushSmoothing, setBrushSmoothing] = useState(30);
  const [pressureEnabled, setPressureEnabled] = useState(true);
  const [activeTool, setActiveTool] = useState<ToolType>(ToolType.BRUSH);
  const [aiPrompt, setAiPrompt] = useState('');
  const [showCamera, setShowCamera] = useState(false);
  const [canUndo, setCanUndo] = useState(false);
  const [canRedo, setCanRedo] = useState(false);
  const [isProMode, setIsProMode] = useState(false);
  const [resolution, setResolution] = useState<ImageResolution>('2K');
  const [outputFormat, setOutputFormat] = useState<OutputFormat>('raster');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  const checkProPermissions = async () => {
    try {
      const hasKey = await (window as any).aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await (window as any).aistudio.openSelectKey();
      }
      return true;
    } catch (e) {
      return false;
    }
  };

  const handleError = async (error: any) => {
    const errorMsg = error?.message || "";
    if (errorMsg.includes("permission denied") || errorMsg.includes("Requested entity was not found")) {
      alert("This advanced model requires a selected API key with billing enabled. Please select your key in the next dialog.");
      await (window as any).aistudio.openSelectKey();
    } else {
      alert("AI Processing Failed. Please try again or check your connection.");
    }
  };

  const processImage = async (base64: string, style: ColoringStyle = 'standard') => {
    // If user wants vector or high-res, ensure they know about API key requirements
    if (outputFormat === 'vector' || isProMode) {
      const hasKey = await (window as any).aistudio.hasSelectedApiKey();
      if (!hasKey) {
        await (window as any).aistudio.openSelectKey();
      }
    }

    setOriginalImage(base64);
    setIsProcessing(true);
    setIsSidebarOpen(false);
    try {
      const lineArt = await convertToLineArt(base64, style, resolution, outputFormat, isProMode);
      setImage(lineArt);
    } catch (error) {
      await handleError(error);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleMasterUpscale = async () => {
    const success = await checkProPermissions();
    if (!success) return;
    setIsProcessing(true);
    try {
      const data = (window as any).getCombinedImage?.();
      if (!data) return;
      const mastered = await upscaleToStudioMaster(data);
      setImage(mastered);
      setResolution('4K');
      setIsProMode(true);
    } catch (error) {
      await handleError(error);
    } finally {
      setIsProcessing(false);
    }
  };

  const adjustBrushSize = (delta: number) => {
    setBrushSize(prev => Math.max(1, Math.min(100, prev + delta)));
  };

  const applyStylePreset = (color: string, size: number, tool: ToolType) => {
    setBrushColor(color);
    setBrushSize(size);
    setActiveTool(tool);
  };

  return (
    <div className="flex flex-col h-screen bg-[#020617] text-slate-100 overflow-hidden font-sans selection:bg-indigo-500/30">
      {showCamera && (
        <CameraModal 
          onCapture={(base64, style) => { setShowCamera(false); processImage(base64, style); }} 
          onClose={() => setShowCamera(false)} 
          format={outputFormat}
        />
      )}

      {/* Header */}
      <header className="bg-slate-950/50 backdrop-blur-3xl border-b border-white/5 px-4 md:px-8 py-3 md:py-4 flex justify-between items-center shrink-0 z-50">
        <div className="flex items-center gap-4 md:gap-10">
          <button 
            onClick={() => setIsSidebarOpen(!isSidebarOpen)}
            className="lg:hidden p-2 hover:bg-white/10 rounded-xl transition-colors"
          >
            {isSidebarOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
          </button>

          <div className="flex items-center gap-3 md:gap-4 group cursor-pointer" title="ChromaSketch AI Studio">
            <div className="bg-gradient-to-br from-indigo-500 to-purple-600 p-1.5 md:p-2 rounded-xl md:rounded-2xl shadow-2xl group-hover:scale-110 transition-transform">
              <Sparkles className="text-white w-4 h-4 md:w-5 md:h-5" />
            </div>
            <div className="hidden sm:block">
              <h1 className="text-lg md:text-xl font-black tracking-tight text-white leading-none">ChromaSketch</h1>
              <p className="text-[7px] md:text-[8px] text-indigo-400 font-black uppercase tracking-[0.2em] mt-1">Pro AI Arts Studio</p>
            </div>
          </div>

          <nav className="hidden xl:flex items-center gap-4 bg-white/5 p-1 rounded-xl border border-white/5">
             <button 
               onClick={async () => { if(await checkProPermissions()) setIsProMode(!isProMode); }}
               className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all font-bold text-[10px] uppercase tracking-wider ${isProMode ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-500/30' : 'text-slate-400 hover:bg-white/5'}`}
               title="Enable advanced Gemini Pro models"
             >
               <ShieldCheck className="w-3.5 h-3.5" /> Studio Engine
             </button>
             <div className="flex bg-black/40 p-1 rounded-lg">
               {(['raster', 'vector'] as OutputFormat[]).map(f => (
                 <button 
                  key={f} 
                  onClick={async () => {
                    if (f === 'vector' && !isProMode) {
                      const success = await checkProPermissions();
                      if (!success) return;
                    }
                    setOutputFormat(f);
                  }} 
                  className={`px-3 py-1.5 rounded-md text-[9px] font-black uppercase transition-all ${outputFormat === f ? 'bg-white/10 text-white' : 'text-slate-500'}`}
                >
                   {f}
                 </button>
               ))}
             </div>
          </nav>
        </div>

        <div className="flex items-center gap-2 md:gap-4">
          <button onClick={() => setShowCamera(true)} className="flex items-center gap-2 px-3 md:px-5 py-2 md:py-2.5 bg-white/5 hover:bg-white/10 text-white rounded-xl transition-all font-bold border border-white/5 text-[10px] md:text-[11px] uppercase tracking-wide">
            <Camera className="w-4 h-4 text-indigo-400" />
            <span className="hidden xs:block">Studio Cam</span>
          </button>
          <button onClick={() => fileInputRef.current?.click()} className="flex items-center gap-2 px-3 md:px-5 py-2 md:py-2.5 bg-indigo-600 hover:bg-indigo-500 text-white rounded-xl transition-all font-bold shadow-xl shadow-indigo-500/20 text-[10px] md:text-[11px] uppercase tracking-wide">
            <Upload className="w-4 h-4" />
            <span className="hidden xs:block">Import</span>
          </button>
          <input type="file" ref={fileInputRef} className="hidden" accept="image/*" onChange={(e) => {
            const file = e.target.files?.[0];
            if(file) {
              const reader = new FileReader();
              reader.onload = (ev) => processImage(ev.target?.result as string);
              reader.readAsDataURL(file);
            }
          }} />
        </div>
      </header>

      <main className="flex flex-1 overflow-hidden relative">
        {/* Responsive Overlay Sidebar */}
        {isSidebarOpen && (
          <div 
            className="fixed inset-0 bg-black/60 backdrop-blur-sm z-[55] lg:hidden"
            onClick={() => setIsSidebarOpen(false)}
          />
        )}

        <aside className={`
          fixed inset-y-0 left-0 w-80 bg-slate-950/90 lg:bg-slate-950/40 backdrop-blur-3xl lg:backdrop-blur-2xl border-r border-white/5 p-6 flex flex-col gap-6 shrink-0 overflow-y-auto custom-scrollbar z-[60] lg:z-40 lg:relative lg:translate-x-0 transition-transform duration-300 ease-in-out
          ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        `}>
          <div className="flex justify-between items-center lg:hidden mb-2">
            <h2 className="text-white font-black uppercase text-xs tracking-widest">Tools & Settings</h2>
            <button onClick={() => setIsSidebarOpen(false)} className="p-2 hover:bg-white/10 rounded-lg">
              <X className="w-5 h-5" />
            </button>
          </div>

          <section>
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-4 flex items-center gap-2">
              <Palette className="w-3 h-3" /> Pigment Library
            </h3>
            <ColorPicker currentColor={brushColor} onChange={setBrushColor} />
          </section>

          <section>
            <StylePresets 
              currentColor={brushColor} 
              currentSize={brushSize} 
              currentTool={activeTool} 
              onApplyPreset={applyStylePreset} 
            />
          </section>

          {/* Brush Configuration Card */}
          <section className="bg-white/5 p-5 rounded-3xl border border-white/5 space-y-6">
            <div>
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                  <Sliders className="w-3 h-3" /> Tool Caliber
                </h3>
                <div className="flex items-center gap-1.5">
                  <button onClick={() => adjustBrushSize(-1)} className="p-1 hover:bg-white/10 rounded-md text-slate-400 transition-colors border border-white/5"><Minus className="w-3 h-3" /></button>
                  <input 
                    type="number" value={brushSize} 
                    onChange={(e) => setBrushSize(parseInt(e.target.value) || 1)}
                    className="w-10 bg-indigo-500/10 rounded-lg text-indigo-400 font-mono text-[10px] font-bold text-center py-1 outline-none border border-indigo-500/20"
                  />
                  <button onClick={() => adjustBrushSize(1)} className="p-1 hover:bg-white/10 rounded-md text-slate-400 transition-colors border border-white/5"><Plus className="w-3 h-3" /></button>
                </div>
              </div>
              <input type="range" min="1" max="100" value={brushSize} onChange={(e) => setBrushSize(parseInt(e.target.value))} className="w-full h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500 mb-4" />
              <div className="grid grid-cols-5 gap-1">
                {BRUSH_PRESETS.map((p) => (
                  <button key={p.label} onClick={() => setBrushSize(p.size)} className={`py-1.5 rounded-lg text-[8px] font-black transition-all ${brushSize === p.size ? 'bg-indigo-600 text-white' : 'bg-slate-800/50 text-slate-500 hover:bg-slate-700'}`}>
                    {p.label[0]}
                  </button>
                ))}
              </div>
            </div>

            {/* Dynamics Group */}
            {activeTool === ToolType.BRUSH && (
              <div className="space-y-4 pt-4 border-t border-white/5 animate-in fade-in slide-in-from-top-1">
                {[
                  { id: 'hardness', icon: Target, label: 'Hardness', value: brushHardness, setter: setBrushHardness, min: 1, max: 100 },
                  { id: 'spacing', icon: MoveDiagonal2, label: 'Spacing', value: brushSpacing, setter: setBrushSpacing, min: 1, max: 100 },
                  { id: 'flow', icon: Droplet, label: 'Flow', value: brushFlow, setter: setBrushFlow, min: 1, max: 100 },
                  { id: 'smoothing', icon: Wind, label: 'Smooth', value: brushSmoothing, setter: setBrushSmoothing, min: 0, max: 100 },
                ].map((dyn) => (
                  <div key={dyn.id} className="space-y-2">
                    <div className="flex justify-between items-center">
                      <div className="flex items-center gap-2">
                        <dyn.icon className="w-3 h-3 text-slate-500" />
                        <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{dyn.label}</label>
                      </div>
                      <input 
                        type="number" value={dyn.value} 
                        onChange={(e) => dyn.setter(parseInt(e.target.value) || 0)}
                        className="w-9 bg-slate-800/50 rounded-md text-indigo-400 font-mono text-[9px] font-bold text-center py-0.5 outline-none border border-white/5"
                      />
                    </div>
                    <input 
                      type="range" min={dyn.min} max={dyn.max} value={dyn.value} 
                      onChange={(e) => dyn.setter(parseInt(e.target.value))} 
                      className="w-full h-0.5 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-indigo-500" 
                    />
                  </div>
                ))}

                <div className="flex items-center justify-between pt-2">
                  <div className="flex items-center gap-2">
                    <Zap className="w-3 h-3 text-amber-500" />
                    <label className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Pressure</label>
                  </div>
                  <button onClick={() => setPressureEnabled(!pressureEnabled)} className={`px-2.5 py-1 rounded-md text-[9px] font-black uppercase transition-all ${pressureEnabled ? 'bg-indigo-600 text-white' : 'bg-slate-800 text-slate-500'}`}>
                    {pressureEnabled ? 'Active' : 'Off'}
                  </button>
                </div>
              </div>
            )}
          </section>

          <section>
            <h3 className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-4">Precision Suite</h3>
            <div className="grid grid-cols-2 gap-2.5">
              {[
                { id: ToolType.BRUSH, icon: Paintbrush, label: 'Artist' },
                { id: ToolType.BUCKET, icon: PaintBucket, label: 'Fill' },
                { id: ToolType.ERASER, icon: Eraser, label: 'Eraser' },
                { id: ToolType.HIGHLIGHTER, icon: Highlighter, label: 'Vibe' },
                { id: ToolType.SPRAY, icon: Wind, label: 'Spray' },
                { id: ToolType.PAN, icon: Hand, label: 'Canvas' },
              ].map(t => (
                <button 
                  key={t.id} onClick={() => { setActiveTool(t.id); if (window.innerWidth < 1024) setIsSidebarOpen(false); }} 
                  className={`flex items-center gap-3 p-3 rounded-2xl border transition-all ${activeTool === t.id ? 'border-indigo-500 bg-indigo-500/10 text-white shadow-lg shadow-indigo-500/10' : 'border-transparent bg-white/5 text-slate-500 hover:bg-white/10'}`}
                >
                  <t.icon className="w-4 h-4 shrink-0" />
                  <span className="text-[9px] font-black uppercase tracking-wide truncate">{t.label}</span>
                </button>
              ))}
            </div>
          </section>

          <section className="mt-auto space-y-4">
             {image && (
               <button onClick={handleMasterUpscale} className="w-full group relative flex items-center justify-center gap-3 p-4 bg-gradient-to-r from-indigo-600 to-purple-700 text-white rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:scale-[1.02] active:scale-95 transition-all">
                 <Crown className="w-4 h-4 text-yellow-400" />
                 Deep Studio 4K
               </button>
             )}

             <div className="bg-slate-900/60 p-4 rounded-2xl border border-white/5">
                <textarea
                  placeholder="Ask AI Stylist..."
                  value={aiPrompt}
                  onChange={(e) => setAiPrompt(e.target.value)}
                  className="w-full text-xs p-3 rounded-xl bg-black/40 border border-white/5 h-20 resize-none focus:ring-1 focus:ring-indigo-500 outline-none"
                />
                <button onClick={async () => {
                  if (!image) return;
                  setIsProcessing(true);
                  try { const edited = await editWithAI(image!, aiPrompt, isProMode); setImage(edited); setAiPrompt(''); }
                  catch(e) { await handleError(e); }
                  finally { setIsProcessing(false); }
                }} className="mt-3 w-full bg-white text-black py-2 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-50 transition-all flex items-center justify-center gap-2" disabled={!image || !aiPrompt || isProcessing}>
                  <Sparkles className="w-3 h-3" /> Infuse
                </button>
             </div>
          </section>
        </aside>

        <section className="flex-1 flex flex-col p-4 md:p-8 relative bg-[#020617]">
          {/* Status Indicator */}
          <div className="absolute top-4 left-4 z-40 flex items-center gap-2 bg-black/40 backdrop-blur-md px-3 py-1.5 rounded-full border border-white/5">
            <div className={`w-2 h-2 rounded-full ${isProMode ? 'bg-indigo-500 animate-pulse' : 'bg-slate-600'}`} />
            <span className="text-[8px] font-black uppercase tracking-widest text-slate-400">
              {isProMode ? 'Studio Engine Online' : 'Standard Engine'}
            </span>
          </div>

          <div className="flex-1 relative">
            {isProcessing && (
              <div className="absolute inset-0 z-50 flex items-center justify-center bg-[#020617]/80 backdrop-blur-md rounded-[2rem]">
