      </main>

      <footer className="bg-slate-950 border-t border-white/5 px-4 md:px-8 py-3 text-[7px] md:text-[8px] text-slate-500 font-black uppercase tracking-[0.2em] flex flex-col md:flex-row justify-between shrink-0 z-50 gap-2">
