          <span>&copy; 2025 ChromaSketch</span>
          <span className="hidden xs:flex items-center gap-2"><ShieldCheck className="w-2.5 h-2.5 text-emerald-500" /> AES Protected Workspace</span>
        </div>
        <div className="flex flex-wrap items-center gap-3 md:gap-4">
           <span className="flex items-center gap-1.5 text-slate-400"><Info className="w-3 h-3" /> Paid project billing required for Studio Engine</span>
           <span className="truncate">Model: {isProMode ? 'Gemini 3 Pro' : 'Gemini 2.5 Flash'} • {resolution} Master</span>
        </div>
      </footer>
    </div>
  );
};

